INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e16e3c98b0941765bbb', '非常感谢前台ANN小姐姐看我们带了小朋友帮我们做了免费升级服务，房型大了一倍。给此次旅行提供了非常高的情绪价值。误打误撞订了广州第一家五星街酒店，里面还设有博物馆，广州花园酒店还有邓小平爷爷的题字，难怪这家酒店从上至下都透露着较强的文化底蕴。以后有朋友来广州我肯定是墙裂推荐的啦。', '["https://dimg04.c-ctrip.com/images/0232c12000cc8q2a5A468_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000cc8qb43B790_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000cc8pfao95AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000cc8pekhF2C5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园大床房', '大床房', '家庭亲子', 140, 4.948759890378168, 0, 0.0, 8, 2.19722457733622, 9, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '非常感谢前台ANN小姐姐看我们带了小朋友帮我们做了免费升级服务，房型大了一倍。给', '非常感谢前台ANN小姐姐看我们带了小朋友帮我们做了免费升级服务，房型大了一倍。给此次旅行提供了非常高的情绪价值。误打误撞订了广州第一家五星街酒店，里面还设有博物馆，广州花园酒店还有邓小平爷爷的题字，难怪这家酒店从上至下都透露着较强的文化底蕴。以后有朋友来广州我肯定是墙裂推荐的啦。', '2023-10-06', 5, '前台服务');
