INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e20e3c98b0941765bc0', '老五星了，十多年了，服务还是那么好，广州的标杆酒店！', '["https://dimg04.c-ctrip.com/images/0233s12000d7s99f54346_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000d7sdtj8D21A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000d7rwi6z043F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000d7rzlr0AE83_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-16', '花园双床房', '双床房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 6, 1.9459101490553128, 6, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '老五星了，十多年了，服务还是那么好，广州的标杆酒店！', '老五星了，十多年了，服务还是那么好，广州的标杆酒店！', '2024-02-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e20e3c98b0941765bc1', '广州花园酒店。
历史篇。
邓伯伯亲笔题写酒店名字（全国只有两家酒店的店名是老人家题写的），杨伯伯亲手奠基，江伯伯亲笔为酒店进口设备问题写报告，贝律铭绘制草图。
1985年开业，是全国第一批五星酒店，也是全国首批三家白金五星酒店之一，华南唯一。
《香港基本法》在这里起草，是当年广州亚运会总部饭店。
酒店里有1家米其林二星餐厅、1家米其林一星餐厅和2家米其林指南入围餐厅。
?
房间篇。
囤的红棉房套餐，办理入住时被告知升级为粤韵房，谢谢可爱的SAVANNA哟~
1416房，能俯视庭院瀑布。
面积虽然不算很大（64平方），但是个小套房格局，有独立的客厅和卧室。
整个房间布置简洁雅致舒适，且有岭南元素点睛，如客厅的花砖挂画、床头靠背的岭南园林漆画、床头的鸟笼灯...
写字台桌面，进门后近视眼刚一看到时还想着这酒店设施老旧到表皮起鼓了？！再细看，对不起是姐姐我肤浅了——人家这是皮面压出的浮雕木棉花图案，显档次得很呢！
开放式洗手间，中间隔着个浴缸，洗漱台只有单盆，坐厕没有什么科技含量。
迷你吧食品需要收费，不过免费的东西也有一大堆，全部打包带回家给兰姨姨。
?
?花园文化艺术之旅篇。
酒店官方整理了26个文化艺术最佳打卡点，每天安排三个时间段（10点、14点和17点）导览，感兴趣的酒店住客可预约专属金牌导游带领讲解游览。
那天姐姐真正是有专属的金牌导游——因为只有姐姐一个人预约了啦！
穿着燕尾服的曾先生带着姐姐，走走看看说说，足足一个小时！
听到看到了很多自己不会注意到的细节，充分满足了姐姐的八卦好奇心。
附：26个文化艺术最佳打卡点
花园酒店题名石（邓伯伯亲笔）；
阳江漆画《百美图》和《百骏图》；
金箔壁画《红楼梦》；
金龙戏珠藻井；
广东水乡风貌石刻壁画；
旋转木楼梯；
环市东咖啡阁HSD Cafe；
庭·日本餐厅；
名仕阁；
瀑布餐厅；
刘元帅像；
荔湾亭；
桃园馆；
锦鲤酒吧；
后花园·双瀑布；
后花园·天涯若比邻；
后花园·水月观音；
后花园·桥；
后花园·《雁壁》；
后花园·《枫桥夜泊》；
后花园·《少女戏鸽》；
后花园·沁春亭；
后花园·锦鲤；
后花园·中澳友谊树；
花园酒店博物馆。
饮食篇之走马观花。
酒店共有9家餐厅。
姐姐入住期间在3家餐厅（桃园馆、荔湾亭和瀑布餐厅，详细情况见餐厅评论）用过餐，而跟着金牌导游到处逛，还走进了没吃过的其他几家餐厅。
——名仕阁，西餐厅。
号称是城中纪念日圣地，纪念日首选。
我们进去时还未营业，里面空无一人。
大面积的落地玻璃，大量的白纱高挂飘逸，桌椅极少，室外是蓝天白云绿树，室内还有钢琴、鲜花、汽球，门外就是古希腊爱奥尼克风格旋转木楼梯，从里到外，如梦如幻，整体氛围感极佳，确实很适合约会或者过重要日子。
——锦鲤酒吧。
掩藏在花园深处，锦鲤池畔。
在楼上房间看到此处露台就极是喜欢，正对着花园和瀑布还有小红桥，风景很好，不太热的天气里坐在这里肯定会很惬意。
这里也是酒店的行政酒廊。
据说晚上有乐队驻唱，那天回酒店太晚没有去听听，有点遗憾，只能留待下次咯。
?——庭·日本餐厅。
地方虽然不大，却分别有专门的刺身和寿司吧台，还有铁板烧台。
?——环市东咖啡阁HSD Cafe。
其实就是大堂吧，供应饮品、面包、糕点。
?——泰安门Taian Table，米其林二星餐厅 ，只在晚上营业，只接受预约，人均消费不菲，看到点评上的单人套餐加酒水团购价3288。
斯蒂勒Stiller，米其林一星餐厅。
这两个餐厅，门都锁着，金牌导游也无法带姐姐进去开开眼界。
?
?健身房篇。
地方不太大，设施也不算太齐全，不过基本锻炼还是可以的了。
喜欢其够光猛。
忘记看看泳池了。
?
?花园篇。
这是省城市中心高档酒店里少有的真正花园，岭南园林特色，面积达21000平方。
花园主题是“天涯若比邻”，除了遍植绿树繁花，还有高达18米的双瀑布，有假山鱼池小红桥沁春亭，有大型壁画和雕塑，还有特定角度才能看到的水月观音哦！
姐姐带老人家在荔湾亭吃完饭，然后到这里来游花园，当是饭后逛公园消消食咯！
?
维波楼。
在酒店二楼，荔湾亭外面，长长的走廊，摆放有很多古雅旧家具。
看到有个“维波楼”牌匾，竟然是黄永玉题写的，顿感此中必然有故事。
搜搜看，这对跨国夫妇对中国古旧家具的修复保护让人敬佩、感动。
而我们前几年去住过吃过的聚龙村源汀就是“维波楼”的一员（7号馆），甚是惊喜！', '["https://dimg04.c-ctrip.com/images/0203l12000c42jr6o9114_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0204012000c42jul5A54D_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0230y12000c42frti3D16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000c42gn6q31FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000c426ls0B9F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000c429mw5577A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000c42eko39D71_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000c42biqfD711_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000c429nnx8F8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000c42bgkcD66D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000c42bsvgD208_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-12', '红棉大床套房', '套房', '独自旅行', 1821, 7.507690077819904, 5, 1.791759469228055, 3, 1.3862943611198906, 10, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '广州花园酒店。', '广州花园酒店。
历史篇。
邓伯伯亲笔题写酒店名字（全国只有两家酒店的店名是老人家题写的），杨伯伯亲手奠基，江伯伯亲笔为酒店进口设备问题写报告，贝律铭绘制草图。
1985年开业，是全国第一批五星酒店，也是全国首批三家白金五星酒店之一，华南唯一。
《香港基本法》在这里起草，是当年广州亚运会总部饭店。
酒店里有1家米其林二星餐厅、1家米其林一星餐厅和2家米其林指南入围餐厅。
?
房间篇。
囤的红棉房套餐，办理入住时被告知升级为粤韵房，谢谢可爱的SAVANNA哟~
1416房，能俯视庭院瀑布。
面积虽然不算很大（64平方），但是个小套房格局，有独立的客厅和卧室。
整个房间布置简洁雅致舒适，且有岭南元素点睛，如客厅的花砖挂画、床头靠背的岭南园林漆画、床头的鸟笼灯...
写字台桌面，进门后近视眼刚一看到时还想着这酒店设施老旧到表皮起鼓了？！再细看，对不起是姐姐我肤浅了——人家这是皮面压出的浮雕木棉花图案，显档次得很呢！
开放式洗手间，中间隔着个浴缸，洗漱台只有单盆，坐厕没有什么科技含量。
迷你吧食品需要收费，不过免费的东西也有一大堆，全部打包带回家给兰姨姨。
?
?花园文化艺术之旅篇。
酒店官方整理了26个文化艺术最佳打卡点，每天安排三个时间段（10点、14点和17点）导览，感兴趣的酒店住客可预约专属金牌导游带领讲解游览。
那天姐姐真正是有专属的金牌导游——因为只有姐姐一个人预约了啦！
穿着燕尾服的曾先生带着姐姐，走走看看说说，足足一个小时！
听到看到了很多自己不会注意到的细节，充分满足了姐姐的八卦好奇心。
附：26个文化艺术最佳打卡点
花园酒店题名石（邓伯伯亲笔）；
阳江漆画《百美图》和《百骏图》；
金箔壁画《红楼梦》；
金龙戏珠藻井；
广东水乡风貌石刻壁画；
旋转木楼梯；
环市东咖啡阁HSD Cafe；
庭·日本餐厅；
名仕阁；
瀑布餐厅；
刘元帅像；
荔湾亭；
桃园馆；
锦鲤酒吧；
后花园·双瀑布；
后花园·天涯若比邻；
后花园·水月观音；
后花园·桥；
后花园·《雁壁》；
后花园·《枫桥夜泊》；
后花园·《少女戏鸽》；
后花园·沁春亭；
后花园·锦鲤；
后花园·中澳友谊树；
花园酒店博物馆。
饮食篇之走马观花。
酒店共有9家餐厅。
姐姐入住期间在3家餐厅（桃园馆、荔湾亭和瀑布餐厅，详细情况见餐厅评论）用过餐，而跟着金牌导游到处逛，还走进了没吃过的其他几家餐厅。
——名仕阁，西餐厅。
号称是城中纪念日圣地，纪念日首选。
我们进去时还未营业，里面空无一人。
大面积的落地玻璃，大量的白纱高挂飘逸，桌椅极少，室外是蓝天白云绿树，室内还有钢琴、鲜花、汽球，门外就是古希腊爱奥尼克风格旋转木楼梯，从里到外，如梦如幻，整体氛围感极佳，确实很适合约会或者过重要日子。
——锦鲤酒吧。
掩藏在花园深处，锦鲤池畔。
在楼上房间看到此处露台就极是喜欢，正对着花园和瀑布还有小红桥，风景很好，不太热的天气里坐在这里肯定会很惬意。
这里也是酒店的行政酒廊。
据说晚上有乐队驻唱，那天回酒店太晚没有去听听，有点遗憾，只能留待下次咯。
?——庭·日本餐厅。
地方虽然不大，却分别有专门的刺身和寿司吧台，还有铁板烧台。
?——环市东咖啡阁HSD Cafe。
其实就是大堂吧，供应饮品、面包、糕点。
?——泰安门Taian Table，米其林二星餐厅 ，只在晚上营业，只接受预约，人均消费不菲，看到点评上的单人套餐加酒水团购价3288。
斯蒂勒Stiller，米其林一星餐厅。
这两个餐厅，门都锁着，金牌导游也无法带姐姐进去开开眼界。
?
?健身房篇。
地方不太大，设施也不算太齐全，不过基本锻炼还是可以的了。
喜欢其够光猛。
忘记看看泳池了。
?
?花园篇。
这是省城市中心高档酒店里少有的真正花园，岭南园林特色，面积达21000平方。
花园主题是“天涯若比邻”，除了遍植绿树繁花，还有高达18米的双瀑布，有假山鱼池小红桥沁春亭，有大型壁画和雕塑，还有特定角度才能看到的水月观音哦！
姐姐带老人家在荔湾亭吃完饭，然后到这里来游花园，当是饭后逛公园消消食咯！
?
维波楼。
在酒店二楼，荔湾亭外面，长长的走廊，摆放有很多古雅旧家具。
看到有个“维波楼”牌匾，竟然是黄永玉题写的，顿感此中必然有故事。
搜搜看，这对跨国夫妇对中国古旧家具的修复保护让人敬佩、感动。
而我们前几年去住过吃过的聚龙村源汀就是“维波楼”的一员（7号馆），甚是惊喜！', '2023-09-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e20e3c98b0941765bc2', '开了三间房，两间出问题。
第一间：1.1房卡日期设置错误，无法开房门，下去前台，问我们是否续住的，最后前台解释说日期设置错，是上位前台开卡失误。
1.2入住登记时，已提出要求把三间作关联，因为前台为了快速处理入住，没有告知房卡分别用了谁的信息登记，导致重新开卡时的误会，第一次增加了与前台沟通成本，因为原接待的前台走开了。
第二间：2.1门锁措施残旧未更换。刷卡进房，门锁显示灯为绿色，但扭动无效，喊了在隔壁的房务员，几次也开不了。
2.2服务响应速度慢。通过楼层电话直拨客服中心，如上反应情况，因为1.2中不知道房卡登记谁的信息，对方也不直接说我信息错误，来回间第二次增加了沟通成本，核对好信息，对方表示让礼宾的同事上来，耐心等待了十来分钟，再次拨打电话，对方表示已看到礼宾员上来找我们，再次耐心等待，才等来礼宾员。
2.3升级房间失误。礼宾员试过门后，主动提出升级房间，并为我们换房卡并带我们去新的房间，我们再再次耐心等待，结果新的房间是双人房，原来房间是大床。礼宾员电话叫房务员拿卡开隔壁房，然后我们再再再次耐心等待，房间没错了。
2.4突**况无备注。礼宾下去换卡给我们，我们婉言拒绝，因为原定外出的时间已耽误很久了，只能晚上我们自己去前台拿卡，让帮忙开好卡就行。晚上回来报了新房号给前台，前台一脸懵，但他并没有表明问题所在，又是一次次无效沟通，他也不停地点击鼠标，我们再再再再次耐心等待，最后我把入住到之前的说了，并主动说了三位入住信息，他才说“难怪和登记的不一样”，第三次增加沟通成本。然而新的房间根本没有为我们预留，也没有任何注明，好在没开出去，不然都不用睡了。
2.5基础专业失误。开好房卡后，前台主动提出带我们到房间，以防其他情况发生。结果房卡刷不开门，显示灯是红色。我们再再再再再次耐心等待前台重新开卡。
最后要赞一下的。唯一一间没有任何问题的，是我爸妈入住的，对大堂工作人员很满意，主动服务意识非常强，房间也很宽敞舒适，对第三次入住花园酒店，仍然是非常满意。真的很谢谢，再再再再再再次感谢', '["https://dimg04.c-ctrip.com/images/0236a12000c72o0nr26F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000c732ilwFFCE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-09-20', '红棉大床套房', '套房', '商务出差', 855, 6.752270376141742, 2, 1.0986122886681098, 4, 1.6094379124341005, 9, '["前台服务", "退房/入住效率", "客房服务"]'::jsonb, '前台服务', '退房/入住效率', '客房服务', '未知酒店', '未知地点', '匿名', '开了三间房，两间出问题。', '开了三间房，两间出问题。
