INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e20e3c98b0941765bc9', '住了3晚，踩雷啊。霉味，漏水，然后没有淋浴区域，只能站在浴缸里洗澡，然后洗澡和马桶只有一扇移动门，关了这边那边只能开着，非常没有隐私感。住了那么多酒店，最不喜欢的。比民宿都差。', '["https://dimg04.c-ctrip.com/images/0234o12000cck3vk83BB9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 88, 4.48863636973214, 3, 1.3862943611198906, 14, 2.70805020110221, 9, '["房间设施", "卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '住了3晚，踩雷啊。霉味，漏水，然后没有淋浴区域，只能站在浴缸里洗澡，然后洗澡和马', '住了3晚，踩雷啊。霉味，漏水，然后没有淋浴区域，只能站在浴缸里洗澡，然后洗澡和马桶只有一扇移动门，关了这边那边只能开着，非常没有隐私感。住了那么多酒店，最不喜欢的。比民宿都差。', '2023-10-07', 1, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e2ce3c98b0941765bca', '房间宽敞干净舒适，居住体验非常好，会再次去。', '["https://dimg04.c-ctrip.com/images/0235012000d12i6wk1CC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000d12ai3eECBA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000d12qj4v4C0E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-24', '红棉大床套房', '套房', '其他', 22, 3.1354942159291497, 0, 0.0, 1, 0.6931471805599453, 5, '["整体满意度", "房间设施", "卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '房间宽敞干净舒适，居住体验非常好，会再次去。', '房间宽敞干净舒适，居住体验非常好，会再次去。', '2024-01-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e2ce3c98b0941765bcb', '房间不错，装修风格典雅，最满意的是服务，酒店里所以工作人员都很友好，行政酒廊欢乐时光的餐食品种虽然不多但出品很不错，吃得很满足，carrie和aimee特别好，还送了酒店的小纪念品。下次来广州还会选择花园酒店，并且会推荐给朋友。', '["https://dimg04.c-ctrip.com/images/0205u12000f70u71i7756_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233l12000f70thyn19F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000f70spcrAE2B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000f70tf2v9095_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-21', '花园大床房', '大床房', '家庭亲子', 114, 4.74493212836325, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间不错，装修风格典雅，最满意的是服务，酒店里所以工作人员都很友好，行政酒廊欢乐', '房间不错，装修风格典雅，最满意的是服务，酒店里所以工作人员都很友好，行政酒廊欢乐时光的餐食品种虽然不多但出品很不错，吃得很满足，carrie和aimee特别好，还送了酒店的小纪念品。下次来广州还会选择花园酒店，并且会推荐给朋友。', '2024-08-21', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e2ce3c98b0941765bcc', '这次续住花园酒店，体验简直超绝！前台的Cecilia和Lavinia两位美女，笑容温暖，办理入住迅速又贴心，耐心解答我的所有疑问。房间一尘不染，设施设备应有尽有，满足了我的各种需求。踏入大堂，金碧辉煌的装修风格，尽显大气奢华，让人眼前一亮。在酒店里碰到的每一位员工，都热情洋溢，主动问好，服务十分周到。在这里，我感受到了宾至如归的待遇，下次出行，花园酒店必定还是我的首选！', '["https://dimg04.c-ctrip.com/images/0235h12000j81l6sz27F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000j81pdduFC7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000j827gin0ABA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000j81ci8zCD90_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '城央绿意大床房', '大床房', '商务出差', 186, 5.231108616854587, 0, 0.0, 8, 2.19722457733622, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '这次续住花园酒店，体验简直超绝！前台的Cecilia和Lavinia两位美女，笑', '这次续住花园酒店，体验简直超绝！前台的Cecilia和Lavinia两位美女，笑容温暖，办理入住迅速又贴心，耐心解答我的所有疑问。房间一尘不染，设施设备应有尽有，满足了我的各种需求。踏入大堂，金碧辉煌的装修风格，尽显大气奢华，让人眼前一亮。在酒店里碰到的每一位员工，都热情洋溢，主动问好，服务十分周到。在这里，我感受到了宾至如归的待遇，下次出行，花园酒店必定还是我的首选！', '2025-03-21', 5, '前台服务');
