INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e2ce3c98b0941765bcf', '酒店非常具有历史文化气息 感觉住进了历史艺术博物馆一样 晚上非常安静很适合入睡 唯一缺点是一大早就被外面道路工程的施工噪音吵醒
