酒店大堂的香氛味道非常好闻 映像分加满了', '2023-10-18', 4, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e2ce3c98b0941765bd0', '超满意的体验，办理入住时Savanna细心询问住店需求，看见带小朋友还给升了房间。住宿期间还有酒店赠送的小点心，酒店花园更是美丽！由于小孩子发烧了，因此延迟了退房，退房时Gillian得知后特意给了延时减免。酒店好，服务好，两位小姐姐更是热情周到！', '["https://dimg04.c-ctrip.com/images/0231k12000c5eepwrC7B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000c5ehns2DDB5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-15', '花园双床房', '双床房', '家庭亲子', 124, 4.8283137373023015, 0, 0.0, 12, 2.5649493574615367, 9, '["前台服务", "整体满意度", "退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '超满意的体验，办理入住时Savanna细心询问住店需求，看见带小朋友还给升了房间', '超满意的体验，办理入住时Savanna细心询问住店需求，看见带小朋友还给升了房间。住宿期间还有酒店赠送的小点心，酒店花园更是美丽！由于小孩子发烧了，因此延迟了退房，退房时Gillian得知后特意给了延时减免。酒店好，服务好，两位小姐姐更是热情周到！', '2023-09-15', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e2ce3c98b0941765bd1', '每次到广州，必住花园酒店。地理位置极佳，地铁五号线淘金站就在酒店旁边。行政酒廊改到了30楼的旋转餐厅，环境更好，食品品种更多了。', '["https://dimg04.c-ctrip.com/images/0235d12000cipyr3b592A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000cipziun87D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000cipwet670BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-05', '花园大床房', '大床房', '独自旅行', 64, 4.174387269895637, 0, 0.0, 4, 1.6094379124341005, 8, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '每次到广州，必住花园酒店。地理位置极佳，地铁五号线淘金站就在酒店旁边。行政酒廊改', '每次到广州，必住花园酒店。地理位置极佳，地铁五号线淘金站就在酒店旁边。行政酒廊改到了30楼的旋转餐厅，环境更好，食品品种更多了。', '2023-11-05', 5, '交通便利性');
