INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bd4', '酒店的体验感太棒了，亲子哪儿都没去都在酒店打卡也很开心，花园特别大宝宝没事就想去喂鱼，开心极了，酒店的服务任务都非常友好，外国友人也特别多，套房也很舒服，推荐推荐亲子出游打卡一下。', '["https://dimg04.c-ctrip.com/images/0231n12000c9be47lD3AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000c9bdcnoD50E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000c9bd85o29AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000c9bl0pc8C5B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000c9bj65x69C8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-27', '红棉大床套房', '套房', '家庭亲子', 90, 4.51085950651685, 1, 0.6931471805599453, 1, 0.6931471805599453, 7, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '酒店的体验感太棒了，亲子哪儿都没去都在酒店打卡也很开心，花园特别大宝宝没事就想去', '酒店的体验感太棒了，亲子哪儿都没去都在酒店打卡也很开心，花园特别大宝宝没事就想去喂鱼，开心极了，酒店的服务任务都非常友好，外国友人也特别多，套房也很舒服，推荐推荐亲子出游打卡一下。', '2023-09-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bd5', '因为此次出行带了三个小朋友，提前跟酒店电话沟通了一下，酒店也非常负责的帮忙做了备注。抵达当天办入住时，竟然给做了免费升房，其实我已经准备加钱升房的，真的很惊喜，67平米的大房间不论是环境还是舒适度，都非常满意。有被酒店的服务感动到，', '["https://dimg04.c-ctrip.com/images/0232v12000c4lynqiD87E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-14', '花园双床房', '双床房', '其他', 116, 4.762173934797756, 0, 0.0, 8, 2.19722457733622, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '因为此次出行带了三个小朋友，提前跟酒店电话沟通了一下，酒店也非常负责的帮忙做了备', '因为此次出行带了三个小朋友，提前跟酒店电话沟通了一下，酒店也非常负责的帮忙做了备注。抵达当天办入住时，竟然给做了免费升房，其实我已经准备加钱升房的，真的很惊喜，67平米的大房间不论是环境还是舒适度，都非常满意。有被酒店的服务感动到，', '2023-09-14', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bd6', '酒店的环境极佳，有相当大的花园景观，也有单独的博物馆，很喜欢前台大堂的十二钗背景板。
早餐与下午茶的餐食也丰富到位，酒廊晚上有表演。酒廊里的Carrie、Yuki、Yoon服务态度非常好，值得点赞。
入住时担心是老酒店，设施会陈旧。入住后房间设施还是比较全面的，除了电视小了点。总体瑕不掩瑜，以后来广州还会入住。', '["https://dimg04.c-ctrip.com/images/0234912000c5br8y4B3DC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000c5bkxtm2E9F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000c5buo6g9065_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-15', '花园双床房', '双床房', '商务出差', 156, 5.056245805348308, 2, 1.0986122886681098, 13, 2.6390573296152584, 9, '["景观/朝向", "餐饮设施", "前台服务"]'::jsonb, '景观/朝向', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '酒店的环境极佳，有相当大的花园景观，也有单独的博物馆，很喜欢前台大堂的十二钗背景', '酒店的环境极佳，有相当大的花园景观，也有单独的博物馆，很喜欢前台大堂的十二钗背景板。
早餐与下午茶的餐食也丰富到位，酒廊晚上有表演。酒廊里的Carrie、Yuki、Yoon服务态度非常好，值得点赞。
入住时担心是老酒店，设施会陈旧。入住后房间设施还是比较全面的，除了电视小了点。总体瑕不掩瑜，以后来广州还会入住。', '2023-09-15', 5, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bd7', '名副其实—花园酒店，环境优美干净整洁，服务更是没话说，一路迎宾和礼仪，给人宾至如归的感觉，前台小邓靓仔服务热情人好心善，我问的问题都能耐心和我解释说明。体验感非常棒的酒店，还有瀑布哦??????', '["https://dimg04.c-ctrip.com/images/0233k12000ext1xix62A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000extj44g6E0E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000ext44e528B3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-29', '花园大床房', '大床房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 6, 1.9459101490553128, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '名副其实—花园酒店，环境优美干净整洁，服务更是没话说，一路迎宾和礼仪，给人宾至如', '名副其实—花园酒店，环境优美干净整洁，服务更是没话说，一路迎宾和礼仪，给人宾至如归的感觉，前台小邓靓仔服务热情人好心善，我问的问题都能耐心和我解释说明。体验感非常棒的酒店，还有瀑布哦??????', '2024-07-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bd8', '白金级的服务太??。地理位置好。入住???送水果。床品舒适。酒店内更???26个打卡点。非常推荐前往。下次???机会还会选择花园。', '["https://dimg04.c-ctrip.com/images/0230812000cjbc6lz6D46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000cjbgnap207A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000cjbipd9856F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000cjbdllqA1CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-08', '红棉双床套房', '套房', '家庭亲子', 65, 4.189654742026425, 0, 0.0, 20, 3.044522437723423, 5, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '白金级的服务太??。地理位置好。入住???送水果。床品舒适。酒店内更???26个', '白金级的服务太??。地理位置好。入住???送水果。床品舒适。酒店内更???26个打卡点。非常推荐前往。下次???机会还会选择花园。', '2023-11-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bd9', '这个套票很超值。套房面积大，装饰富有岭南特色，注重细节。大大的写字台面甚至有木棉花的隐花纹。双洗手台，洗手台、马桶间和洗浴间三分离。大大的观景窗，窗外是广州的繁华夜景。套票里的500元餐券用在了岭南特色餐厅荔湾亭，毕竟是米其林指南餐厅。', '["https://dimg04.c-ctrip.com/images/0231t12000c5wizp83C35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000c5wftsr411A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000c5we0rmC1A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000c5wivggE746_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-17', '红棉双床套房', '套房', '家庭亲子', 118, 4.77912349311153, 0, 0.0, 77, 4.356708826689592, 9, '["房间设施", "性价比", "餐饮设施"]'::jsonb, '房间设施', '性价比', '餐饮设施', '未知酒店', '未知地点', '匿名', '这个套票很超值。套房面积大，装饰富有岭南特色，注重细节。大大的写字台面甚至有木棉', '这个套票很超值。套房面积大，装饰富有岭南特色，注重细节。大大的写字台面甚至有木棉花的隐花纹。双洗手台，洗手台、马桶间和洗浴间三分离。大大的观景窗，窗外是广州的繁华夜景。套票里的500元餐券用在了岭南特色餐厅荔湾亭，毕竟是米其林指南餐厅。', '2023-09-17', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bda', '酒店很好，就是房间有点局促。', '["https://dimg04.c-ctrip.com/images/0235a12000d5zel49D630_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000d5zk52dC4A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-02-09', '花园双床房', '双床房', '家庭亲子', 14, 2.70805020110221, 0, 0.0, 3, 1.3862943611198906, 4, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店很好，就是房间有点局促。', '酒店很好，就是房间有点局促。', '2024-02-09', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bdb', '酒店服务态度好，环境优雅，房间感觉，满意', '["https://dimg04.c-ctrip.com/images/0230112000d0mf85fCAE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-23', '花园双床房', '双床房', '朋友出游', 20, 3.044522437723423, 0, 0.0, 3, 1.3862943611198906, 4, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店服务态度好，环境优雅，房间感觉，满意', '酒店服务态度好，环境优雅，房间感觉，满意', '2024-01-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bdc', '去了很多次了，是我在广州很喜欢入住的一家酒店。改革开放初期就开业的花园永远给人一种岁月流金的时光感。从下车穿过的门厅到前台的大观园壁画，从顺着扶梯看到的大厅全貌到伴着瀑布流水的锦鲤红桥，从电梯厅的格局到房间的布置，都是老牌五星级的风格，而且一点都没有陈旧的感觉，加上工作人员周到老练又热情的服务，反倒彰显一种绝对经典的从容和大气。客房的床品和洗浴用品都很舒服，很喜欢。还贴心地放了环市东的旅行小手册，方便给客人去附近citywalk做指引。酒店周边是很烟火的本地生活区，藏着众多平民美食和有意思的小店，每次我都放弃酒店餐饮去那些地方暴走暴吃，哈哈哈，相当过瘾。
非常喜欢酒店三楼的酒店博物馆，不是只讲他们酒店自己的陈列馆，是东西方整个酒店业的缩影，很值得花点时间去逛一逛哦。', '["https://dimg04.c-ctrip.com/images/0233912000bwaim6c3EE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000bwa36zr0D0B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000bwadk1aD2E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000bwacuj5B44C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000bwa4z3uDC9B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000bw9yzzwD662_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000bwa29jc84D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000bwao9ub454C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000bwabdpyC0B2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-13', '花园大床房', '大床房', '商务出差', 337, 5.823045895483019, 3, 1.3862943611198906, 10, 2.3978952727983707, 10, '["整体满意度", "房间设施", "周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套', '未知酒店', '未知地点', '匿名', '去了很多次了，是我在广州很喜欢入住的一家酒店。改革开放初期就开业的花园永远给人一', '去了很多次了，是我在广州很喜欢入住的一家酒店。改革开放初期就开业的花园永远给人一种岁月流金的时光感。从下车穿过的门厅到前台的大观园壁画，从顺着扶梯看到的大厅全貌到伴着瀑布流水的锦鲤红桥，从电梯厅的格局到房间的布置，都是老牌五星级的风格，而且一点都没有陈旧的感觉，加上工作人员周到老练又热情的服务，反倒彰显一种绝对经典的从容和大气。客房的床品和洗浴用品都很舒服，很喜欢。还贴心地放了环市东的旅行小手册，方便给客人去附近citywalk做指引。酒店周边是很烟火的本地生活区，藏着众多平民美食和有意思的小店，每次我都放弃酒店餐饮去那些地方暴走暴吃，哈哈哈，相当过瘾。
非常喜欢酒店三楼的酒店博物馆，不是只讲他们酒店自己的陈列馆，是东西方整个酒店业的缩影，很值得花点时间去逛一逛哦。', '2023-08-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e37e3c98b0941765bdd', '每个接触的服务员都非常nice，中午来早了，前台办理入住各种温馨提示，还免费升级粤韵房型，一房一厅，房和厅一样大那种，两个大电视，一键升降窗帘，住的很舒服。博物馆看了，26个打卡点也人工导览了，带看很仔细，酒店的来龙去脉也清楚了，很棒。早餐看起来不多，吃起来啥都有，都想吃奈何吃不下太多，又不好一直坐下去，毕竟后面还有人在排队等位。床和椅子都好睡好坐。周边地铁施工时间大约8：10-20：30，中午有休息。周末也开工，有些影响，能接受，窗都是中空玻璃，比较隔音。', '["https://dimg04.c-ctrip.com/images/0231y12000c3tcnik6C55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000c3ta272133D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237212000c3tef3eA2B7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000c3tdwhnA535_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '红棉双床套房', '套房', '朋友出游', 231, 5.44673737166631, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "房间设施", "安静程度"]'::jsonb, '前台服务', '房间设施', '安静程度', '未知酒店', '未知地点', '匿名', '每个接触的服务员都非常nice，中午来早了，前台办理入住各种温馨提示，还免费升级', '每个接触的服务员都非常nice，中午来早了，前台办理入住各种温馨提示，还免费升级粤韵房型，一房一厅，房和厅一样大那种，两个大电视，一键升降窗帘，住的很舒服。博物馆看了，26个打卡点也人工导览了，带看很仔细，酒店的来龙去脉也清楚了，很棒。早餐看起来不多，吃起来啥都有，都想吃奈何吃不下太多，又不好一直坐下去，毕竟后面还有人在排队等位。床和椅子都好睡好坐。周边地铁施工时间大约8：10-20：30，中午有休息。周末也开工，有些影响，能接受，窗都是中空玻璃，比较隔音。', '2023-09-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e42e3c98b0941765bde', '位于广州市中心地带的一家五星级酒店，自带环境优美的后花园，非常舒适。大堂装修融入了四大名著红楼梦元素，奢华又大气。房间卫生和装修都非常好，入住当晚还有小惊喜，送了小点心，服务周到，下次来广州还会再订花园酒店。', '["https://dimg04.c-ctrip.com/images/0234h12000c47kkef2A54_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000c47nk25C679_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000c47qms9A1C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-12', '花园双床房', '双床房', '独自旅行', 104, 4.653960350157523, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "客房服务", "卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '位于广州市中心地带的一家五星级酒店，自带环境优美的后花园，非常舒适。大堂装修融入', '位于广州市中心地带的一家五星级酒店，自带环境优美的后花园，非常舒适。大堂装修融入了四大名著红楼梦元素，奢华又大气。房间卫生和装修都非常好，入住当晚还有小惊喜，送了小点心，服务周到，下次来广州还会再订花园酒店。', '2023-09-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e42e3c98b0941765bdf', '房间很干净宽敞，前台yolo小姐姐服务细致周到，还特别贴心的给升了套房，下次旅游还住花园酒店', '["https://dimg04.c-ctrip.com/images/0232b12000i1m6mob213A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000i1lkk4a1143_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000i1kdk690606_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000i1lb1o8AD3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000i1kobkg2580_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-24', '花园双床房', '双床房', '朋友出游', 46, 3.8501476017100575, 0, 0.0, 3, 1.3862943611198906, 7, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '房间很干净宽敞，前台yolo小姐姐服务细致周到，还特别贴心的给升了套房，下次旅游', '房间很干净宽敞，前台yolo小姐姐服务细致周到，还特别贴心的给升了套房，下次旅游还住花园酒店', '2025-01-24', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e42e3c98b0941765be0', '这是我在国内见到的唯一一家，酒店保养做的这么优秀的酒店。1985年开业，近40年风雨历程，太多的老物件还像新的一样。雅致的花园，金箔画的灿烂，细腻的服务，美味的菜肴……儿子说下次来广州还要住花园酒店。
非常感谢礼宾部的Tim专业细致的精彩讲解！谢谢你为我们提供了宾至如归的服务。在您身上让我看到了金钥匙的闪烁。', '["https://dimg04.c-ctrip.com/images/0230z12000cplrvgbBAAB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000cplrui186C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000cplq3zbAD98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000cplrkxq1775_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-10', '花园大床房', '大床房', '家庭亲子', 155, 5.049856007249537, 1, 0.6931471805599453, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '这是我在国内见到的唯一一家，酒店保养做的这么优秀的酒店。1985年开业，近40年', '这是我在国内见到的唯一一家，酒店保养做的这么优秀的酒店。1985年开业，近40年风雨历程，太多的老物件还像新的一样。雅致的花园，金箔画的灿烂，细腻的服务，美味的菜肴……儿子说下次来广州还要住花园酒店。
非常感谢礼宾部的Tim专业细致的精彩讲解！谢谢你为我们提供了宾至如归的服务。在您身上让我看到了金钥匙的闪烁。', '2023-12-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e42e3c98b0941765be1', '酒店很赞，早餐丰富，花园美丽，下次再来。', '["https://dimg04.c-ctrip.com/images/0233l12000d86w1twF8EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000d86o184EA59_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000d86pvfx8309_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000d86o8imE9A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '花园大床房', '大床房', '家庭亲子', 20, 3.044522437723423, 0, 0.0, 8, 2.19722457733622, 4, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店很赞，早餐丰富，花园美丽，下次再来。', '酒店很赞，早餐丰富，花园美丽，下次再来。', '2024-02-17', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e42e3c98b0941765be2', '非常难忘的体验，此次广州顺德旅游一共定了三个酒店，这个是最后一个也是最让人期待的，酒店就在地铁旁，交通便利。前台接待非常专业，行政酒廊的工作人员也非常不错。酒店内部也非常漂亮，不愧是大师之作，离开的那天上午还打卡了酒店博物馆，感谢小哥细致的讲解，最后退房的时候在前台买了一只花园小羊送给儿子，希望有机会再带我们家小朋友来住，感觉这酒店很适合遛娃啊', '["https://dimg04.c-ctrip.com/images/0232m12000c3p0u9849A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000c3p04eg49A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000c3p7ecd0D70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000c3pal66CD01_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000c3p0co1115A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000c3p7o778165_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000c3paf85748F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000c3p6sx9883C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '花园大床房', '大床房', '情侣出游', 173, 5.159055299214529, 0, 0.0, 2, 1.0986122886681098, 9, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '非常难忘的体验，此次广州顺德旅游一共定了三个酒店，这个是最后一个也是最让人期待的', '非常难忘的体验，此次广州顺德旅游一共定了三个酒店，这个是最后一个也是最让人期待的，酒店就在地铁旁，交通便利。前台接待非常专业，行政酒廊的工作人员也非常不错。酒店内部也非常漂亮，不愧是大师之作，离开的那天上午还打卡了酒店博物馆，感谢小哥细致的讲解，最后退房的时候在前台买了一只花园小羊送给儿子，希望有机会再带我们家小朋友来住，感觉这酒店很适合遛娃啊', '2023-09-10', 5, '交通便利性');
