INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e42e3c98b0941765be5', '之前第一次来广州，住在花园酒店，感受就非常好，这次全家一起来广州，仍然住在花园，孩子们很喜欢这里。酒店大堂高端大气，花园精美。并且前台看我们有小朋友还给升级了房间。为我们的旅行增添了愉快的体验。', '["https://dimg04.c-ctrip.com/images/0236b12000c41drwrAE56_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000c4194orE0BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000c41cu8bC56B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-11', '花园双床房', '双床房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 1, 0.6931471805599453, 8, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '之前第一次来广州，住在花园酒店，感受就非常好，这次全家一起来广州，仍然住在花园，', '之前第一次来广州，住在花园酒店，感受就非常好，这次全家一起来广州，仍然住在花园，孩子们很喜欢这里。酒店大堂高端大气，花园精美。并且前台看我们有小朋友还给升级了房间。为我们的旅行增添了愉快的体验。', '2023-09-11', 5, '整体满意度');
