让我敬佩的是，酒店前台，酒店行政酒廊，酒店的自助餐厅，专业的操守，敬业精神，这证明酒店对员工培训的如此到位，更是15楼层的小妹妹的客房服务，让我更似感动。
谢谢你们的专业服务。谢谢了！！！', '2023-09-09', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e4de3c98b0941765be9', '房券配合岭南金卡十分好用，感谢前台Billy升级到喜洋洋套房。酒廊Carrie、yuki、Mia和Lena等小姐姐们服务一流，令我父母享受到尊贵的服务，花园酒店的行政酒廊锦鲤酒吧绝对值得体验！', '["https://dimg04.c-ctrip.com/images/0235d12000c3ra50qDC6F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000c3re2t91627_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000c3r4a5u6C3E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000c3ra7ns3038_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000c3rdyhd6F3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000c3rauua1067_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000c3r8pfg8D08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000c3r9jprCC73_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000c3re8vg61B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '红棉双床套房', '套房', '家庭亲子', 96, 4.574710978503383, 0, 0.0, 4, 1.6094379124341005, 8, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房券配合岭南金卡十分好用，感谢前台Billy升级到喜洋洋套房。酒廊Carrie、', '房券配合岭南金卡十分好用，感谢前台Billy升级到喜洋洋套房。酒廊Carrie、yuki、Mia和Lena等小姐姐们服务一流，令我父母享受到尊贵的服务，花园酒店的行政酒廊锦鲤酒吧绝对值得体验！', '2023-09-10', 5, '前台服务');
