INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e4de3c98b0941765bec', '春节期间活动丰富', '["https://dimg04.c-ctrip.com/images/0235g12000d7n7kf81BEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 8, 2.19722457733622, 0, 0.0, 4, 1.6094379124341005, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '春节期间活动丰富', '春节期间活动丰富', '2024-02-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e4de3c98b0941765bed', '在花园酒店住了一晚，广州老牌五星酒店，坐落在有点异域风情的建设六马路旁，总体来讲体验还不错。
环境：客房隔音不错，楼下施工也没有什么声音。一楼有很漂亮的后花园，吃完早餐去逛逛很舒服。四楼的博物馆也可以逛逛蛮有趣的。但是空中花园和泳池在装修，有点可惜。
设施：总体比较老旧，不过能看出来细心维护，卫生也做的不错。床也睡的挺舒服的。
早餐：挺丰富的，在瀑布餐厅，各国菜式都有，看着瀑布和花园吃早餐有种在度假的感觉，很喜欢～
服务：服务一般，需要提升。checkin办理时间巨长，且全程没有一些提示，会让客人干等着。早餐指引入座也有同样的问题。总的来说就是“我什么都做了但我毫无感情”。最后押金退还失败也没有人来通知，主动打电话三次才办妥，这里效率有点低。作为五星标准，我觉得服务应该要跟上。', '["https://dimg04.c-ctrip.com/images/0236k12000c27apgy3C15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000c27buuaB46B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000c2713raA770_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000c27585e763E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-09-12', '红棉大床套房', '套房', '情侣出游', 343, 5.840641657373398, 1, 0.6931471805599453, 15, 2.772588722239781, 9, '["退房/入住效率", "安静程度", "餐饮设施"]'::jsonb, '退房/入住效率', '安静程度', '餐饮设施', '未知酒店', '未知地点', '匿名', '在花园酒店住了一晚，广州老牌五星酒店，坐落在有点异域风情的建设六马路旁，总体来讲', '在花园酒店住了一晚，广州老牌五星酒店，坐落在有点异域风情的建设六马路旁，总体来讲体验还不错。
环境：客房隔音不错，楼下施工也没有什么声音。一楼有很漂亮的后花园，吃完早餐去逛逛很舒服。四楼的博物馆也可以逛逛蛮有趣的。但是空中花园和泳池在装修，有点可惜。
设施：总体比较老旧，不过能看出来细心维护，卫生也做的不错。床也睡的挺舒服的。
早餐：挺丰富的，在瀑布餐厅，各国菜式都有，看着瀑布和花园吃早餐有种在度假的感觉，很喜欢～
服务：服务一般，需要提升。checkin办理时间巨长，且全程没有一些提示，会让客人干等着。早餐指引入座也有同样的问题。总的来说就是“我什么都做了但我毫无感情”。最后押金退还失败也没有人来通知，主动打电话三次才办妥，这里效率有点低。作为五星标准，我觉得服务应该要跟上。', '2023-09-12', 3, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e4de3c98b0941765bee', '环境：非常棒，是我目前住过的酒店内部环境最好的了
设施：原来订的红棉大床房，入住的时候说给做了小小的升级，给了个同样面积但是近几年装修的房间。房间设施总体还不错，不过以这个价位来说算不上惊艳。电视不错，三星的，尺寸也够大。虽然不能使用手机投屏，但电视节目很多，HBO也能直接放，还有一些4K的频道。酒店还配了针线包，而且这针线包看着还不错。酒店的拖鞋很舒服，配了大小两个尺码，打电话给前台还会给一双小孩子的拖鞋。就是拖鞋的防滑不太好，洗脸盆附近地方弄了水之后，我在洗漱的时候还滑了一跤，脚趾撞到台下的洗衣篮了，现在都还有点疼呢！在吐槽下酒店配了浴缸和浴盐，一开始我没看到浴盐打电话问前台要浴盐，前台居然说酒店没有浴盐，这业务也太不熟悉了吧！然后还问了有没有一次性浴缸套的也说没有，不知道真没有呢还是假没有呢？还有一个比较失望的就是坐便器了，19年重新装修的居然没有配智能马桶，而且这个普通的??也不好，厕纸扔在马桶前端的位置的话居然会冲不下去，因为冲水的时候前端这个位置冲不到水！再来说点好的，有咖啡机有胶囊，茶包配的TWG。说完房间，说下酒店公区的部份，那是真的豪华，这才对得起这么贵的房价。酒店一进门先是有个小的大堂，左右两边墙上分别有百骏图和百美图。然后再进去才是酒店真正的大堂，那叫一个金碧辉煌，前台身后的那幅红楼梦据说使用金箔贴的，有钱是真的任性。对着前台在我们的右手边是瀑布餐厅，我们的早餐就是在这里吃的，环境很棒，抬头就能看到外面的人造瀑布。早餐种类不算多，不过味道都还不错，水果也比较新鲜，酸奶稍微差点，只有调味的酸奶。咖啡机做的??也挺好的。外面瀑布连着的是酒店的一个大花园，没大太阳的时候去逛逛还是挺惬意的，逛累了就能直接回楼上休息。酒店酒店4楼还有一个酒店博物馆，面积还挺大，内容挺多，不是随便糊弄的。要参观的话直接过去在门口手机扫码实名预约一下就可以了。最后说一下酒店的餐厅，我们现在大众点评上看了下几个餐厅的人均消费，一看吓死个人，还有我们有送的消费券，最后选了个其中比较便宜的荔湾亭，想着两个人500元怎么也应该能吃饱吧。很遗憾，最后吃完花了500多后，我是饿着肚子出来的??
服务：服务中规中矩。', '["https://dimg04.c-ctrip.com/images/0205p12000c2pnl5r74CD_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0232c12000c2pcyg1E4AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000c2p8qv59E6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000c2p3dmc14CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230v12000c2p4wbl2E59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-09-05', '红棉大床套房', '套房', '家庭亲子', 915, 6.82001636467413, 0, 0.0, 6, 1.9459101490553128, 9, '["房间设施", "公共设施", "餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '环境：非常棒，是我目前住过的酒店内部环境最好的了', '环境：非常棒，是我目前住过的酒店内部环境最好的了
设施：原来订的红棉大床房，入住的时候说给做了小小的升级，给了个同样面积但是近几年装修的房间。房间设施总体还不错，不过以这个价位来说算不上惊艳。电视不错，三星的，尺寸也够大。虽然不能使用手机投屏，但电视节目很多，HBO也能直接放，还有一些4K的频道。酒店还配了针线包，而且这针线包看着还不错。酒店的拖鞋很舒服，配了大小两个尺码，打电话给前台还会给一双小孩子的拖鞋。就是拖鞋的防滑不太好，洗脸盆附近地方弄了水之后，我在洗漱的时候还滑了一跤，脚趾撞到台下的洗衣篮了，现在都还有点疼呢！在吐槽下酒店配了浴缸和浴盐，一开始我没看到浴盐打电话问前台要浴盐，前台居然说酒店没有浴盐，这业务也太不熟悉了吧！然后还问了有没有一次性浴缸套的也说没有，不知道真没有呢还是假没有呢？还有一个比较失望的就是坐便器了，19年重新装修的居然没有配智能马桶，而且这个普通的??也不好，厕纸扔在马桶前端的位置的话居然会冲不下去，因为冲水的时候前端这个位置冲不到水！再来说点好的，有咖啡机有胶囊，茶包配的TWG。说完房间，说下酒店公区的部份，那是真的豪华，这才对得起这么贵的房价。酒店一进门先是有个小的大堂，左右两边墙上分别有百骏图和百美图。然后再进去才是酒店真正的大堂，那叫一个金碧辉煌，前台身后的那幅红楼梦据说使用金箔贴的，有钱是真的任性。对着前台在我们的右手边是瀑布餐厅，我们的早餐就是在这里吃的，环境很棒，抬头就能看到外面的人造瀑布。早餐种类不算多，不过味道都还不错，水果也比较新鲜，酸奶稍微差点，只有调味的酸奶。咖啡机做的??也挺好的。外面瀑布连着的是酒店的一个大花园，没大太阳的时候去逛逛还是挺惬意的，逛累了就能直接回楼上休息。酒店酒店4楼还有一个酒店博物馆，面积还挺大，内容挺多，不是随便糊弄的。要参观的话直接过去在门口手机扫码实名预约一下就可以了。最后说一下酒店的餐厅，我们现在大众点评上看了下几个餐厅的人均消费，一看吓死个人，还有我们有送的消费券，最后选了个其中比较便宜的荔湾亭，想着两个人500元怎么也应该能吃饱吧。很遗憾，最后吃完花了500多后，我是饿着肚子出来的??
服务：服务中规中矩。', '2023-09-05', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e4de3c98b0941765bef', '市中心老牌五星级酒店，交通方便，酒店房间设施还比较新，干净，舒服。服务则有待加强，有点令人失望。
1. 入住和退房光排队各要15分钟，每个人办入住时间太长。退房时还比人插队，前台小姐姐没注意客人是否有排队。
2. 酒店早餐种类和服务对比同集团的南沙花园差太远了，吐槽一下负责蛋类制作的，估计是不粘锅使用太长时间了，不粘涂层都没有了，煎出来的鸡蛋基本是胡边的。Onmelet的制作技巧有待加强，早餐很多外国客人会点这个。', '["https://dimg04.c-ctrip.com/images/0235u12000c26yv8l5E96_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000c26phtz85AE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-09-03', '花园大床房', '大床房', '商务出差', 209, 5.3471075307174685, 1, 0.6931471805599453, 14, 2.70805020110221, 8, '["退房/入住效率", "餐饮设施", "房间设施"]'::jsonb, '退房/入住效率', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '市中心老牌五星级酒店，交通方便，酒店房间设施还比较新，干净，舒服。服务则有待加强', '市中心老牌五星级酒店，交通方便，酒店房间设施还比较新，干净，舒服。服务则有待加强，有点令人失望。
1. 入住和退房光排队各要15分钟，每个人办入住时间太长。退房时还比人插队，前台小姐姐没注意客人是否有排队。
2. 酒店早餐种类和服务对比同集团的南沙花园差太远了，吐槽一下负责蛋类制作的，估计是不粘锅使用太长时间了，不粘涂层都没有了，煎出来的鸡蛋基本是胡边的。Onmelet的制作技巧有待加强，早餐很多外国客人会点这个。', '2023-09-03', 4, '退房/入住效率');
