INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e58e3c98b0941765bf4', '这次又来入住广州花园酒店，因为离家近????小朋友们的staycation了～不知道为什么前台办理入住还是那么慢??房间升级了红棉客房，但是看到房间的刷牙杯垫发黄了，而且洗漱的时候很容易水就流出去杯子的区域??叫客房服务送东西，送第三次的时候，服务员很直接地说：你们还有要什么？要想清楚哈，不要等下又要叫??要不酒店也配几个送东西的机器人？这样不用劳烦服务员。
和之前疫情期间比起来，行政酒廊的餐饮丰富了很多，基本上早餐和晚餐在酒廊解决了，如果晚上能加两个热菜就完美了～
这次酒廊的小姐姐们都很温柔nice，Carrie、Katherine、cherry、Yana她们都很尽职尽责，特别是Carrie，对小孩子特别温柔，会及时帮忙??????
其他：希望酒店能加一些适合孩子们玩的游乐设施', '["https://dimg04.c-ctrip.com/images/0236n12000c26b8p825FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000c265y2y770C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000c26c0ubB2E0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-03', '花园大床房', '大床房', '家庭亲子', 344, 5.84354441703136, 0, 0.0, 1, 0.6931471805599453, 8, '["客房服务", "房间设施", "餐饮设施"]'::jsonb, '客房服务', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '这次又来入住广州花园酒店，因为离家近????小朋友们的staycation了～不', '这次又来入住广州花园酒店，因为离家近????小朋友们的staycation了～不知道为什么前台办理入住还是那么慢??房间升级了红棉客房，但是看到房间的刷牙杯垫发黄了，而且洗漱的时候很容易水就流出去杯子的区域??叫客房服务送东西，送第三次的时候，服务员很直接地说：你们还有要什么？要想清楚哈，不要等下又要叫??要不酒店也配几个送东西的机器人？这样不用劳烦服务员。
和之前疫情期间比起来，行政酒廊的餐饮丰富了很多，基本上早餐和晚餐在酒廊解决了，如果晚上能加两个热菜就完美了～
这次酒廊的小姐姐们都很温柔nice，Carrie、Katherine、cherry、Yana她们都很尽职尽责，特别是Carrie，对小孩子特别温柔，会及时帮忙??????
其他：希望酒店能加一些适合孩子们玩的游乐设施', '2023-09-03', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e58e3c98b0941765bf5', '九零年代就来花园酒店住过，这次来广州带着对花园的情节又住了3晚上，酒店界的标杆非花园莫属，一如既往地好，还会再来', '["https://dimg04.c-ctrip.com/images/0230x12000civavllE92D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000ciuzz7q7671_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000civ5lkx73BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000civ5freF3E1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-06', '花园大床房', '大床房', '独自旅行', 56, 4.04305126783455, 0, 0.0, 8, 2.19722457733622, 6, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '九零年代就来花园酒店住过，这次来广州带着对花园的情节又住了3晚上，酒店界的标杆非', '九零年代就来花园酒店住过，这次来广州带着对花园的情节又住了3晚上，酒店界的标杆非花园莫属，一如既往地好，还会再来', '2023-11-06', 5, '整体满意度');
