INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e58e3c98b0941765bf9', '本来的订的双床房到了前台Billy直接给我升级到了红棉套房，前台的服务真的非常好！整个酒店一进门就感受到了文化底蕴，真的超级漂亮。大堂每个地方都很好拍，有很多外国友人选择这家酒店，瀑布餐厅也是一大亮点，带小孩过来挺方便的。', '["https://dimg04.c-ctrip.com/images/0231u12000c1peaw69B26_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000c1pe8aq693A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000c1pf94r1BC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000c1ph83q2603_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000c1pj2u8AB85_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-01', '花园双床房', '双床房', '家庭亲子', 111, 4.718498871295094, 0, 0.0, 2, 1.0986122886681098, 8, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '本来的订的双床房到了前台Billy直接给我升级到了红棉套房，前台的服务真的非常好', '本来的订的双床房到了前台Billy直接给我升级到了红棉套房，前台的服务真的非常好！整个酒店一进门就感受到了文化底蕴，真的超级漂亮。大堂每个地方都很好拍，有很多外国友人选择这家酒店，瀑布餐厅也是一大亮点，带小孩过来挺方便的。', '2023-09-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e58e3c98b0941765bfa', '终于有机会打卡广州老牌酒店花园酒店，酒店工作人员热情洋溢、年轻活力，感受到无微不至的关怀，特别感谢Savanna和Ariel的亲切服务。酒店翻新后硬件提升更好，客房硬件用料扎实。公区富丽堂皇，花园风景如画，博物馆增长见识，颇有都市休闲感觉。让人流连忘返。酒廊早餐有单点，下午茶进步空间大，hh餐食丰富可吃饱，希望以后提升行政酒廊的硬件水平，增加如独立行政酒廊场所，酒廊ci、co服务等。', '["https://dimg04.c-ctrip.com/images/0234o12000ccdm79jEBC5_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233512000ccdm29mB3B9_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236e12000ccdm458E8B8_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230k12000ccdmlcbFE3E_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2023-10-06', '花园大床房', '大床房', '独自旅行', 193, 5.267858159063328, 0, 0.0, 13, 2.6390573296152584, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '终于有机会打卡广州老牌酒店花园酒店，酒店工作人员热情洋溢、年轻活力，感受到无微不', '终于有机会打卡广州老牌酒店花园酒店，酒店工作人员热情洋溢、年轻活力，感受到无微不至的关怀，特别感谢Savanna和Ariel的亲切服务。酒店翻新后硬件提升更好，客房硬件用料扎实。公区富丽堂皇，花园风景如画，博物馆增长见识，颇有都市休闲感觉。让人流连忘返。酒廊早餐有单点，下午茶进步空间大，hh餐食丰富可吃饱，希望以后提升行政酒廊的硬件水平，增加如独立行政酒廊场所，酒廊ci、co服务等。', '2023-10-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e58e3c98b0941765bfb', '想给这家酒店写大大的好评!太棒了~这个好评我必须要写
来这家酒店住过了两晚了~三天都觉得身心愉悦都还是那么的棒下次还要来!!!
环境真的超绝!
很适合假期去度假住一天会嫌少的，低调的掩映在车水马龙的城市中央
仿佛一处低调的世外桃源般
服务很棒
前台小姐姐、小哥、扫地的阿姨都好热情啊~
有送入住欢迎下午茶办理入住速度也很快!
酒店设施齐全
有游泳池、健身房园区内还有网红瀑布可以打卡
草坪也不错，百拍照很出片
超级多米其林餐厅，罗氏虾煲超nice!', '["https://dimg04.c-ctrip.com/images/0234112000c4d1wvx6E57_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000c4dax3sD827_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000c4d6cze39F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-13', '红棉大床套房', '套房', '家庭亲子', 224, 5.41610040220442, 0, 0.0, 12, 2.5649493574615367, 8, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '想给这家酒店写大大的好评!太棒了~这个好评我必须要写', '想给这家酒店写大大的好评!太棒了~这个好评我必须要写
