INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765bfc', '亲爱的花园酒店客服人员你们好，我们非常感谢您的支持与帮助。我们在酒店度过了非常愉快的三天，您让我们享用了很多美食，让我们了解到了花园酒店的历史与现在。再次感谢您的照顾，希望将来还能与你们相遇！——来自二年级的小崔同学口述评语（妈妈帮忙记录）
由衷感谢所有工作人员（行李服务、大堂迎宾、大堂经理、客房服务、30层自助旋转餐厅、工程维护等等）的热忱和美好善意，我们都记下了。期待再次重逢！', '["https://dimg04.c-ctrip.com/images/0235812000cc0y0rw94C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000cc10hu6653B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000cc0w50fD704_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000cc10hu82DB5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000cc0s9tf3EE1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000cc0zjclCA6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000cc0witd0C47_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000cc10g43A91C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000cc0vqmkB67E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '红棉双床套房', '套房', '家庭亲子', 192, 5.262690188904886, 1, 0.6931471805599453, 11, 2.4849066497880004, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '亲爱的花园酒店客服人员你们好，我们非常感谢您的支持与帮助。我们在酒店度过了非常愉', '亲爱的花园酒店客服人员你们好，我们非常感谢您的支持与帮助。我们在酒店度过了非常愉快的三天，您让我们享用了很多美食，让我们了解到了花园酒店的历史与现在。再次感谢您的照顾，希望将来还能与你们相遇！——来自二年级的小崔同学口述评语（妈妈帮忙记录）
