INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765bfd', '免费升级套房，非常宽敞舒适。周围吃饭购物也很便利，四楼还有酒店博物馆，非常用心了。而且步行两百多米就是地铁站，马路对面就是商场，很适合带娃citywalk', '["https://dimg04.c-ctrip.com/images/0235t12000cbmo67z3A67_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-04', '花园双床房', '双床房', '家庭亲子', 77, 4.356708826689592, 0, 0.0, 6, 1.9459101490553128, 8, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '免费升级套房，非常宽敞舒适。周围吃饭购物也很便利，四楼还有酒店博物馆，非常用心了', '免费升级套房，非常宽敞舒适。周围吃饭购物也很便利，四楼还有酒店博物馆，非常用心了。而且步行两百多米就是地铁站，马路对面就是商场，很适合带娃citywalk', '2023-10-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765bfe', '酒店本身就像一座小花园，瀑布，小桥，金鱼，红花真是风景优美。办理入住时对着红楼梦的壁画真是赏心悦目，酒店的服务超级好，进了大堂就不用管行李了，直接送入房间。因为生日还送了甜品和生日蛋糕，哈哈…', '["https://dimg04.c-ctrip.com/images/0231k12000c54djz0F405_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000c54l84964A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000c548zloEAFE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000c54oy99A52B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-15', '红棉大床套房', '套房', '家庭亲子', 96, 4.574710978503383, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '酒店本身就像一座小花园，瀑布，小桥，金鱼，红花真是风景优美。办理入住时对着红楼梦', '酒店本身就像一座小花园，瀑布，小桥，金鱼，红花真是风景优美。办理入住时对着红楼梦的壁画真是赏心悦目，酒店的服务超级好，进了大堂就不用管行李了，直接送入房间。因为生日还送了甜品和生日蛋糕，哈哈…', '2023-09-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765bff', '出差来广州，赶在入住时间比较晚了，用了自己在携程大促上囤的券小试一下，前台帮忙升级到了粤韵双床房，在前台稍微等了一下，但抵达房间时发现已经开好了夜床服务，点个赞。整体一定要给五星好评！下次还会来！??????????退房服务也超级Nice！
整体上粤韵套房的性价比超级高，各方面比较新，为了照顾日本旅客吧，双床之间还会有升降拉帘，这种小细节一般只有在日本才能感受到。但是双床房没有浴缸，以及办公位电源位置插不进Mac的充电器
床品对于我来讲非常干爽舒适了，前段时间在香港金钟JW万豪都觉得没有这么干爽舒适，干爽和舒适缺一不可，花园酒店做到了。
酒店餐饮：早餐就有惊艳到了，早餐我吃的2楼荔湾亭，完爆其他酒店，萝卜糕芋头糕牛肉粥等等等是外面各种大酒楼点心店吃不到的香气，幸福到会瞪大眼睛感叹的那种！另外一家是活动房券本身包含了500消费额，用在了桃园馆1人套餐，除了略贵没别的毛病，口感和卖相上匠心独运着实吃出了前中后调。另外最后一道甜品，值得单独说说！近期拔草的所有上海新晋网红店我都提不起兴趣，觉得就那样吧，但是！桃园馆套餐里配的甜品让我觉得我好像还是喜欢吃甜品的！
美中不足：抵达时未见迎宾门童、白天阳光照进房间发现卫生间门上玻璃擦拭不干净、卫生间和卧室之间的拉门上也擦拭不干净，不符合花园酒店的卫生定位。
但是花园酒店的粤韵套房依然很不错，下次值得再来～', '["https://dimg04.c-ctrip.com/images/0236c12000c28x1fkF107_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000c28qqka4222_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000c28uisqF2D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000c28x5c9F401_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000c28w8aw052F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000c28wja3D26D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000c28ugze47AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-03', '红棉双床套房', '套房', '商务出差', 585, 6.373319789577012, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "性价比", "卫生状况"]'::jsonb, '整体满意度', '性价比', '卫生状况', '未知酒店', '未知地点', '匿名', '出差来广州，赶在入住时间比较晚了，用了自己在携程大促上囤的券小试一下，前台帮忙升', '出差来广州，赶在入住时间比较晚了，用了自己在携程大促上囤的券小试一下，前台帮忙升级到了粤韵双床房，在前台稍微等了一下，但抵达房间时发现已经开好了夜床服务，点个赞。整体一定要给五星好评！下次还会来！??????????退房服务也超级Nice！
整体上粤韵套房的性价比超级高，各方面比较新，为了照顾日本旅客吧，双床之间还会有升降拉帘，这种小细节一般只有在日本才能感受到。但是双床房没有浴缸，以及办公位电源位置插不进Mac的充电器
床品对于我来讲非常干爽舒适了，前段时间在香港金钟JW万豪都觉得没有这么干爽舒适，干爽和舒适缺一不可，花园酒店做到了。
酒店餐饮：早餐就有惊艳到了，早餐我吃的2楼荔湾亭，完爆其他酒店，萝卜糕芋头糕牛肉粥等等等是外面各种大酒楼点心店吃不到的香气，幸福到会瞪大眼睛感叹的那种！另外一家是活动房券本身包含了500消费额，用在了桃园馆1人套餐，除了略贵没别的毛病，口感和卖相上匠心独运着实吃出了前中后调。另外最后一道甜品，值得单独说说！近期拔草的所有上海新晋网红店我都提不起兴趣，觉得就那样吧，但是！桃园馆套餐里配的甜品让我觉得我好像还是喜欢吃甜品的！
美中不足：抵达时未见迎宾门童、白天阳光照进房间发现卫生间门上玻璃擦拭不干净、卫生间和卧室之间的拉门上也擦拭不干净，不符合花园酒店的卫生定位。
但是花园酒店的粤韵套房依然很不错，下次值得再来～', '2023-09-03', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765c00', '品质非常的perfect,服务态度很好，设施优质，环境优美，地段便利，100米内就是地铁站，而且酒店内的美食非要的地道，特别是红棉房，小孩很喜欢', '["https://dimg04.c-ctrip.com/images/0236r12000cctlsfcEBA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000cctk4la07D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000cctlch5B6C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000cctp2qbB6F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000cctk4tbE562_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '红棉双床套房', '套房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 25, 3.258096538021482, 7, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '品质非常的perfect,服务态度很好，设施优质，环境优美，地段便利，100米内', '品质非常的perfect,服务态度很好，设施优质，环境优美，地段便利，100米内就是地铁站，而且酒店内的美食非要的地道，特别是红棉房，小孩很喜欢', '2023-10-08', 5, '交通便利性');
