INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765c03', '订了双床房 前台办理入住时加了点钱升级到了比原先大一倍的粤韵套房，太划算了，前台小姐姐与酒店的服务人员的服务态度都很好，入住后还送了一套宝格丽洗护用品+蛋糕拼盘??。酒店文化集聚了中国的古典文化特色，后花园也很漂亮，用完餐可以在里面逛逛，酒店的自助餐一流，这次过生日一家三口特意赶过来庆祝了一番，以后还会经常光顾的～', '["https://dimg04.c-ctrip.com/images/0232c12000c198ic6D997_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000c198ic8FE5C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000c19j0l182A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000c19c3mr5ABC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000c19jzzi74EC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000c19ilb0EE9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000c19igv90F61_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000c19k5q2E586_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-30', '花园双床房', '双床房', '家庭亲子', 158, 5.068904202220232, 0, 0.0, 1, 0.6931471805599453, 9, '["性价比", "前台服务", "餐饮设施"]'::jsonb, '性价比', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '订了双床房 前台办理入住时加了点钱升级到了比原先大一倍的粤韵套房，太划算了，前台', '订了双床房 前台办理入住时加了点钱升级到了比原先大一倍的粤韵套房，太划算了，前台小姐姐与酒店的服务人员的服务态度都很好，入住后还送了一套宝格丽洗护用品+蛋糕拼盘??。酒店文化集聚了中国的古典文化特色，后花园也很漂亮，用完餐可以在里面逛逛，酒店的自助餐一流，这次过生日一家三口特意赶过来庆祝了一番，以后还会经常光顾的～', '2023-08-30', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765c04', '真不知道网上为啥有些帖子说酒店不好？带娃在长隆住了两天，因最后一天长隆续房太贵，就定了花园一天，花园酒店升级了到了红棉，进房间后太惊喜，有客厅卫生条件非常好，连拖鞋的质感也超好，服务员阿姨态度非常好，酒店还免费加了床！这个性价比打败我住过所有的酒店。
关键酒店很有历史，国际、大牌、红棉房间设施也很新，隔音效果也不错，外面施工也不吵！周围非常方便，应有尽有！简直挑不出一出毛病来！真的印象太好了！对这次旅行来说真的是点睛之笔！', '["https://dimg04.c-ctrip.com/images/0203d12000c0pbhhf709F_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233312000c0oudqg8BF6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000c0oubyf8EE8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-28', '花园双床房', '双床房', '家庭亲子', 213, 5.365976015021851, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "性价比", "房间设施"]'::jsonb, '整体满意度', '性价比', '房间设施', '未知酒店', '未知地点', '匿名', '真不知道网上为啥有些帖子说酒店不好？带娃在长隆住了两天，因最后一天长隆续房太贵，', '真不知道网上为啥有些帖子说酒店不好？带娃在长隆住了两天，因最后一天长隆续房太贵，就定了花园一天，花园酒店升级了到了红棉，进房间后太惊喜，有客厅卫生条件非常好，连拖鞋的质感也超好，服务员阿姨态度非常好，酒店还免费加了床！这个性价比打败我住过所有的酒店。
关键酒店很有历史，国际、大牌、红棉房间设施也很新，隔音效果也不错，外面施工也不吵！周围非常方便，应有尽有！简直挑不出一出毛病来！真的印象太好了！对这次旅行来说真的是点睛之笔！', '2023-08-28', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e63e3c98b0941765c05', '冲着瀑布订的酒店，但一进酒店就最资深的豪华酒店之一的感觉震撼了，酒店位置和设施都很棒，一点也没老旧的感觉，去的那天正好是酒店多少周年活动，入住送了小饼干和鲜花。从窗户望去的感觉我感觉是值回一半房价的，房间设施也都挺不错的，配的的巴马的矿泉水，就是房间稍显局促，但还OK。孩子特别喜欢这个酒店，就有多住了一晚。交通很方便，门口就是地铁约车都很方便。就是希望服务能再亲民一些就更好了。', '["https://dimg04.c-ctrip.com/images/0233412000c0tv9sp4CD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000c0tw3r22572_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-08-28', '花园双床房', '双床房', '家庭亲子', 190, 5.25227342804663, 0, 0.0, 10, 2.3978952727983707, 8, '["景观/朝向", "交通便利性", "房间设施"]'::jsonb, '景观/朝向', '交通便利性', '房间设施', '未知酒店', '未知地点', '匿名', '冲着瀑布订的酒店，但一进酒店就最资深的豪华酒店之一的感觉震撼了，酒店位置和设施都', '冲着瀑布订的酒店，但一进酒店就最资深的豪华酒店之一的感觉震撼了，酒店位置和设施都很棒，一点也没老旧的感觉，去的那天正好是酒店多少周年活动，入住送了小饼干和鲜花。从窗户望去的感觉我感觉是值回一半房价的，房间设施也都挺不错的，配的的巴马的矿泉水，就是房间稍显局促，但还OK。孩子特别喜欢这个酒店，就有多住了一晚。交通很方便，门口就是地铁约车都很方便。就是希望服务能再亲民一些就更好了。', '2023-08-28', 3, '景观/朝向');
