INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c07', '过年气氛很好', '["https://dimg04.c-ctrip.com/images/0231e12000dbetn960E5F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-29', '花园双床房', '双床房', '家庭亲子', 6, 1.9459101490553128, 0, 0.0, 12, 2.5649493574615367, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '过年气氛很好', '过年气氛很好', '2024-02-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c08', '房间很大但显得陈旧了些，必须出新装修的。地段很不错，地铁站就在宾馆门口。', '["https://dimg04.c-ctrip.com/images/0234d12000cplov6kFD62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000cplp5r7DE8F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000cpltpwgFBB1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000cplj9uj7D51_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000cplssrgFB8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-12-10', '红棉双床套房', '套房', '朋友出游', 36, 3.610917912644224, 0, 0.0, 32, 3.49650756146648, 6, '["房间设施", "交通便利性"]'::jsonb, '房间设施', '交通便利性', NULL, '未知酒店', '未知地点', '匿名', '房间很大但显得陈旧了些，必须出新装修的。地段很不错，地铁站就在宾馆门口。', '房间很大但显得陈旧了些，必须出新装修的。地段很不错，地铁站就在宾馆门口。', '2023-12-10', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c09', '环境舒适，服务周到。', '["https://dimg04.c-ctrip.com/images/0231z12000d3l696r7EA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-01', '花园双床房', '双床房', '家庭亲子', 10, 2.3978952727983707, 0, 0.0, 12, 2.5649493574615367, 3, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '环境舒适，服务周到。', '环境舒适，服务周到。', '2024-02-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c0a', '【位置与环境】占据越秀核心地段，正门外就是地铁淘金站，周边五百米内有几个商场，购物餐饮相当方便。酒店内的几家米其林推荐餐厅比较热门，可能需要预约或等位较长时间。
【设施与服务】老牌五星级酒店，公共空间宽敞大气，花园也算一大特色。但房间布局和设施难免有些陈旧感，优缺点都比较明显。服务没问题，从前台到客房都很亲切负责，中英文服务都很优秀。', '["https://dimg04.c-ctrip.com/images/0236t12000c0r90rvAC43_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000c0r9flg1511_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-08-28', '城央绿意双床房', '双床房', '家庭亲子', 169, 5.135798437050262, 0, 0.0, 64, 4.174387269895637, 8, '["交通便利性", "周边配套", "公共设施"]'::jsonb, '交通便利性', '周边配套', '公共设施', '未知酒店', '未知地点', '匿名', '【位置与环境】占据越秀核心地段，正门外就是地铁淘金站，周边五百米内有几个商场，购', '【位置与环境】占据越秀核心地段，正门外就是地铁淘金站，周边五百米内有几个商场，购物餐饮相当方便。酒店内的几家米其林推荐餐厅比较热门，可能需要预约或等位较长时间。
【设施与服务】老牌五星级酒店，公共空间宽敞大气，花园也算一大特色。但房间布局和设施难免有些陈旧感，优缺点都比较明显。服务没问题，从前台到客房都很亲切负责，中英文服务都很优秀。', '2023-08-28', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c0b', '酒店里面很漂亮', '["https://dimg04.c-ctrip.com/images/0231512000d5ybscq63D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000d5ykndhA2BF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-09', '花园双床房', '双床房', '家庭亲子', 7, 2.079441541679836, 0, 0.0, 12, 2.5649493574615367, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '酒店里面很漂亮', '酒店里面很漂亮', '2024-02-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c0c', '红棉大床房套餐非常物超所值，除了国庆期间不能预定。特意去了酒店的桃园馆，菜品果然名不虚传，可用套餐中的500元消费券。因为前两晚所订房型跟最后这日套餐不同，入住时酒店大堂Viria特意帮忙升级了房间，避免换房之苦，帮这次出行节省了不少麻烦，特此感谢。
酒店4楼的博物院值得一去，没想到关于古今酒店业发展历史及未来趋势干货满满，即使在酒店晚一整天也不会感觉枯燥。', '["https://dimg04.c-ctrip.com/images/0236x12000ccyabp99353_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000ccyay1jE05B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000ccy9ybw4EA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000ccy9i1gD0C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000ccy9infA306_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-09', '红棉大床套房', '套房', '朋友出游', 180, 5.198497031265826, 0, 0.0, 6, 1.9459101490553128, 9, '["性价比", "餐饮设施", "前台服务"]'::jsonb, '性价比', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '红棉大床房套餐非常物超所值，除了国庆期间不能预定。特意去了酒店的桃园馆，菜品果然', '红棉大床房套餐非常物超所值，除了国庆期间不能预定。特意去了酒店的桃园馆，菜品果然名不虚传，可用套餐中的500元消费券。因为前两晚所订房型跟最后这日套餐不同，入住时酒店大堂Viria特意帮忙升级了房间，避免换房之苦，帮这次出行节省了不少麻烦，特此感谢。
酒店4楼的博物院值得一去，没想到关于古今酒店业发展历史及未来趋势干货满满，即使在酒店晚一整天也不会感觉枯燥。', '2023-10-09', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c0d', '服务很好，房间也舒适', '["https://dimg04.c-ctrip.com/images/0235512000d6wwyf75F0D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-13', '红棉大床套房', '套房', '家庭亲子', 10, 2.3978952727983707, 0, 0.0, 4, 1.6094379124341005, 4, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '服务很好，房间也舒适', '服务很好，房间也舒适', '2024-02-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c0e', '老牌酒店，值得入住。', '["https://dimg04.c-ctrip.com/images/0236212000d480zs18570_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000d48ctdf03E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000d488737D218_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000d486d2m59D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000d48h501677F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-03', '花园双床房', '双床房', '家庭亲子', 10, 2.3978952727983707, 0, 0.0, 10, 2.3978952727983707, 3, '["整体满意度", "性价比"]'::jsonb, '整体满意度', '性价比', NULL, '未知酒店', '未知地点', '匿名', '老牌酒店，值得入住。', '老牌酒店，值得入住。', '2024-02-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e6fe3c98b0941765c0f', '收到携程的点评邀请，那就来评评吧，吐槽一下这次入住遇到的小小不愉快。这家酒店之前住过，因为是出差，匆匆来去对服务没啥特别感觉，但环境还是不错的，虽然现在好酒店选择不少，但花园酒店在广州土族同学的心目中一直是高档酒店的存在；个人喜欢现代风格的，所以虽然红棉房间大一些，这次还是订了重新装修后的花园大床房。去的当天飞机长时间延误，起飞时间不确定，候机的时候特意给酒店打电话告知晚上会晚到请她们保留房间（其实房间本身也是不可退的），并且请她帮忙换一下双床房，工作人员也表示已帮忙备注没有问题。我晚上8点到酒店时又累又饿，也不想多说话，和前台提到下午电话请她们换双床房，并问有没有高一些的房间，前台开始了长时间啪啦啪啦敲键盘，过了十多分钟也没好，中间问了我是哪个平台定的房间。后来告诉我没有高楼层的房间，可以给我景观最好的对着瀑布的8楼房间，我拒绝了，这个瀑布很吵影响休息，就问可以升级吗？“有红棉套房”，我说那算了还是给我原来预定的房间吧，有再高一点楼层吗？“最高就是9楼”，我问“今天就没有再高一点房间了？”，回复“今天太晚了（8点多是太晚？）”，我说这和今天太晚有什么关系，有就是有没有就是没有，又是长时间的沉默和敲击键盘，中间前台问了边上的小姑娘，人家不耐烦回复“刚才不是说了没有双床房吗？”，后来前台说“要不今天就住低楼层明天帮你换”，这时候快20分钟过去了，我也有点不高兴，精力也有点恢复了，我说我订的房型本来就是写的18-21楼，携程上这个双床房也可以预定，下午还特意打电话过来说了房间的事，为啥现在没有房间呢（有点不相信这么大体量的酒店还能住满）？请领导过来我问一下，更让人气愤的是边上小姑娘说是领导，就和我们隔了一米的距离一直闲在那，中间没人找她办过入住，前面听了20分钟这边发生的事情，居然能做到一直没反应，始终没主动站出来处理一下，好歹也是家高级酒店，这种服务意识令人失望，小姑娘过来看了电脑没几秒，就说其实给我预留了20楼的双床房前面没看到。无语，我又累又饿白白在前台站20分钟发了一顿火才拿到我预定房间的门卡？也不知道前面迟迟不愿给我预定的房间是出于什么考虑？另外，酒店楼下马路在修路，从早到晚都是机器马达声，喜欢安静的建议绕路这家酒店。', '["https://dimg04.c-ctrip.com/images/0231112000c0ebhen6C01_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000c0eaj5e8EDA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000c0e7c941C8A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000c0ecsxp10DA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-08-26', '花园大床房', '大床房', '商务出差', 928, 6.834108738813838, 0, 0.0, 13, 2.6390573296152584, 9, '["前台服务", "退房/入住效率", "安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度', '未知酒店', '未知地点', '匿名', '收到携程的点评邀请，那就来评评吧，吐槽一下这次入住遇到的小小不愉快。这家酒店之前', '收到携程的点评邀请，那就来评评吧，吐槽一下这次入住遇到的小小不愉快。这家酒店之前住过，因为是出差，匆匆来去对服务没啥特别感觉，但环境还是不错的，虽然现在好酒店选择不少，但花园酒店在广州土族同