INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c10', '名不虚传的美食酒店，里面有四五家餐厅，食物精致美味。打卡了荔湾庭和瀑布餐厅。套餐非常划算，有500元抵用券可以在餐厅抵用。会员赠送了行政酒廊早晚餐和下午茶。酒店里充满具有岭南特色的装饰，红龙梦金箔壁画、木雕藻井、木雕家具等等，还有博物馆和后花园可以餐馆。住宿设施上，红棉房床品舒适度极高，设施齐备。唯一不足的是老牌酒店，房间有些味道，在可接受范围内。', '["https://dimg04.c-ctrip.com/images/0233x12000c3nmkblF289_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000c3mxj1j556F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000c3mw6hkE30B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '红棉双床套房', '套房', '家庭亲子', 175, 5.170483995038151, 0, 0.0, 3, 1.3862943611198906, 9, '["餐饮设施", "性价比", "房间设施"]'::jsonb, '餐饮设施', '性价比', '房间设施', '未知酒店', '未知地点', '匿名', '名不虚传的美食酒店，里面有四五家餐厅，食物精致美味。打卡了荔湾庭和瀑布餐厅。套餐', '名不虚传的美食酒店，里面有四五家餐厅，食物精致美味。打卡了荔湾庭和瀑布餐厅。套餐非常划算，有500元抵用券可以在餐厅抵用。会员赠送了行政酒廊早晚餐和下午茶。酒店里充满具有岭南特色的装饰，红龙梦金箔壁画、木雕藻井、木雕家具等等，还有博物馆和后花园可以餐馆。住宿设施上，红棉房床品舒适度极高，设施齐备。唯一不足的是老牌酒店，房间有些味道，在可接受范围内。', '2023-09-10', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c11', '酒店氛围很好，服务员工作主动热情 ，做事情忙而不乱。
酒店开业多年  但设施维护很好，并不显残旧，酒店所承载的历史反而成为酒店自身的魅力，这也是我选住花园酒店的主要原因。', '["https://dimg04.c-ctrip.com/images/0231r12000c4dzt4l995F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000c4e3x6rF3F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000c4e35rt8323_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000c4dzycs2A04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000c4e4bve9E33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000c4e4ac80F4D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000c4e4a5v7F52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000c4dzyqe682F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-13', '花园大床房', '大床房', '情侣出游', 85, 4.454347296253507, 0, 0.0, 6, 1.9459101490553128, 8, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '酒店氛围很好，服务员工作主动热情 ，做事情忙而不乱。', '酒店氛围很好，服务员工作主动热情 ，做事情忙而不乱。
酒店开业多年  但设施维护很好，并不显残旧，酒店所承载的历史反而成为酒店自身的魅力，这也是我选住花园酒店的主要原因。', '2023-09-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c12', '房间舒适，设施完善。入住很是惬意，大堂很美，服务态度很好??', '["https://dimg04.c-ctrip.com/images/0236312000cqtpts96049_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000cqttqq9D916_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-16', '花园大床房', '大床房', '家庭亲子', 30, 3.4339872044851463, 0, 0.0, 2, 1.0986122886681098, 5, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '房间舒适，设施完善。入住很是惬意，大堂很美，服务态度很好??', '房间舒适，设施完善。入住很是惬意，大堂很美，服务态度很好??', '2023-12-16', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c13', '非常非常不建议这段时间入住，外面在施工太吵了，晚上施工到9，10点，听得无比烦躁，房间里压根不能待，早上7点就被施工的声音吵醒了，休假期间就想好好睡个觉，上一个酒店每天睡到9，10点才醒，这个酒店到好，7点就被吵醒，幸亏只订个一晚', '["https://dimg04.c-ctrip.com/images/0235o12000bzovub82ECF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000bzp0q5hEDC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000bzp0q5l3AE2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-08-24', '红棉大床套房', '套房', '独自旅行', 115, 4.7535901911063645, 2, 1.0986122886681098, 11, 2.4849066497880004, 8, '["安静程度", "整体满意度"]'::jsonb, '安静程度', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '非常非常不建议这段时间入住，外面在施工太吵了，晚上施工到9，10点，听得无比烦躁', '非常非常不建议这段时间入住，外面在施工太吵了，晚上施工到9，10点，听得无比烦躁，房间里压根不能待，早上7点就被施工的声音吵醒了，休假期间就想好好睡个觉，上一个酒店每天睡到9，10点才醒，这个酒店到好，7点就被吵醒，幸亏只订个一晚', '2023-08-24', 2, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c14', '和父母来，本来是想再次回味一下广州的老牌酒店，没想到是这么的脏，打扫完的房间还有长头发，酒店茶餐厅的服务人员也非常排外，很明显提供不平等对待！', '["https://dimg04.c-ctrip.com/images/0234x12000cbx013o6647_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-10-05', '花园大床房', '大床房', '家庭亲子', 71, 4.276666119016055, 0, 0.0, 2, 1.0986122886681098, 7, '["卫生状况", "前台服务"]'::jsonb, '卫生状况', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '和父母来，本来是想再次回味一下广州的老牌酒店，没想到是这么的脏，打扫完的房间还有', '和父母来，本来是想再次回味一下广州的老牌酒店，没想到是这么的脏，打扫完的房间还有长头发，酒店茶餐厅的服务人员也非常排外，很明显提供不平等对待！', '2023-10-05', 1, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c15', '房间非常不错，环境很漂亮噢！特别是酒店的大堂和用餐区，非常的气派，难怪有这么多外国友人过来！值得一提的是离地铁站非常非常的近，出行很方便。去广州塔，动物园，珠江夜游等景区五个站不到。晚上回来居然还有小点心。老人家出行必须要夸一下这里，配备了硬床板，腰疼得到了很好的缓解，以后来广州还会再来的，再次感谢花园酒店！', '["https://dimg04.c-ctrip.com/images/0231112000c34qqsk0B08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000c34m2c90DC9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000c34twdv5F4E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000c34muyn565A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-09-07', '花园双床房', '双床房', '家庭亲子', 155, 5.049856007249537, 0, 0.0, 1, 0.6931471805599453, 9, '["交通便利性", "房间设施", "整体满意度"]'::jsonb, '交通便利性', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '房间非常不错，环境很漂亮噢！特别是酒店的大堂和用餐区，非常的气派，难怪有这么多外', '房间非常不错，环境很漂亮噢！特别是酒店的大堂和用餐区，非常的气派，难怪有这么多外国友人过来！值得一提的是离地铁站非常非常的近，出行很方便。去广州塔，动物园，珠江夜游等景区五个站不到。晚上回来居然还有小点心。老人家出行必须要夸一下这里，配备了硬床板，腰疼得到了很好的缓解，以后来广州还会再来的，再次感谢花园酒店！', '2023-09-07', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e7de3c98b0941765c16', '设施：配套设施齐全
