INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e88e3c98b0941765c1b', '一家38年历史的老酒店，管理、服务依然是那么好。美中不足是设施上要更进一步才能赶上多元化多样性的需求，建议管理者从顾客多元化需求方面考虑改进。如枕头的软与硬。羽绒枕固然好，可我更喜欢乳胶枕，睡觉睡不好，整个人一天都不爽。住的时候刚好碰上泳池维修，没能畅游一番很是遗憾。', '["https://dimg04.c-ctrip.com/images/0236r12000bzam50aA064_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000bzam96b8F8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000bzaori1403C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-08-23', '花园大床房', '大床房', '家庭亲子', 134, 4.90527477843843, 0, 0.0, 4, 1.6094379124341005, 8, '["房间设施", "公共设施", "整体满意度"]'::jsonb, '房间设施', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '一家38年历史的老酒店，管理、服务依然是那么好。美中不足是设施上要更进一步才能赶', '一家38年历史的老酒店，管理、服务依然是那么好。美中不足是设施上要更进一步才能赶上多元化多样性的需求，建议管理者从顾客多元化需求方面考虑改进。如枕头的软与硬。羽绒枕固然好，可我更喜欢乳胶枕，睡觉睡不好，整个人一天都不爽。住的时候刚好碰上泳池维修，没能畅游一番很是遗憾。', '2023-08-23', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e88e3c98b0941765c1c', '很愉快的一次入住！酒店环境好，服务棒！尤其是这次入住赠送行政酒廊的下午茶和欢乐时光，里面二个班的小姐姐都特别有趣有心！Katherine,Cherry,Yana这三个小姐妹我遇上了二次，尤其是Yana特别贴心，给我介绍酒店好玩好看的地方，谢谢啦！
