INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e88e3c98b0941765c20', '第二次在携程订的，房间很大，设施都很好，一楼早餐人很多，要排队，二楼早餐品类少些也够吃，但是人少
用劵买了晚餐，不知道是不是人多，味道跟上次比有所下降，但是工作人员的还是一样的nice，很热情', '["https://dimg04.c-ctrip.com/images/0232h12000bzpmo8j966E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000bzpzuqz68E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000bzpv72y8BF6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000bzpy9lq7904_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000bzq0p2oDF5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-24', '红棉大床套房', '套房', '情侣出游', 96, 4.574710978503383, 0, 0.0, 25, 3.258096538021482, 7, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '第二次在携程订的，房间很大，设施都很好，一楼早餐人很多，要排队，二楼早餐品类少些', '第二次在携程订的，房间很大，设施都很好，一楼早餐人很多，要排队，二楼早餐品类少些也够吃，但是人少
