INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e88e3c98b0941765c21', '老牌五星酒店整体不失水准，保持着自己的特色，及五星酒店该有的标准，值得推荐！大气宽敞的大堂，酒店前台有序高效的办理入住，全程笑容满面，非常nice!礼宾部的服务人员也很不错哦????酒店内（除房间）随处可见的花艺展示是酒店的一大亮点，入住时前台妹妹提供的酒店内景打卡，还不错，可以逛逛拍拍，酒店内的后花园虽小，却不影响她的特色。大堂吧有时间可以去坐坐，面包和咖啡?不错????
建议酒店房间内的卫生间，特别是冲凉房的设计，最好改善提升一下，太局促不方便，拉低了酒店整体满意度。房间内空调静音效果不错，花洒??水压足，好多五星酒店上述两点都不咋样。早餐品种少了点，希望以后能有改变。
整体不错！', '["https://dimg04.c-ctrip.com/images/0233712000byj9s9u3182_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000byjbzelB37E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000byj7a0wECE8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000byizzuj6CA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000byja5317414_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000byj8egh4E39_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 296, 5.6937321388027, 2, 1.0986122886681098, 4, 1.6094379124341005, 8, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '老牌五星酒店整体不失水准，保持着自己的特色，及五星酒店该有的标准，值得推荐！大气', '老牌五星酒店整体不失水准，保持着自己的特色，及五星酒店该有的标准，值得推荐！大气宽敞的大堂，酒店前台有序高效的办理入住，全程笑容满面，非常nice!礼宾部的服务人员也很不错哦????酒店内（除房间）随处可见的花艺展示是酒店的一大亮点，入住时前台妹妹提供的酒店内景打卡，还不错，可以逛逛拍拍，酒店内的后花园虽小，却不影响她的特色。大堂吧有时间可以去坐坐，面包和咖啡?不错????
建议酒店房间内的卫生间，特别是冲凉房的设计，最好改善提升一下，太局促不方便，拉低了酒店整体满意度。房间内空调静音效果不错，花洒??水压足，好多五星酒店上述两点都不咋样。早餐品种少了点，希望以后能有改变。
整体不错！', '2023-08-20', 3, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e88e3c98b0941765c22', '老牌五星级酒店', '["https://dimg04.c-ctrip.com/images/0236m12000d2pb5di11E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-29', '城央绿意双床房', '双床房', '家庭亲子', 7, 2.079441541679836, 0, 0.0, 1, 0.6931471805599453, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '老牌五星级酒店', '老牌五星级酒店', '2024-01-29', 5, '整体满意度');
