INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c25', '来广州旅行，花园酒店是一个非常好的选择。酒店在市中心，有地铁可以直接到。淘金站上来就是。大堂非常气派。服务非常周到。客房干净，服务人员热情。里面有很多外国人。二楼的早餐非常好吃。每天都有更新。总体来说非常满意！', '["https://dimg04.c-ctrip.com/images/0230312000bts6cjd8EDD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000btryuo06FD5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000bts0sisBD25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000bts5gqp88F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000bts4l6rE5F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000bts3ebs619B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000bts5s752B1B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000btrx3vd7D5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000btrzoc72BDD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-04', '红棉双床套房', '套房', '家庭亲子', 105, 4.663439094112067, 3, 1.3862943611198906, 8, 2.19722457733622, 7, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '来广州旅行，花园酒店是一个非常好的选择。酒店在市中心，有地铁可以直接到。淘金站上', '来广州旅行，花园酒店是一个非常好的选择。酒店在市中心，有地铁可以直接到。淘金站上来就是。大堂非常气派。服务非常周到。客房干净，服务人员热情。里面有很多外国人。二楼的早餐非常好吃。每天都有更新。总体来说非常满意！', '2023-08-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c26', '花园酒店非常惊艳，是全家广州行觉得性价比最高的选择。首先是酒店的环境大气又有历史沉淀，然后是餐厅，酒店里面有几家米其林，早餐的两家餐厅都非常惊艳。难得的是酒店不但适合商务入住还适合亲子旅游，周边交通方便，商场和美食也不少。孩子最喜欢的就是去后花园喂小鱼了，唯一可惜的是露天泳池没有开放。', '["https://dimg04.c-ctrip.com/images/0230c12000bxqdopw889E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000bxqesqs5E4A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000bxqjo1yAAFB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000bxqeuw09816_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-17', '花园双床房', '双床房', '家庭亲子', 143, 4.969813299576001, 0, 0.0, 2, 1.0986122886681098, 9, '["性价比", "餐饮设施", "交通便利性"]'::jsonb, '性价比', '餐饮设施', '交通便利性', '未知酒店', '未知地点', '匿名', '花园酒店非常惊艳，是全家广州行觉得性价比最高的选择。首先是酒店的环境大气又有历史', '花园酒店非常惊艳，是全家广州行觉得性价比最高的选择。首先是酒店的环境大气又有历史沉淀，然后是餐厅，酒店里面有几家米其林，早餐的两家餐厅都非常惊艳。难得的是酒店不但适合商务入住还适合亲子旅游，周边交通方便，商场和美食也不少。孩子最喜欢的就是去后花园喂小鱼了，唯一可惜的是露天泳池没有开放。', '2023-08-17', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c27', '房间非常满意，前台亲切，给我感觉特别好，一进大堂确实给我很震惊，富丽堂皇，面积如此之大，还有演出和弹琴～房间和早餐都很有广州特色～', '["https://dimg04.c-ctrip.com/images/0231a12000cc5x7iy8353_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000cc5uhbb7D2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000cc5uhbd583A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000cc5v1kz6212_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园大床房', '大床房', '商务出差', 65, 4.189654742026425, 0, 0.0, 5, 1.791759469228055, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间非常满意，前台亲切，给我感觉特别好，一进大堂确实给我很震惊，富丽堂皇，面积如', '房间非常满意，前台亲切，给我感觉特别好，一进大堂确实给我很震惊，富丽堂皇，面积如此之大，还有演出和弹琴～房间和早餐都很有广州特色～', '2023-10-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c28', '慕瀑布餐厅名而来，有更多惊喜。老派酒店新式装修设施齐全服务细致。泳池赞。自助晚餐的牛扒和甜品很正！芝士蛋糕好吃！还看了个小画展。', '["https://dimg04.c-ctrip.com/images/0235912000cci24mz48F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000cci09l13B1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000cchyw0pB85D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000cci3nijF9AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000cci4fgy72AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-07', '花园大床房', '大床房', '独自旅行', 64, 4.174387269895637, 0, 0.0, 4, 1.6094379124341005, 7, '["餐饮设施", "公共设施", "整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '慕瀑布餐厅名而来，有更多惊喜。老派酒店新式装修设施齐全服务细致。泳池赞。自助晚餐', '慕瀑布餐厅名而来，有更多惊喜。老派酒店新式装修设施齐全服务细致。泳池赞。自助晚餐的牛扒和甜品很正！芝士蛋糕好吃！还看了个小画展。', '2023-10-07', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c29', '首先说第一印象
1.服务:所有工作人员都很热情耐心友好，说真的特别温暖！第一晚的房间厕所反味，和大堂的bobo说了，立马给安排成了套房还送了小点心和一张手写信！服务方面真的无可挑剔！
2.设施:大堂很大，富丽堂皇的感觉，配套有棋牌室，壁球室，健身室，网球场，按摩室，桑拿浴室，室外游泳池，SPA（都没去，就看到室外泳池一直在维护无法使用）
3.儿童:
前台办理入住的时候，看到有带小孩就有工作人员上来发酒店自己做的黄油曲奇，和蔓越莓曲奇！yummy
还可以在前台领打卡的卡片，集满3个章就可以换一张书签，对于小朋友也很有趣啦，也可以顺便深度逛一逛酒店！
酒店内有花园酒店博物馆，周一闭馆，可以带娃去逛逛（也是一个集章打卡点）
4.房间:相对紧凑，没那么宽敞！
5.交通:酒店出门就是地铁站??出行便利，要坐APM线需要换乘相对麻烦点。
6.吃饭:酒店附近200m内就有广州酒家，点都德！走路就能到!花园酒店的早茶和瀑布餐厅也很有名
7.国际化:在花园酒店这几天真的是3步一个外国人，非常international了，酒店周围也全是外国人！工作人员想必外语肯定各个都很赞！
8.周边:第二天妹妹生病了，导航到周围几百米有一家医院，过去没有儿科，又打车过去中山大学附属第一医院，去医院也不远！能酒店深度评价到周边医院，多夸了我的好大儿
	花园酒店一共住了2晚，真的能感受到广州人民的热情专业温暖的服务！', '["https://dimg04.c-ctrip.com/images/0234u12000byi4cu60BA4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000byi16oxB0B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000byhr4us9780_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000byi4mzdFA14_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 603, 6.403574197934815, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "公共设施", "交通便利性"]'::jsonb, '前台服务', '公共设施', '交通便利性', '未知酒店', '未知地点', '匿名', '首先说第一印象', '首先说第一印象
