	花园酒店一共住了2晚，真的能感受到广州人民的热情专业温暖的服务！', '2023-08-20', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c2a', '其实家就在附近，想临时抛开家里孩子谈谈恋爱。其实之前家里有亲戚之类的过来广州玩也会选择花园酒店。但是这回住又有新体验。前台的billy服务非常热情满脸笑容。为我们安排了可以吸烟的房型并做了升级。非常详细的介绍了房间是新装修过望花园瀑布，以及行政礼遇和设施。非常感动！装修后的花园酒店方方面面都符合五星级标准', '["https://dimg04.c-ctrip.com/images/0234i12000ccqa1nh68AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000ccq9cs309D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000ccqeipo6E20_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000ccqe6eyF5A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000ccqbo2m56B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000ccqbkdjE34D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000ccqb0qo8169_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000ccqchj74159_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000ccqa7xs408E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '红棉大床套房', '套房', '情侣出游', 153, 5.0369526024136295, 0, 0.0, 33, 3.5263605246161616, 8, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '其实家就在附近，想临时抛开家里孩子谈谈恋爱。其实之前家里有亲戚之类的过来广州玩也', '其实家就在附近，想临时抛开家里孩子谈谈恋爱。其实之前家里有亲戚之类的过来广州玩也会选择花园酒店。但是这回住又有新体验。前台的billy服务非常热情满脸笑容。为我们安排了可以吸烟的房型并做了升级。非常详细的介绍了房间是新装修过望花园瀑布，以及行政礼遇和设施。非常感动！装修后的花园酒店方方面面都符合五星级标准', '2023-10-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c2b', '房间设计西式化，估计当年是跟中国大酒店各不同风格，一个中式一个西式。吃早餐也是分中西式两个厅。服务生态度非常亲和，吃早餐虽然要排队等候，但是就算是一个人也可以选择坐一张桌子不与别人share，还会特意写上“留坐”示意。非常人性化。酒店很华丽！没住过的可以去感受一下。中餐厅也很有氛围。', '["https://dimg04.c-ctrip.com/images/0230812000bwjgd2b0592_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000bwjcjk37D0A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000bwjdkutF45F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-08-13', '花园大床房', '大床房', '其他', 142, 4.962844630259907, 0, 0.0, 9, 2.302585092994046, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间设计西式化，估计当年是跟中国大酒店各不同风格，一个中式一个西式。吃早餐也是分', '房间设计西式化，估计当年是跟中国大酒店各不同风格，一个中式一个西式。吃早餐也是分中西式两个厅。服务生态度非常亲和，吃早餐虽然要排队等候，但是就算是一个人也可以选择坐一张桌子不与别人share，还会特意写上“留坐”示意。非常人性化。酒店很华丽！没住过的可以去感受一下。中餐厅也很有氛围。', '2023-08-13', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e94e3c98b0941765c2c', '体验感最差的一次酒店入住，看乌鸦行为的视频被媒来的，视频里酒店设施看起来还挺好的，结果入住后发现设施陈旧，房间狭小，晚上洗个澡，水就从洗澡间里漏出来了，而且不是一点点，联系客房服务给换了一间房，感觉还是有点渗，只是没那么严重，忍了，窗台上是黑灰色的都是泥灰尘留下的痕迹，团购还一千五一晚的房费就这个样子，真心上当受骗，房间差成这样我又何必再在这个酒店多花一个子。', '["https://dimg04.c-ctrip.com/images/0233612000bwqm6bnF289_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000bwqk05l2146_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000bwqksflD0EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000bwqjmh8552D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-08-14', '花园双床房', '双床房', '家庭亲子', 181, 5.204006687076795, 4, 1.6094379124341005, 7, 2.079441541679836, 9, '["房间设施", "卫生状况", "性价比"]'::jsonb, '房间设施', '卫生状况', '性价比', '未知酒店', '未知地点', '匿名', '体验感最差的一次酒店入住，看乌鸦行为的视频被媒来的，视频里酒店设施看起来还挺好的', '体验感最差的一次酒店入住，看乌鸦行为的视频被媒来的，视频里酒店设施看起来还挺好的，结果入住后发现设施陈旧，房间狭小，晚上洗个澡，水就从洗澡间里漏出来了，而且不是一点点，联系客房服务给换了一间房，感觉还是有点渗，只是没那么严重，忍了，窗台上是黑灰色的都是泥灰尘留下的痕迹，团购还一千五一晚的房费就这个样子，真心上当受骗，房间差成这样我又何必再在这个酒店多花一个子。', '2023-08-14', 1, '房间设施');
