INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e9ee3c98b0941765c32', '带娃出游，准备退房的时候，小宝宝闹觉，要睡觉，跟前台说明理由后，小姐姐延迟让我们退房，让宝宝睡一会！这点很窝心，服务很好！', '["https://dimg04.c-ctrip.com/images/0232y12000ccb3zyjB4D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000ccb3qw0C7F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000ccb3qw25D41_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 6, 1.9459101490553128, 7, '["前台服务", "退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL, '未知酒店', '未知地点', '匿名', '带娃出游，准备退房的时候，小宝宝闹觉，要睡觉，跟前台说明理由后，小姐姐延迟让我们', '带娃出游，准备退房的时候，小宝宝闹觉，要睡觉，跟前台说明理由后，小姐姐延迟让我们退房，让宝宝睡一会！这点很窝心，服务很好！', '2023-10-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e9ee3c98b0941765c33', '第一次住花园酒店，老牌的酒店了，无论交通，酒店设施都很方便齐备。', '["https://dimg04.c-ctrip.com/images/0236912000cmzgvcm1817_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000cmzivu9F016_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000cmzlg0n4D15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000cmzhk7s25A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-26', '花园大床房', '大床房', '其他', 32, 3.49650756146648, 0, 0.0, 30, 3.4339872044851463, 5, '["交通便利性", "房间设施", "公共设施"]'::jsonb, '交通便利性', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '第一次住花园酒店，老牌的酒店了，无论交通，酒店设施都很方便齐备。', '第一次住花园酒店，老牌的酒店了，无论交通，酒店设施都很方便齐备。', '2023-11-26', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e9ee3c98b0941765c34', '我很高兴能够分享我对入住广州花园酒店体验，非常令人满意。花园酒店作为广州的一家知名五星级酒店，在服务和设施方面都非常出色。入住体验非常愉快，让我感受到了高品质的服务和舒适的环境。
首先，我非常欣赏酒店的设计和装修。房间宽敞明亮，设施齐全，而且非常干净整洁。床铺舒适，让我每天都能够得到充分的休息。浴室设施完善，包括高品质的洗浴用品和浴袍等，让我感到非常舒适。
其次，我非常满意酒店的服务。员工都非常友好和专业，能够满足我所有的需求。他们始终保持微笑，让人感到非常亲切。此外，酒店还提供了许多额外的服务，例如早餐、下午茶和晚间鸡尾酒等，这些服务都非常出色。
在性价比方面，我认为花园酒店的价格非常合理。虽然价格稍高，但考虑到酒店的高品质服务和设施，我认为这笔钱花得非常值得。如果你正在寻找一家高品质的酒店，我认为花园酒店是一个非常好的选择。
总的来说，我对“入住广州花园酒店体验”的评价非常高。酒店的服务和设施都非常好，让我感到非常舒适和满意。如果你正在计划来广州旅游，我强烈推荐你选择花园酒店作为你的住宿地点。总之，这是一次非常愉快的购物体验，我非常满意。', '["https://dimg04.c-ctrip.com/images/0234812000c880ow4A3A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000c885i30FC8F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000c886rx3A008_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000c882ure8C12_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232m12000c883ckg2120_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000c886e1s61BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-24', '花园大床房', '大床房', '朋友出游', 482, 6.180016653652572, 0, 0.0, 73, 4.30406509320417, 9, '["整体满意度", "房间设施", "性价比"]'::jsonb, '整体满意度', '房间设施', '性价比', '未知酒店', '未知地点', '匿名', '我很高兴能够分享我对入住广州花园酒店体验，非常令人满意。花园酒店作为广州的一家知', '我很高兴能够分享我对入住广州花园酒店体验，非常令人满意。花园酒店作为广州的一家知名五星级酒店，在服务和设施方面都非常出色。入住体验非常愉快，让我感受到了高品质的服务和舒适的环境。
