卫生：干净整洁
环境：旁边工地打桩到10点左右会停工。感觉吵闹可以去对面世贸，友谊转转，吃点东西，再回来。
设施：还行吧，浴盆的位置有点怪。卫生间和卧室通透，会有点气味传过来。先到外边的房间等10分钟再去卧室就没有气味。', '2023-08-06', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ea9e3c98b0941765c3b', '酒店年限有些久，设施相对有些老旧，楼下就是地铁口这点相对比较方便，服务人员态度一般，吃自助餐的时候还没吃完就要我签字房号。没有惊喜。花园瀑布餐厅算是一个打卡地非常出片。', '["https://dimg04.c-ctrip.com/images/0230z12000cawrf685F64_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000cax4hai9636_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000cawu33o6E33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-10-01', '红棉大床套房', '套房', '家庭亲子', 84, 4.442651256490317, 0, 0.0, 15, 2.772588722239781, 7, '["房间设施", "交通便利性", "餐饮设施"]'::jsonb, '房间设施', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店年限有些久，设施相对有些老旧，楼下就是地铁口这点相对比较方便，服务人员态度一', '酒店年限有些久，设施相对有些老旧，楼下就是地铁口这点相对比较方便，服务人员态度一般，吃自助餐的时候还没吃完就要我签字房号。没有惊喜。花园瀑布餐厅算是一个打卡地非常出片。', '2023-10-01', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ea9e3c98b0941765c3c', '位置非常好，吃饭非常方便，酒店打卡的人很多，瀑布餐厅名不虚传，早餐服务很好，花园可以带小朋友喂鱼，博物馆也可以看一看。', '["https://dimg04.c-ctrip.com/images/0233912000cc2gwjqA94F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000cc2j8xc6A35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000cc2greoF3F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 8, 2.19722457733622, 7, '["周边配套", "餐饮设施", "整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '位置非常好，吃饭非常方便，酒店打卡的人很多，瀑布餐厅名不虚传，早餐服务很好，花园', '位置非常好，吃饭非常方便，酒店打卡的人很多，瀑布餐厅名不虚传，早餐服务很好，花园可以带小朋友喂鱼，博物馆也可以看一看。', '2023-10-05', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ea9e3c98b0941765c3d', '房间比较老，卫生间有补过?迹，但房间宽阔，价格实惠。', '["https://dimg04.c-ctrip.com/images/0236b12000coud33rE1A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000couau9qCBB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000couaz1gC65B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-06', '红棉大床套房', '套房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 6, 1.9459101490553128, 6, '["房间设施", "价格合理性"]'::jsonb, '房间设施', '价格合理性', NULL, '未知酒店', '未知地点', '匿名', '房间比较老，卫生间有补过?迹，但房间宽阔，价格实惠。', '房间比较老，卫生间有补过?迹，但房间宽阔，价格实惠。', '2023-12-06', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ea9e3c98b0941765c3e', '其他都不想说，除了床垫床垫床垫；第一次住酒店掀开床垫看，再看看官网价格！嗯 告辞！！早餐的环境还可以，菜品也就那样！', '["https://dimg04.c-ctrip.com/images/0233n12000cda81ve17C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000cda2gb088ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-11', '花园双床房', '双床房', '其他', 58, 4.07753744390572, 0, 0.0, 7, 2.079441541679836, 5, '["房间设施", "性价比", "餐饮设施"]'::jsonb, '房间设施', '性价比', '餐饮设施', '未知酒店', '未知地点', '匿名', '其他都不想说，除了床垫床垫床垫；第一次住酒店掀开床垫看，再看看官网价格！嗯 告辞', '其他都不想说，除了床垫床垫床垫；第一次住酒店掀开床垫看，再看看官网价格！嗯 告辞！！早餐的环境还可以，菜品也就那样！', '2023-10-11', 5, '房间设施');
