INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ea9e3c98b0941765c41', '作为中国唯三的白金五星级酒店，花园酒店一直是广州的一个招牌，旅游出行很方便，环境非常不错，瀑布餐厅非常有名，服务也很到位，很欢喜，下次应该还会带娃来的，只可惜这次去的时候泳池在装修，没有游起来，算是开心旅程中的一点点遗憾吧', '["https://dimg04.c-ctrip.com/images/0232112000bu4c7he35D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-05', '红棉双床套房', '套房', '家庭亲子', 111, 4.718498871295094, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "交通便利性", "公共设施"]'::jsonb, '整体满意度', '交通便利性', '公共设施', '未知酒店', '未知地点', '匿名', '作为中国唯三的白金五星级酒店，花园酒店一直是广州的一个招牌，旅游出行很方便，环境', '作为中国唯三的白金五星级酒店，花园酒店一直是广州的一个招牌，旅游出行很方便，环境非常不错，瀑布餐厅非常有名，服务也很到位，很欢喜，下次应该还会带娃来的，只可惜这次去的时候泳池在装修，没有游起来，算是开心旅程中的一点点遗憾吧', '2023-08-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c42', '这次临时来广州办事，预定了放在收藏夹里很久的花园酒店，因为带了宝宝，想着要环境好一些，地方大一些，果然是不错的，宝宝每天和奶奶逛酒店很开心，我就和老公在外面办事情，一共续住了三次，总共住了八天，都不想换酒店，就一直在这续住，下次来还住这里????', '["https://dimg04.c-ctrip.com/images/0233g12000btv0r1g45B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000btv0kr700F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000btv0oe94B08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000btv0s7h8766_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000btv0sv0E919_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000btv0n1sB9A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000btv0ufr0067_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000btv0yf8C7B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000btv0rvuC484_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-04', '花园双床房', '双床房', '家庭亲子', 123, 4.820281565605037, 1, 0.6931471805599453, 1, 0.6931471805599453, 7, '["整体满意度", "房间设施", "公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '这次临时来广州办事，预定了放在收藏夹里很久的花园酒店，因为带了宝宝，想着要环境好', '这次临时来广州办事，预定了放在收藏夹里很久的花园酒店，因为带了宝宝，想着要环境好一些，地方大一些，果然是不错的，宝宝每天和奶奶逛酒店很开心，我就和老公在外面办事情，一共续住了三次，总共住了八天，都不想换酒店，就一直在这续住，下次来还住这里????', '2023-08-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c43', '这次来广州，特地选择了代表着改革开放以后，“传说中的”第一批五星级酒店的几家酒店，走入酒店，那种开篇之作，厚重不浮夸的质感让人满意，环抱着的花园有典型岭南园林的痕迹，不能言表的高级感让酒店蕴含着神秘的气息。', '["https://dimg04.c-ctrip.com/images/0233w12000ca2czkl8C95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000ca2d1762026_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000ca2cxkz1B03_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000ca2cxcuDE20_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000ca2cw939F61_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000ca2csj2B0ED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000ca2cys880F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000ca2ctblEF5A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000ca2cy0n0CC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-29', '红棉大床套房', '套房', '家庭亲子', 103, 4.6443908991413725, 0, 0.0, 10, 2.3978952727983707, 9, '["整体满意度", "景观/朝向"]'::jsonb, '整体满意度', '景观/朝向', NULL, '未知酒店', '未知地点', '匿名', '这次来广州，特地选择了代表着改革开放以后，“传说中的”第一批五星级酒店的几家酒店', '这次来广州，特地选择了代表着改革开放以后，“传说中的”第一批五星级酒店的几家酒店，走入酒店，那种开篇之作，厚重不浮夸的质感让人满意，环抱着的花园有典型岭南园林的痕迹，不能言表的高级感让酒店蕴含着神秘的气息。', '2023-09-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c44', '酒店虽和我同龄，但维护保养的非常好，大气精致共存，特色餐厅也极具水准，难以想象，在1985年开业时这是怎样超前的存在！', '["https://dimg04.c-ctrip.com/images/0235l12000cbkcs7d2A67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000cbkgb1iEB61_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000cbkggwn5239_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000cbkjbht4C73_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000cbkjq1g1537_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-03', '红棉大床套房', '套房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店虽和我同龄，但维护保养的非常好，大气精致共存，特色餐厅也极具水准，难以想象，', '酒店虽和我同龄，但维护保养的非常好，大气精致共存，特色餐厅也极具水准，难以想象，在1985年开业时这是怎样超前的存在！', '2023-10-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c45', '酒店很漂亮，不负白金酒店的称号，酒店在地铁5号线淘金站A口的边上，附近商城多，吃饭购物都很方便，酒店的服务也很好 ，入住的房间因网络有问题，而我们晚上有线上课，在和客房服务反应后，客户服务热心的帮我们升级了房间。早餐瀑布餐厅的服务员也都很热情。', '["https://dimg04.c-ctrip.com/images/0231b12000btrdw195238_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000btreuky00C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000btrhfoh4BA0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000btrf63t02B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-04', '花园双床房', '双床房', '家庭亲子', 122, 4.812184355372417, 1, 0.6931471805599453, 10, 2.3978952727983707, 9, '["交通便利性", "周边配套", "客房服务"]'::jsonb, '交通便利性', '周边配套', '客房服务', '未知酒店', '未知地点', '匿名', '酒店很漂亮，不负白金酒店的称号，酒店在地铁5号线淘金站A口的边上，附近商城多，吃', '酒店很漂亮，不负白金酒店的称号，酒店在地铁5号线淘金站A口的边上，附近商城多，吃饭购物都很方便，酒店的服务也很好 ，入住的房间因网络有问题，而我们晚上有线上课，在和客房服务反应后，客户服务热心的帮我们升级了房间。早餐瀑布餐厅的服务员也都很热情。', '2023-08-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c46', '地段优越，环境好，交通便利，服务人员热情，餐厅的环境和食物的味道都很好，周边300米有点都德得和其他美食餐厅，值得入住。', '["https://dimg04.c-ctrip.com/images/0234r12000ccyxn1yAA0B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000ccyx6c64B11_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000ccyrqcxEB29_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-09', '城央绿意大床房', '大床房', '朋友出游', 60, 4.110873864173311, 0, 0.0, 10, 2.3978952727983707, 7, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '地段优越，环境好，交通便利，服务人员热情，餐厅的环境和食物的味道都很好，周边30', '地段优越，环境好，交通便利，服务人员热情，餐厅的环境和食物的味道都很好，周边300米有点都德得和其他美食餐厅，值得入住。', '2023-10-09', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c47', '饭店历史悠久，风景极美，早餐非常丰盛！', '["https://dimg04.c-ctrip.com/images/0232v12000cr0ffg2BCA8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000cr0f01m70A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-17', '花园大床房', '大床房', '商务出差', 19, 2.995732273553991, 0, 0.0, 10, 2.3978952727983707, 5, '["餐饮设施", "景观/朝向", "整体满意度"]'::jsonb, '餐饮设施', '景观/朝向', '整体满意度', '未知酒店', '未知地点', '匿名', '饭店历史悠久，风景极美，早餐非常丰盛！', '饭店历史悠久，风景极美，早餐非常丰盛！', '2023-12-17', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c48', '主体建筑Y型，寓意“年轻和希望”的白金五星广州花园酒店，难得数十年来仍保持经典非凡，果然实至名归。
本次体验的是含行政礼遇的客房，除没有浴缸外，其他设施、卫生、环境、服务以及满溢岭南气息的后花园、故事感满满的大堂、餐厅和博物馆，都让人心悦诚服。
特别感谢锦鲤酒吧行政酒廊的服务员Carrie、Winnie、Mia、乐队和全体成员，还有送来精美点心的客房服务员??', '["https://dimg04.c-ctrip.com/images/0232v12000cd5gfew46B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000cd5mngp66A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000cd5i482C811_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000cd5hcstC69D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-10', '花园双床房', '双床房', '其他', 181, 5.204006687076795, 0, 0.0, 35, 3.58351893845611, 9, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '主体建筑Y型，寓意“年轻和希望”的白金五星广州花园酒店，难得数十年来仍保持经典非', '主体建筑Y型，寓意“年轻和希望”的白金五星广州花园酒店，难得数十年来仍保持经典非凡，果然实至名归。
本次体验的是含行政礼遇的客房，除没有浴缸外，其他设施、卫生、环境、服务以及满溢岭南气息的后花园、故事感满满的大堂、餐厅和博物馆，都让人心悦诚服。
特别感谢锦鲤酒吧行政酒廊的服务员Carrie、Winnie、Mia、乐队和全体成员，还有送来精美点心的客房服务员??', '2023-10-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c49', '第一次来广州，选择了久负盛名的花园酒店，，大厅和瀑布餐厅都很惊艳。特别要赞一下前台的Billy小哥哥，特别细心耐心，专业素质好，看到我一个人带孩子充分了解我的需求并且帮我规划了最优的方案。从长隆一身疲惫到了这里因为Billy感受到了宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0236412000cz75nvzA5BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000cz6sxv62E2B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-19', '花园双床房', '双床房', '家庭亲子', 124, 4.8283137373023015, 2, 1.0986122886681098, 14, 2.70805020110221, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '第一次来广州，选择了久负盛名的花园酒店，，大厅和瀑布餐厅都很惊艳。特别要赞一下前', '第一次来广州，选择了久负盛名的花园酒店，，大厅和瀑布餐厅都很惊艳。特别要赞一下前台的Billy小哥哥，特别细心耐心，专业素质好，看到我一个人带孩子充分了解我的需求并且帮我规划了最优的方案。从长隆一身疲惫到了这里因为Billy感受到了宾至如归的感觉。', '2024-01-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c4a', '非常不好的入住体验，一千多的价格，设施陈旧，只有个好看的酒店大堂，非常不值得推荐，建议大家多加几百推荐去珠江新城那几家，卫生状况极其差，只有浴缸，洗澡需要站立上去，感觉很不干净，而且带着老人家入住，爬不上去，大夏天只能将就一晚上，将就着住了一夜所谓的五星酒店，关了浴室门就没办法关卫生间的门，窗帘只有一层纱，而且很脏发黄，早上天一亮你就知道了，有一股发霉的老酒店味道，下次降到五百房价，都不推荐去住，差评内容还有很多很多', '["https://dimg04.c-ctrip.com/images/0233912000bsvr2n6C35B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000bsvtydl4A4B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-08-01', '花园双床房', '双床房', '商务出差', 210, 5.351858133476067, 5, 1.791759469228055, 1, 0.6931471805599453, 9, '["房间设施", "卫生状况", "性价比"]'::jsonb, '房间设施', '卫生状况', '性价比', '未知酒店', '未知地点', '匿名', '非常不好的入住体验，一千多的价格，设施陈旧，只有个好看的酒店大堂，非常不值得推荐', '非常不好的入住体验，一千多的价格，设施陈旧，只有个好看的酒店大堂，非常不值得推荐，建议大家多加几百推荐去珠江新城那几家，卫生状况极其差，只有浴缸，洗澡需要站立上去，感觉很不干净，而且带着老人家入住，爬不上去，大夏天只能将就一晚上，将就着住了一夜所谓的五星酒店，关了浴室门就没办法关卫生间的门，窗帘只有一层纱，而且很脏发黄，早上天一亮你就知道了，有一股发霉的老酒店味道，下次降到五百房价，都不推荐去住，差评内容还有很多很多', '2023-08-01', 1, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027eb6e3c98b0941765c4b', '酒店38年了大堂还是金碧辉煌，38年前作为广州的五星级酒店还是硬件保养的不错，重新装修过的房间干净整洁，早餐比较中规中矩，总体还是非常满意。', '["https://dimg04.c-ctrip.com/images/0232d12000c8cv20wF5D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000c8cry0t14AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000c8cpn3bD7CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000c8cy0d6D06C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000c8cxfknBC30_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000c8cz5pm9D88_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000c8csg7u6FD7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000c8cpw0o36C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000c8crs3u8227_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-24', '红棉大床套房', '套房', '其他', 70, 4.262679877041316, 0, 0.0, 42, 3.7612001156935615, 7, '["房间设施", "整体满意度", "卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店38年了大堂还是金碧辉煌，38年前作为广州的五星级酒店还是硬件保养的不错，重', '酒店38年了大堂还是金碧辉煌，38年前作为广州的五星级酒店还是硬件保养的不错，重新装修过的房间干净整洁，早餐比较中规中矩，总体还是非常满意。', '2023-09-24', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c4c', '不愧是广花啊，服务环境都很满意，最关键的早餐是在瀑布餐厅吃，服务员小姐姐还很热情的帮忙拍照。吃早饭就可以去后面花园散步，瀑布下面有很多大锦鲤。', '["https://dimg04.c-ctrip.com/images/0232s12000c494aofB4EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-12', '红棉双床套房', '套房', '家庭亲子', 71, 4.276666119016055, 0, 0.0, 2, 1.0986122886681098, 8, '["餐饮设施", "整体满意度", "公共设施"]'::jsonb, '餐饮设施', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '不愧是广花啊，服务环境都很满意，最关键的早餐是在瀑布餐厅吃，服务员小姐姐还很热情', '不愧是广花啊，服务环境都很满意，最关键的早餐是在瀑布餐厅吃，服务员小姐姐还很热情的帮忙拍照。吃早饭就可以去后面花园散步，瀑布下面有很多大锦鲤。', '2023-09-12', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c4d', '本次入住让我非常舒服感动，特别是Billy Deng 很热情,服务态度很好,细致周到,让我印象非常深刻!', '["https://dimg04.c-ctrip.com/images/0233612000cdvw1g32C75_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000cdw06pm7DB9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000cdw005u8C91_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-13', '花园行政大床套房', '套房', '商务出差', 52, 3.970291913552122, 0, 0.0, 172, 5.153291594497779, 6, '["前台服务"]'::jsonb, '前台服务', NULL, NULL, '未知酒店', '未知地点', '匿名', '本次入住让我非常舒服感动，特别是Billy Deng 很热情,服务态度很好,细致', '本次入住让我非常舒服感动，特别是Billy Deng 很热情,服务态度很好,细致周到,让我印象非常深刻!', '2023-10-13', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c4e', '酒店的地理位置超级无敌好，在淘金地铁站上来就看到了，我们早上到达酒店，因为未到两点暂时不能入住，就把行李寄存在大堂然后玩去了。晚上再回去办理入住，等候过程也很快。而且酒店很贴心，提早帮我们开了空调。想想在外面40多度的热浪中回到凉飕飕的房间，多舒服啊！重点是不用等房间降温！必须表扬！订酒店之前看评论，很纠结那个市政工程会不会噪音很大？我是神经质的睡眠，有点担心。酒店也很贴心，写了提醒字条在桌面上。幸好整个晚上到白天九点多我们出发时都很安静。 瀑布餐厅的早餐品种很多，工作人员的态度也非常好，环境一流，拍照打卡非常棒，不过要稍稍排一下队。要延迟退房跟客服说了一下就可以免费延迟到下午两点。说了好的方面，再提一下意见，为什么厕所跟浴房是同一扇推拉门呢？两个人同时使用的话，关哪边好？这个设计，不懂欣赏。', '["https://dimg04.c-ctrip.com/images/0232y12000bocj0b6A168_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000bocjrf0D013_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000boch9k6A0B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000bocbgea3B79_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000bocilvqCAAE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000bocdo1iCF5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000bocemorA905_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000bocmc963FA2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000boce7nl32BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-17', '花园双床房', '双床房', '家庭亲子', 351, 5.863631175598097, 0, 0.0, 3, 1.3862943611198906, 9, '["交通便利性", "前台服务", "安静程度"]'::jsonb, '交通便利性', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '酒店的地理位置超级无敌好，在淘金地铁站上来就看到了，我们早上到达酒店，因为未到两', '酒店的地理位置超级无敌好，在淘金地铁站上来就看到了，我们早上到达酒店，因为未到两点暂时不能入住，就把行李寄存在大堂然后玩去了。晚上再回去办理入住，等候过程也很快。而且酒店很贴心，提早帮我们开了空调。想想在外面40多度的热浪中回到凉飕飕的房间，多舒服啊！重点是不用等房间降温！必须表扬！订酒店之前看评论，很纠结那个市政工程会不会噪音很大？我是神经质的睡眠，有点担心。酒店也很贴心，写了提醒字条在桌面上。幸好整个晚上到白天九点多我们出发时都很安静。 瀑布餐厅的早餐品种很多，工作人员的态度也非常好，环境一流，拍照打卡非常棒，不过要稍稍排一下队。要延迟退房跟客服说了一下就可以免费延迟到下午两点。说了好的方面，再提一下意见，为什么厕所跟浴房是同一扇推拉门呢？两个人同时使用的话，关哪边好？这个设计，不懂欣赏。', '2023-07-17', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c4f', '酒店有着优秀服务的沉淀！地理位置优越，交通便利！花园酒店的精致花园使其名副其实！酒店大堂的设计依旧经典，极富艺术气息和美好寓意！房间到餐厅都非常用心，最爱在早餐看着瀑布，开启美好的广州之旅！羊羔公仔也是孩子爱不释手的布娃娃！', '["https://dimg04.c-ctrip.com/images/0232m12000c0dp47jE2D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000c0dvyy688BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000c0dpamc53E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000c0dwm8v7F09_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000c0ds68y4B53_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-26', '花园双床房', '双床房', '家庭亲子', 112, 4.727387818712341, 0, 0.0, 23, 3.1780538303479458, 8, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店有着优秀服务的沉淀！地理位置优越，交通便利！花园酒店的精致花园使其名副其实！', '酒店有着优秀服务的沉淀！地理位置优越，交通便利！花园酒店的精致花园使其名副其实！酒店大堂的设计依旧经典，极富艺术气息和美好寓意！房间到餐厅都非常用心，最爱在早餐看着瀑布，开启美好的广州之旅！羊羔公仔也是孩子爱不释手的布娃娃！', '2023-08-26', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c50', '外面看真的不错，大厅也很气派，看得出很有文化底蕴。迎宾以及服务员都很nice。就是房间有点小，酒店餐厅环境不错，但是早餐种类还是少了点。行程匆忙，也没来得及去酒店博物馆参观。去的时候泳池正在设备维护，没有去游泳很是遗憾。退房后有东西落酒店了，打电话过来询问，还帮忙快递，真的非常感谢，必须好评。', '["https://dimg04.c-ctrip.com/images/0234812000by7luqg6A1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000by7f2c5A460_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000by7e6rq5FE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-19', '花园双床房', '双床房', '家庭亲子', 147, 4.997212273764115, 0, 0.0, 5, 1.791759469228055, 8, '["客房服务", "餐饮设施", "公共设施"]'::jsonb, '客房服务', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '外面看真的不错，大厅也很气派，看得出很有文化底蕴。迎宾以及服务员都很nice。就', '外面看真的不错，大厅也很气派，看得出很有文化底蕴。迎宾以及服务员都很nice。就是房间有点小，酒店餐厅环境不错，但是早餐种类还是少了点。行程匆忙，也没来得及去酒店博物馆参观。去的时候泳池正在设备维护，没有去游泳很是遗憾。退房后有东西落酒店了，打电话过来询问，还帮忙快递，真的非常感谢，必须好评。', '2023-08-19', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c51', '服务超温暖，宾至如归，健身房环境一流，游泳池超好，早餐丰富多彩，非常可口，中式和西式早餐并存，还有地域特色', '["https://dimg04.c-ctrip.com/images/0237112000cckawhe23BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000cckel8y93F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000cck9wry0F37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 1, 0.6931471805599453, 7, '["公共设施", "餐饮设施", "整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务超温暖，宾至如归，健身房环境一流，游泳池超好，早餐丰富多彩，非常可口，中式和', '服务超温暖，宾至如归，健身房环境一流，游泳池超好，早餐丰富多彩，非常可口，中式和西式早餐并存，还有地域特色', '2023-10-07', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c52', '第二次选择花园酒店，工作人员服务态度好，酒店还送我们早餐卷，在楼顶用餐，把整个城市景色收入眼帘，太棒了??', '["https://dimg04.c-ctrip.com/images/0202j12000cd1gtgh6F18_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0235s12000cd1g658F538_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000cd1g2mvDEBA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000cd1ef7p4C2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-09', '花园双床房', '双床房', '情侣出游', 53, 3.9889840465642745, 0, 0.0, 5, 1.791759469228055, 7, '["前台服务", "餐饮设施", "景观/朝向"]'::jsonb, '前台服务', '餐饮设施', '景观/朝向', '未知酒店', '未知地点', '匿名', '第二次选择花园酒店，工作人员服务态度好，酒店还送我们早餐卷，在楼顶用餐，把整个城', '第二次选择花园酒店，工作人员服务态度好，酒店还送我们早餐卷，在楼顶用餐，把整个城市景色收入眼帘，太棒了??', '2023-10-09', 5, '前台服务');
