INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ec0e3c98b0941765c54', '非常惊喜的一次体验，中国唯三的白金五星级酒店。不同于其他国际品牌的统一性，这家酒店保留了历史的底蕴 民族品牌的特色和与时俱进的设施。前台Betty和迎宾非常细心，首次入住帮忙升级了房型。四点惊喜 ①花园绿化非常好 一看就是用心打理的成果，很出片 锦鲤非常漂亮②锦鲤酒吧 乐队水准极高 ，感染力强 本来是等外卖找地方坐坐，但代入感太强一直听到 外卖凉了③酒店博物馆推荐，对中国酒店业发展史有了了解 更被花园酒店的企业文化感染 ④酒店很国际化 推荐荔湾园 598双人套餐 极其丰富', '["https://dimg04.c-ctrip.com/images/0231y12000dlsge1dEDF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000dlsfxir7EED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000dlsfm94EEEC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-06', '花园大床房', '大床房', '商务出差', 238, 5.476463551931511, 0, 0.0, 21, 3.091042453358316, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '非常惊喜的一次体验，中国唯三的白金五星级酒店。不同于其他国际品牌的统一性，这家酒', '非常惊喜的一次体验，中国唯三的白金五星级酒店。不同于其他国际品牌的统一性，这家酒店保留了历史的底蕴 民族品牌的特色和与时俱进的设施。前台Betty和迎宾非常细心，首次入住帮忙升级了房型。四点惊喜 ①花园绿化非常好 一看就是用心打理的成果，很出片 锦鲤非常漂亮②锦鲤酒吧 乐队水准极高 ，感染力强 本来是等外卖找地方坐坐，但代入感太强一直听到 外卖凉了③酒店博物馆推荐，对中国酒店业发展史有了了解 更被花园酒店的企业文化感染 ④酒店很国际化 推荐荔湾园 598双人套餐 极其丰富', '2024-04-06', 5, '整体满意度');
