INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ecbe3c98b0941765c58', '广州花园酒店是国内的白金五星级酒店。酒店有自己的博物馆、瀑布花园、26个景点等你来解锁。
房间环境不错，床品很好。
早饭有鲤鱼池和瀑布酒吧2个地方，来这里的外国人很多所以早餐有中、西、日三种，餐食品种繁多。
酒店服务员很多，特别要感谢前台Gillian，得知我们要去白云山想延迟退房，非常热心的帮我们办理了手续。
