INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ecbe3c98b0941765c5d', '出发前纠结了好久，担心酒店会太陈旧，
到了后意识到自己多虑了～
从check in遇到Betty就预示着此次入住体验极佳，Betty见我带着老人和小孩，贴心滴给我们两间房做了升级，粤韵的硬件很不错，自带小厅让活动范围大大增加，舒适度指数大涨，大床房还有?????泡澡，总体来说这次入住是很Nice的体验～下次来广州还会选择花园酒店。
要说欠缺的点，那就是近期泳池在升级改造，不在开放期，小朋友有点失望。', '["https://dimg04.c-ctrip.com/images/0235w12000bqyaxaa7830_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000bqy74e2AAD3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000bqyl3vzCDB7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000bqy91g519AD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000bqyjdwa05A9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000bqylbcpA5C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-26', '花园双床房', '双床房', '家庭亲子', 201, 5.308267697401205, 1, 0.6931471805599453, 2, 1.0986122886681098, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '出发前纠结了好久，担心酒店会太陈旧，', '出发前纠结了好久，担心酒店会太陈旧，
到了后意识到自己多虑了～
从check in遇到Betty就预示着此次入住体验极佳，Betty见我带着老人和小孩，贴心滴给我们两间房做了升级，粤韵的硬件很不错，自带小厅让活动范围大大增加，舒适度指数大涨，大床房还有?????泡澡，总体来说这次入住是很Nice的体验～下次来广州还会选择花园酒店。
要说欠缺的点，那就是近期泳池在升级改造，不在开放期，小朋友有点失望。', '2023-07-26', 5, '前台服务');
