INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c61', '酒店环境好，但是房间比较小，服务还可以，就是我看到携程有帮我匹配成岭客汇金卡会员，可是没有看到欢迎水果、行政酒廊使用等等，快速退房就更是没有了，退房碰到系统问题，我抱着小孩在那里排队等，也没看到服务员来告诉我，还是我主动问的。PS：早餐有赠送给我，就是菜品不够丰富，说是一楼二楼有中西餐区别，其实差不多！', '["https://dimg04.c-ctrip.com/images/0233312000bqn713c1C0A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000bqn3huz2F8C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000bqn16cq5987_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000bqnaz505CDD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000bqmy6zq2EB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000bqn82x4BC61_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000bqnbnb12E55_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-07-25', '花园双床房', '双床房', '家庭亲子', 152, 5.030437921392435, 1, 0.6931471805599453, 3, 1.3862943611198906, 7, '["前台服务", "退房/入住效率", "餐饮设施"]'::jsonb, '前台服务', '退房/入住效率', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店环境好，但是房间比较小，服务还可以，就是我看到携程有帮我匹配成岭客汇金卡会员', '酒店环境好，但是房间比较小，服务还可以，就是我看到携程有帮我匹配成岭客汇金卡会员，可是没有看到欢迎水果、行政酒廊使用等等，快速退房就更是没有了，退房碰到系统问题，我抱着小孩在那里排队等，也没看到服务员来告诉我，还是我主动问的。PS：早餐有赠送给我，就是菜品不够丰富，说是一楼二楼有中西餐区别，其实差不多！', '2023-07-25', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c62', '必须满分！作为老牌酒店，服务真的好，从下车至前台，各工作人员都让人感觉宾至如归。房间配套设施完善，维护得很好。值得推荐入住！', '["https://dimg04.c-ctrip.com/images/0230x12000c7h7fl9E3EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000c7h8astF760_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000c7ha6eb017B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-22', '红棉大床套房', '套房', '朋友出游', 62, 4.143134726391533, 0, 0.0, 16, 2.833213344056216, 7, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '必须满分！作为老牌酒店，服务真的好，从下车至前台，各工作人员都让人感觉宾至如归。', '必须满分！作为老牌酒店，服务真的好，从下车至前台，各工作人员都让人感觉宾至如归。房间配套设施完善，维护得很好。值得推荐入住！', '2023-09-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c63', '环境非常好，不愧是花园酒店，后花园一定要参观一下，有瀑布和小桥流水还有各种花草。红棉大床房面积很大，有个厅，加了床，三个人住很舒适。唯一不足是服务，因为到达时间已是半夜，早上提前致电前台说了务必把床提前加好，结果半夜一点到了依然没加，坐等加完才能休息，此刻的心情谁懂。', '["https://dimg04.c-ctrip.com/images/0236n12000br1s7wkFAA8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000br1kn2cC852_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000br1n6bdB320_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000br1p57g7F46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000br1l2xy485F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000br1l7443DBE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000br1owma54B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-07-26', '红棉大床套房', '套房', '家庭亲子', 134, 4.90527477843843, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '环境非常好，不愧是花园酒店，后花园一定要参观一下，有瀑布和小桥流水还有各种花草。', '环境非常好，不愧是花园酒店，后花园一定要参观一下，有瀑布和小桥流水还有各种花草。红棉大床房面积很大，有个厅，加了床，三个人住很舒适。唯一不足是服务，因为到达时间已是半夜，早上提前致电前台说了务必把床提前加好，结果半夜一点到了依然没加，坐等加完才能休息，此刻的心情谁懂。', '2023-07-26', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c64', '不愧是白金五星级酒店，入住感觉非常满意，第一要表扬的是前台的吴经理，没有见到人，提前一天就直接打电话跟她商量，因为带了孩子能不能房间给调整成床铺比较大的，结果她真的帮忙给协调升级成双床套房；第二个要表扬的是前台的viria，入住效率快，办事认真体贴，给孩子申请了一个儿童餐，虽然孩子不吃什么东西，但是享受到了酒店的温暖！希望酒店能继续保持这种人性化的关怀！第三个要表扬的就是酒店的客房服务，需要补充饮用水或者是房间用品时响应速度非常快，客房的清洁阿姨（是东北过来的阿姨）态度也非常好，做事情速度快，整理得很清楚！你是个就要表扬早餐瀑布餐厅的服务员，真的真的很棒，态度温和有礼，服务积极！
     特别特别要提一点的是，花园酒店的位置太好了，一出门右转就是淘金口地铁站，去哪儿都非常方便，因为带的很多行李，所以非常庆幸选择的花园酒店
      整体这次入住的感觉就是酒店服务人员都是高素质的，路上碰到都会打招呼，餐饮服务也都很认真细致！', '["https://dimg04.c-ctrip.com/images/0233o12000c774dtuEE59_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000c774f0x6E14_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000c774g6m667E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000c774i3q0D80_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000c774khi24B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000c774knp1ABB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-21', '红棉大床套房', '套房', '家庭亲子', 419, 6.040254711277414, 0, 0.0, 9, 2.302585092994046, 9, '["前台服务", "客房服务", "交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性', '未知酒店', '未知地点', '匿名', '不愧是白金五星级酒店，入住感觉非常满意，第一要表扬的是前台的吴经理，没有见到人，', '不愧是白金五星级酒店，入住感觉非常满意，第一要表扬的是前台的吴经理，没有见到人，提前一天就直接打电话跟她商量，因为带了孩子能不能房间给调整成床铺比较大的，结果她真的帮忙给协调升级成双床套房；第二个要表扬的是前台的viria，入住效率快，办事认真体贴，给孩子申请了一个儿童餐，虽然孩子不吃什么东西，但是享受到了酒店的温暖！希望酒店能继续保持这种人性化的关怀！第三个要表扬的就是酒店的客房服务，需要补充饮用水或者是房间用品时响应速度非常快，客房的清洁阿姨（是东北过来的阿姨）态度也非常好，做事情速度快，整理得很清楚！你是个就要表扬早餐瀑布餐厅的服务员，真的真的很棒，态度温和有礼，服务积极！
     特别特别要提一点的是，花园酒店的位置太好了，一出门右转就是淘金口地铁站，去哪儿都非常方便，因为带的很多行李，所以非常庆幸选择的花园酒店
      整体这次入住的感觉就是酒店服务人员都是高素质的，路上碰到都会打招呼，餐饮服务也都很认真细致！', '2023-09-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c65', '早餐果子里有虫子.房间一开始很吵（因为楼下装修）然后给我从很吵的房间换到了一个空调一直出臭气的房间.', '["https://dimg04.c-ctrip.com/images/0204712000cdfwxp26C28_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0236712000cdfrbow5199_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-10-11', '花园双床房', '双床房', '朋友出游', 50, 3.9318256327243257, 0, 0.0, 1, 0.6931471805599453, 7, '["餐饮设施", "安静程度", "房间设施"]'::jsonb, '餐饮设施', '安静程度', '房间设施', '未知酒店', '未知地点', '匿名', '早餐果子里有虫子.房间一开始很吵（因为楼下装修）然后给我从很吵的房间换到了一个空', '早餐果子里有虫子.房间一开始很吵（因为楼下装修）然后给我从很吵的房间换到了一个空调一直出臭气的房间.', '2023-10-11', 1, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c66', '提前和酒店沟通了是来过生日，前台的joe和ann帮忙升级了粤韵房型，还赠送了单人的行政礼遇，房间是19年装修的，比较新。行政酒廊的Carrie很热情，食物出品也不错。晚上回到房间发现酒店还赠送了生日蛋糕和点心。
美中不足是第二天在桃园馆餐厅使用了500签账额，口味一般，肉筋没剃除，勺子没洗干净，不合米其林的出品。', '["https://dimg04.c-ctrip.com/images/0232f12000c4rsq1eEAF1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000c4rolqx00A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000c4rjkotBF72_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000c4riizgE991_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000c4rykywCF90_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000c4rn8zdB04E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000c4rvspoEE43_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000c4rsmtq131F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000c4roi8sFFB9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-14', '红棉大床套房', '套房', '独自旅行', 157, 5.062595033026967, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '提前和酒店沟通了是来过生日，前台的joe和ann帮忙升级了粤韵房型，还赠送了单人', '提前和酒店沟通了是来过生日，前台的joe和ann帮忙升级了粤韵房型，还赠送了单人的行政礼遇，房间是19年装修的，比较新。行政酒廊的Carrie很热情，食物出品也不错。晚上回到房间发现酒店还赠送了生日蛋糕和点心。
美中不足是第二天在桃园馆餐厅使用了500签账额，口味一般，肉筋没剃除，勺子没洗干净，不合米其林的出品。', '2023-09-14', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c67', '每一个工作人员服务态度都很好，非常满意的一次住宿体验。酒店配备了不少设施，小朋友也能在酒店晚上一会儿。', '["https://dimg04.c-ctrip.com/images/0234c12000cc4k1w3B64B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000cc4jivd5AE6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000cc4jpgv0FBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 6, 1.9459101490553128, 5, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '每一个工作人员服务态度都很好，非常满意的一次住宿体验。酒店配备了不少设施，小朋友', '每一个工作人员服务态度都很好，非常满意的一次住宿体验。酒店配备了不少设施，小朋友也能在酒店晚上一会儿。', '2023-10-05', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c68', '老酒店有品味，值得体验', '["https://dimg04.c-ctrip.com/images/0234a12000d16c1hhD495_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000d16c2nv37A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-25', '红棉大床套房', '套房', '朋友出游', 11, 2.4849066497880004, 0, 0.0, 48, 3.8918202981106265, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '老酒店有品味，值得体验', '老酒店有品味，值得体验', '2024-01-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ed8e3c98b0941765c69', '我们是岭南汇的会员，多次去花园酒店了，一次比一次惊喜，房间升级了，非常舒适，我们代表广州15-19号去??庆打省锦标游泳比赛，在??庆喜来登住了两晚，这酒店不想评价，但没下次，然后去了亚朵住了一晚，亚朵的排污管老有臭气攻进房间这缺点一直都有，所以不是没选择是绝不住这酒店了，漂了5天刚回到家睡了一晚，又说小区停电，刚好又是我女儿12岁生日，我们立刻马上就飞奔去了花园酒店开房了，真的是家里的酒店最好，一间四十年的全中国唯一三间中国自己开的涉外酒店，服务真的细致，见到我们是国际家庭，马上有外国前台来接待，当知道我们是带孩子来过生日，还送了我们一盘非常新鲜的欢迎水果给孩子，自助早餐也非常好，新鲜，中西合璧，非常好吃，而且招待非常好，有服务员带位，不会像喜来登吃个早餐会有个男人跑来说要和你拼桌，在花园酒店你会感受到真正五星级酒店的服务和礼仪，还有真正的尊重及被酒店的欢迎，花园酒店的确是值得去渡假首选的酒店，酒店内的博物馆也得一去，会让你重新认识广州及中国到全世界的酒店发展历史，值得带孩子一起去参观！', '["https://dimg04.c-ctrip.com/images/0230n12000bpopo926242_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000bpopjdn00A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000bpokopyBA50_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000bpoq4sp8E47_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-21', '花园双床房', '双床房', '家庭亲子', 451, 6.113682179832232, 0, 0.0, 12, 2.5649493574615367, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '我们是岭南汇的会员，多次去花园酒店了，一次比一次惊喜，房间升级了，非常舒适，我们', '我们是岭南汇的会员，多次去花园酒店了，一次比一次惊喜，房间升级了，非常舒适，我们代表广州15-19号去??庆打省锦标游泳比赛，在??庆喜来登住了两晚，这酒店不想评价，但没下次，然后去了亚朵住了一晚，亚朵的排污管老有臭气攻进房间这缺点一直都有，所以不是没选择是绝不住这酒店了，漂了5天刚回到家睡了一晚，又说小区停电，刚好又是我女儿12岁生日，我们立刻马上就飞奔去了花园酒店开房了，真的是家里的酒店最好，一间四十年的全中国唯一三间中国自己开的涉外酒店，服务真的细致，见到我们是国际家庭，马上有外国前台来接待，当知道我们是带孩子来过生日，还送了我们一盘非常新鲜的欢迎水果给孩子，自助早餐也非常好，新鲜，中西合璧，非常好吃，而且招待非常好，有服务员带位，不会像喜来登吃个早餐会有个男人跑来说要和你拼桌，在花园酒店你会感受到真正五星级酒店的服务和礼仪，还有真正的尊重及被酒店的欢迎，花园酒店的确是值得去渡假首选的酒店，酒店内的博物馆也得一去，会让你重新认识广州及中国到全世界的酒店发展历史，值得带孩子一起去参观！', '2023-07-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c6a', '酒店非常干净，设施也都很新，前台小姐姐viria和ariel超级nice、有耐心，笑容甜美，服务周到！好评好评！以后会再来的！z
对了，早餐很好吃哦！！', '["https://dimg04.c-ctrip.com/images/0231y12000bze47kc1A59_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000bze5isk4242_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-23', '花园大床房', '大床房', '独自旅行', 76, 4.343805421853684, 0, 0.0, 4, 1.6094379124341005, 8, '["卫生状况", "前台服务", "餐饮设施"]'::jsonb, '卫生状况', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店非常干净，设施也都很新，前台小姐姐viria和ariel超级nice、有耐心', '酒店非常干净，设施也都很新，前台小姐姐viria和ariel超级nice、有耐心，笑容甜美，服务周到！好评好评！以后会再来的！z
对了，早餐很好吃哦！！', '2023-08-23', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c6b', '第一次认真评价：房间小，设施陈旧，体验感差，瀑布花园还不错，孩子喂喂鱼玩儿了一会儿，瀑布餐厅早餐一般，还需要排队，而且服务员业务不熟练，总结一下就是：如果白天出去玩儿，晚上回去只住一下酒店的，那不推荐住这儿，因为房间小，布局也不合理。如果白天不出去，只在酒店休息的话，也不推荐，因为房间里待着又潮又暗。住了两天，非常不舒服，这酒店唯一的优点就是大堂好看，瀑布花园还不错，虚有其表，住的房间是真不行。', '["https://dimg04.c-ctrip.com/images/0232x12000bqhucoa43E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000bqhwmcj3DAE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000bqhtapz333D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-07-24', '花园双床房', '双床房', '家庭亲子', 199, 5.298317366548036, 6, 1.9459101490553128, 4, 1.6094379124341005, 9, '["房间设施", "整体满意度", "卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '第一次认真评价：房间小，设施陈旧，体验感差，瀑布花园还不错，孩子喂喂鱼玩儿了一会', '第一次认真评价：房间小，设施陈旧，体验感差，瀑布花园还不错，孩子喂喂鱼玩儿了一会儿，瀑布餐厅早餐一般，还需要排队，而且服务员业务不熟练，总结一下就是：如果白天出去玩儿，晚上回去只住一下酒店的，那不推荐住这儿，因为房间小，布局也不合理。如果白天不出去，只在酒店休息的话，也不推荐，因为房间里待着又潮又暗。住了两天，非常不舒服，这酒店唯一的优点就是大堂好看，瀑布花园还不错，虚有其表，住的房间是真不行。', '2023-07-24', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c6c', '被种草，特意带孩子来打卡花园酒店，不愧是白金五星酒店的，获奖无数，见证了很多很有意义的历史时刻。不仅有非常硬核的硬件，软性服务也让人如沐春风！细节非常到位，进门就碰到小姐姐演奏，每层楼都有鲜花点缀 造型各异等等 真正让人感到宾至如归！尤其表扬经理Tina小姐姐，温柔美貌 彬彬有礼，遇到问题很快就帮我解决了，非常圆满！祝花园酒店越来越好', '["https://dimg04.c-ctrip.com/images/0232u12000cz19cn8CD6C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000cz18fss767E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000cz19ez7980F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000cz19cna6001_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000cz18fsu5BC3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000cz19ez9E0F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000cz19cncC81B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000cz18fswF8EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000cz19ezbE352_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-19', '花园双床房', '双床房', '家庭亲子', 168, 5.1298987149230735, 0, 0.0, 2, 1.0986122886681098, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '被种草，特意带孩子来打卡花园酒店，不愧是白金五星酒店的，获奖无数，见证了很多很有', '被种草，特意带孩子来打卡花园酒店，不愧是白金五星酒店的，获奖无数，见证了很多很有意义的历史时刻。不仅有非常硬核的硬件，软性服务也让人如沐春风！细节非常到位，进门就碰到小姐姐演奏，每层楼都有鲜花点缀 造型各异等等 真正让人感到宾至如归！尤其表扬经理Tina小姐姐，温柔美貌 彬彬有礼，遇到问题很快就帮我解决了，非常圆满！祝花园酒店越来越好', '2024-01-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c6d', '住了十几天，感觉很舒服。空调干湿度控制的很好，不会像一些酒店太干燥。床褥松软温暖，很适合睡眠。早餐很棒。', '["https://dimg04.c-ctrip.com/images/0236h12000ccptfgr042D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '花园双床房', '双床房', '商务出差', 52, 3.970291913552122, 0, 0.0, 4, 1.6094379124341005, 7, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '住了十几天，感觉很舒服。空调干湿度控制的很好，不会像一些酒店太干燥。床褥松软温暖', '住了十几天，感觉很舒服。空调干湿度控制的很好，不会像一些酒店太干燥。床褥松软温暖，很适合睡眠。早餐很棒。', '2023-10-08', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c6e', '一开始选择看了其他酒店，最后还是选了这家，环境舒适，服务也不错，很不错的一次体验，下次还会介绍朋友！', '["https://dimg04.c-ctrip.com/images/0230412000ccabub86914_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000cca7xrjC43C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000cca9mgs8DB3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000ccafcleBC6C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000ccaczrg1D21_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000ccacew92644_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 2, 1.0986122886681098, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '一开始选择看了其他酒店，最后还是选了这家，环境舒适，服务也不错，很不错的一次体验', '一开始选择看了其他酒店，最后还是选了这家，环境舒适，服务也不错，很不错的一次体验，下次还会介绍朋友！', '2023-10-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c6f', '入住时前台的人员服务很好，风景很好，设施设备也不错，床品挺舒适的，房间服务员也很用心，还准备了甜点和问候的卡片，总体感觉很不错。', '["https://dimg04.c-ctrip.com/images/0232w12000c4edjny068E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232m12000c4ednkuC255_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000c4edqg0F5C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000c4edrro1044_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-13', '花园大床房', '大床房', '商务出差', 64, 4.174387269895637, 0, 0.0, 1, 0.6931471805599453, 7, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '入住时前台的人员服务很好，风景很好，设施设备也不错，床品挺舒适的，房间服务员也很', '入住时前台的人员服务很好，风景很好，设施设备也不错，床品挺舒适的，房间服务员也很用心，还准备了甜点和问候的卡片，总体感觉很不错。', '2023-09-13', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c70', '广州带娃办事，只停留一天的情况下，庆幸订了花园酒店。
这是一所名副其实的酒店，酒店一楼真真正正的有个很大的花园，一步一景，也是中国三家白金五星的唯一民族品牌，从今天上个世纪80年代开始规划，面积庞大、包罗万象，我带娃在酒店里面玩一天都不带重样的。
酒店前台服务很优秀，遇到Billy为我们办理入住，给宝贝提供了精美的小玩具，也帮忙升级房间到比较新的户型，行李也帮忙送到房间，给宝贝加的小床刚刚好可以放在我们的大床旁边，一直说“交给我吧”，很给力！
酒店自带瀑布景观餐厅，可以用早餐，因为我单独带娃吃饭，从很里面的位置又换了一个更方便的位子，服务人员也很配合。（隐藏福利，30楼有一个旋转餐厅也可以用早餐，只有上午开放到12点，入住的大家可以来看看）。
酒店的四楼还有博物馆，带宝贝逛了一圈也不会接的腻，还买了纪念品。（隐藏福利，酒店的户外泳池变有个儿童乐园，一般都是公寓常住客带娃去玩很少有人知道）。', '["https://dimg04.c-ctrip.com/images/0232912000ccr3h4q2D87_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000ccr4ha319F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000ccqzk0c3EB9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000ccr4ha79FE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000ccr39ct0588_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000ccr25744FB1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000ccqwlvpBA38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000ccr4vk394B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000ccqzk0m2A71_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '红棉大床套房', '套房', '家庭亲子', 400, 5.993961427306569, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "公共设施", "餐饮设施"]'::jsonb, '前台服务', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '广州带娃办事，只停留一天的情况下，庆幸订了花园酒店。', '广州带娃办事，只停留一天的情况下，庆幸订了花园酒店。
