INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c71', '酒店地理位置很好，出行方便，大厅工作人员很有礼貌，我带着老人和孩子出行，一下车小哥就帮忙拿行李，帮我寄存。我想去的地方工作人员又耐心告诉我怎么走，虽说房间面积不大，但已经很好了。很满意。', '["https://dimg04.c-ctrip.com/images/0235i12000bryaofuC266_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000bry8o1a6540_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-29', '城央绿意双床房', '双床房', '家庭亲子', 93, 4.543294782270004, 1, 0.6931471805599453, 8, 2.19722457733622, 8, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店地理位置很好，出行方便，大厅工作人员很有礼貌，我带着老人和孩子出行，一下车小', '酒店地理位置很好，出行方便，大厅工作人员很有礼貌，我带着老人和孩子出行，一下车小哥就帮忙拿行李，帮我寄存。我想去的地方工作人员又耐心告诉我怎么走，虽说房间面积不大，但已经很好了。很满意。', '2023-07-29', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c72', '入住花园酒店、前台富丽堂皇、博物馆和后花园都很不错??歺食精美。这次美中不足我们预定好的房间没有了、前台小哥只是降标安排了一间，后来还是前台许诗玮经理又调剂了一间，第二天还升级了房间送了水果和蛋糕??，许经理楼上楼下跑了好几趟送房卡拿行李、耐心解释道谦，给我们很好的补偿，为许经理的热情服务和敬业精神点赞。房间的保洁和歺厅服务也很赞。谢谢花园酒店！', '["https://dimg04.c-ctrip.com/images/0234w12000cspi49254EC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000csp8c8c1D33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000cspu20p717C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-25', '花园双床房', '双床房', '情侣出游', 174, 5.1647859739235145, 0, 0.0, 23, 3.1780538303479458, 9, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '入住花园酒店、前台富丽堂皇、博物馆和后花园都很不错??歺食精美。这次美中不足我们', '入住花园酒店、前台富丽堂皇、博物馆和后花园都很不错??歺食精美。这次美中不足我们预定好的房间没有了、前台小哥只是降标安排了一间，后来还是前台许诗玮经理又调剂了一间，第二天还升级了房间送了水果和蛋糕??，许经理楼上楼下跑了好几趟送房卡拿行李、耐心解释道谦，给我们很好的补偿，为许经理的热情服务和敬业精神点赞。房间的保洁和歺厅服务也很赞。谢谢花园酒店！', '2023-12-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ee3e3c98b0941765c73', '酒店的公共区域无可挑剔，客房内部设施与卫生也做得很好，贴心的前台Vivia还给小朋友赠送了自助早餐。', '["https://dimg04.c-ctrip.com/images/0233d12000cbyqp2107FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000cbyvdkd2AB0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000cbyp44pBC9F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 2, 1.0986122886681098, 7, '["公共设施", "房间设施", "前台服务"]'::jsonb, '公共设施', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '酒店的公共区域无可挑剔，客房内部设施与卫生也做得很好，贴心的前台Vivia还给小', '酒店的公共区域无可挑剔，客房内部设施与卫生也做得很好，贴心的前台Vivia还给小朋友赠送了自助早餐。', '2023-10-05', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c74', '白金五星名不虚传，38年的老牌酒店，19年新装修，比现代化的很多五星有文化内涵，后花园美景，服务一流，美食有几家米其林榜的，特别是入住时前台银小姐热情细致介绍，特意赞一个，订的红棉套房还给免费升级到雅韵套房', '["https://dimg04.c-ctrip.com/images/0233912000c5pw2me8769_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-16', '红棉双床套房', '套房', '其他', 103, 4.6443908991413725, 0, 0.0, 65, 4.189654742026425, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '白金五星名不虚传，38年的老牌酒店，19年新装修，比现代化的很多五星有文化内涵，', '白金五星名不虚传，38年的老牌酒店，19年新装修，比现代化的很多五星有文化内涵，后花园美景，服务一流，美食有几家米其林榜的，特别是入住时前台银小姐热情细致介绍，特意赞一个，订的红棉套房还给免费升级到雅韵套房', '2023-09-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c75', '一家人出行住了几天，非常满意，酒店文化底蕴深厚，服务环境餐饮价格等各方面都是最好的，真的是流连忘返！', '["https://dimg04.c-ctrip.com/images/0230a12000cbj994b964F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000cbj9e8i87F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000cbj9pp4B6DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-03', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 1, 0.6931471805599453, 6, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '一家人出行住了几天，非常满意，酒店文化底蕴深厚，服务环境餐饮价格等各方面都是最好', '一家人出行住了几天，非常满意，酒店文化底蕴深厚，服务环境餐饮价格等各方面都是最好的，真的是流连忘返！', '2023-10-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c76', '入住当天送了一份精美的甜品蛋糕，来不及拍照被两娃给秒吃了。房间很大，酒店的环境不错，大门口就是淘金地铁站，对面就是友谊商场，广州酒家，去景点也都3-5公里内，很方便。', '["https://dimg04.c-ctrip.com/images/0236612000bvsjss66495_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-11', '红棉大床套房', '套房', '家庭亲子', 83, 4.430816798843313, 0, 0.0, 3, 1.3862943611198906, 8, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '入住当天送了一份精美的甜品蛋糕，来不及拍照被两娃给秒吃了。房间很大，酒店的环境不', '入住当天送了一份精美的甜品蛋糕，来不及拍照被两娃给秒吃了。房间很大，酒店的环境不错，大门口就是淘金地铁站，对面就是友谊商场，广州酒家，去景点也都3-5公里内，很方便。', '2023-08-11', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c77', '酒店设计一流，服务跟得上，餐饮一般，虽然有几家都是米其林推荐餐厅，但是味道远不如我们去的路边老字号。', '["https://dimg04.c-ctrip.com/images/0235712000cb1v08d8D1D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000cb1vbcb7A77_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 3, 1.3862943611198906, 7, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店设计一流，服务跟得上，餐饮一般，虽然有几家都是米其林推荐餐厅，但是味道远不如', '酒店设计一流，服务跟得上，餐饮一般，虽然有几家都是米其林推荐餐厅，但是味道远不如我们去的路边老字号。', '2023-10-02', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c78', '酒店位置非常方便，在越秀区离地铁站很近，大堂环境非常有特色，早餐也很好，房间设施稍稍有点久远，不过服务还是不错的，总体来说体验感很好，有机会还会再来。', '["https://dimg04.c-ctrip.com/images/0234w12000c1355d128B5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000c1355d77AAB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000c1355da876F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000c134w5mB8DF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000c1355ddCBB7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000c134w5s8890_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-08-29', '花园大床房', '大床房', '家庭亲子', 75, 4.330733340286331, 0, 0.0, 75, 4.330733340286331, 8, '["交通便利性", "整体满意度", "餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置非常方便，在越秀区离地铁站很近，大堂环境非常有特色，早餐也很好，房间设施', '酒店位置非常方便，在越秀区离地铁站很近，大堂环境非常有特色，早餐也很好，房间设施稍稍有点久远，不过服务还是不错的，总体来说体验感很好，有机会还会再来。', '2023-08-29', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c79', '整个花园酒店如其名，各种各样的花。大厅，餐厅，迎宾的服务人员都很nice。
