INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ef2e3c98b0941765c7d', '本次住宿非常愉快
果然是超白金的五星酒店
很幸运入住时候前台升级成了套间
环境：维护很好，37年的酒店，但是经常翻新，维护得很好
服务：无论是前台人员，电梯遇见的员工，退房的小钰态度都很好
饮食:   行政下午茶，早餐（荔湾亭和瀑布餐厅）都很好，出品精致，味道一流
下次来广州，还是会想住花园酒店', '["https://dimg04.c-ctrip.com/images/0230e12000c1rqyot14F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000c1rrno34946_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000c1rulcs1758_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000c1rq91a44F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000c1rtnip5E5D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000c1rrr535161_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000c1s07qh1AC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000c1rwwpiAF5B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-01', '花园双床房', '双床房', '家庭亲子', 153, 5.0369526024136295, 0, 0.0, 19, 2.995732273553991, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '本次住宿非常愉快', '本次住宿非常愉快
