INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c7f', '房间很小，但是有浴缸，就很挤。。
但是公共设施还行，毕竟是五星酒店。。
押金一直没退，刚刚打电话我问押金一般什么时候退？说是如果没别的费用当天就会退，反之隔天。
我说我没别的费用为什么都离店第三天了，还没退呢？她说前台同事会跟进的，然后不说话，我一脸懵逼。。我就说那现在是等他们再联系我？她才说让我等十分钟就会退回。。
我可以理解为工作人员忘了操作吗？如果我不打电话问是不是永远不退呢？
还有你们客服真的很不专业。不会和客人沟通。', '["https://dimg04.c-ctrip.com/images/0233312000bof8cw2E8E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000bof7rzg11B3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-07-17', '花园大床房', '大床房', '家庭亲子', 216, 5.37989735354046, 3, 1.3862943611198906, 3, 1.3862943611198906, 8, '["前台服务", "退房/入住效率", "房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施', '未知酒店', '未知地点', '匿名', '房间很小，但是有浴缸，就很挤。。', '房间很小，但是有浴缸，就很挤。。
但是公共设施还行，毕竟是五星酒店。。
