INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c82', '白金五星级酒店，环境优美大气，花园瀑布、锦鲤鱼池很美！服务专业到位，宾至如归！酒店美食不错，博物馆里学习了不好知识，是出差、旅行的首选酒店。五星好评??', '["https://dimg04.c-ctrip.com/images/0234t12000bykn4bm35CC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000byksrrw9516_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000bykt5i39727_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000bykulwi7157_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 76, 4.343805421853684, 0, 0.0, 4, 1.6094379124341005, 7, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '白金五星级酒店，环境优美大气，花园瀑布、锦鲤鱼池很美！服务专业到位，宾至如归！酒', '白金五星级酒店，环境优美大气，花园瀑布、锦鲤鱼池很美！服务专业到位，宾至如归！酒店美食不错，博物馆里学习了不好知识，是出差、旅行的首选酒店。五星好评??', '2023-08-20', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c83', '本来对老酒店期望不大，但花园酒店完全给了我一个意外惊喜！虽然因台风外面风大雨大，但呆在酒店一点也不闷：花园酒店博物馆的讲解，让我对酒店这个行业对中国酒店以及花园酒店的起源发展有了大概的了解，很幸运得到礼宾部金钥匙员工Tim陈一个多小时的陪伴及介绍，打卡酒店26个打卡点，对整个花园酒店有了更加深刻的印象。下午收到来自酒店的下午茶甜点和手写问候便签，让人意外又感动！早上在瀑布餐厅早餐，员工无论客人多工作量大，都注意到每个客人的需求，主动提出帮我们照相，虽然花园酒店是一家38年的老酒店，但硬件软件真的无愧于全国仅有三家白金五星酒店称号！我们刚住过香港东方文华酒店文华阁，花园的服务完全可以与之媲美，甚至有过之而无不及！', '["https://dimg04.c-ctrip.com/images/0234h12000c3cv4hg9CDB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000c3cv5xr6E49_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000c3cv9ldC0E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000c3d09ew1F00_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000c3d0aieCEA1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-08', '红棉双床套房', '套房', '家庭亲子', 309, 5.736572297479192, 0, 0.0, 5, 1.791759469228055, 10, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '本来对老酒店期望不大，但花园酒店完全给了我一个意外惊喜！虽然因台风外面风大雨大，', '本来对老酒店期望不大，但花园酒店完全给了我一个意外惊喜！虽然因台风外面风大雨大，但呆在酒店一点也不闷：花园酒店博物馆的讲解，让我对酒店这个行业对中国酒店以及花园酒店的起源发展有了大概的了解，很幸运得到礼宾部金钥匙员工Tim陈一个多小时的陪伴及介绍，打卡酒店26个打卡点，对整个花园酒店有了更加深刻的印象。下午收到来自酒店的下午茶甜点和手写问候便签，让人意外又感动！早上在瀑布餐厅早餐，员工无论客人多工作量大，都注意到每个客人的需求，主动提出帮我们照相，虽然花园酒店是一家38年的老酒店，但硬件软件真的无愧于全国仅有三家白金五星酒店称号！我们刚住过香港东方文华酒店文华阁，花园的服务完全可以与之媲美，甚至有过之而无不及！', '2023-09-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c84', '大堂宽敞气派，却没有供客人等候的休息区；
房间价格不低，但设施简陋，卫生间马桶和淋雨区共用一扇门，非常鸡肋，前所未见；
客房打扫人员不专业，不按时提供免费饮用水，客人要求提供后还声称要收费的。对不起，我可没有说要依云的水。房间打扫完地面依旧很脏，地上还可见头发，黑点和不知明污渍。
前台服务人员不尽责，反馈了客房问题后，没有后续跟踪，等到离店后有电话询问入住体验。如真想改进，应该在入住期间询问才更有意义吧，更何况我是在入住过程中提出了问题的。
无论设施与服务，硬件和软件，都对不起老牌五星级酒店的称号。
服务行业靠的得就是服务与口碑，也许你们不缺客人，但客人也有很多酒店可以去选择！', '["https://dimg04.c-ctrip.com/images/0232212000bofr4cbD6D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000bofv56514E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000bofsqh57116_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-07-17', '花园双床房', '双床房', '家庭亲子', 292, 5.680172609017068, 2, 1.0986122886681098, 3, 1.3862943611198906, 9, '["房间设施", "客房服务", "前台服务"]'::jsonb, '房间设施', '客房服务', '前台服务', '未知酒店', '未知地点', '匿名', '大堂宽敞气派，却没有供客人等候的休息区；', '大堂宽敞气派，却没有供客人等候的休息区；
