INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c85', '老牌五星酒店，重新装修，设施齐全，环境优美，卫生干净整洁，城市中心，出行方便，服务很好。早餐很好、行政酒廊的下午茶、欢乐时光很棒，工作人员Carrie.Yuki.shirleg服务态度热情周到', '["https://dimg04.c-ctrip.com/images/0235s12000bpcpvjhB6A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000bpcjkiy6592_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000bpchi6453A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-20', '花园双床房', '双床房', '家庭亲子', 96, 4.574710978503383, 1, 0.6931471805599453, 17, 2.8903717578961645, 7, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '老牌五星酒店，重新装修，设施齐全，环境优美，卫生干净整洁，城市中心，出行方便，服', '老牌五星酒店，重新装修，设施齐全，环境优美，卫生干净整洁，城市中心，出行方便，服务很好。早餐很好、行政酒廊的下午茶、欢乐时光很棒，工作人员Carrie.Yuki.shirleg服务态度热情周到', '2023-07-20', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c86', '慕名而来，想试试白金五星酒店，进房间有小小惊喜，但用厕所时发现抽风机不工作，早餐选了荔湾亭吃发现不如头一晚住的三星，说实话早餐太差劲了，期望值大打折扣，服务也一般。', '["https://dimg04.c-ctrip.com/images/0236s12000bui4spc2B58_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000buhwqo359D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000buhyq7m2B43_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-08-07', '花园双床房', '双床房', '家庭亲子', 82, 4.418840607796598, 1, 0.6931471805599453, 5, 1.791759469228055, 7, '["餐饮设施", "房间设施", "整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '慕名而来，想试试白金五星酒店，进房间有小小惊喜，但用厕所时发现抽风机不工作，早餐', '慕名而来，想试试白金五星酒店，进房间有小小惊喜，但用厕所时发现抽风机不工作，早餐选了荔湾亭吃发现不如头一晚住的三星，说实话早餐太差劲了，期望值大打折扣，服务也一般。', '2023-08-07', 3, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027efee3c98b0941765c87', '1. ?? 广州花园酒店，一处让人心生花开的住宿胜地！服务??????????，环境???令人陶醉，餐饮美味可口???。这里的员工热情周到，让你感受到家的温馨和舒适。强烈推荐给所有寻找完美住宿体验的朋友们！?
2. ?? 广州花园酒店，一场花样满满的入住之旅！从入门到退房，无一不体现着专业与贴心。房间整洁舒适，设施一应俱全??。而且酒店周边景点众多，交通便利??。在这里度过的时光成为了我美好回忆的一部分。??
3. ?? 广州花园酒店，绝对是一处花花世界！入住期间，每一个细节都散发着品质和温馨。从大堂到客房，无处不体现出酒店对细节的追求。而且服务人员态度友好，亲切有礼??。真心感谢酒店为我们提供了一段美好的旅行时光！??
4. ?? 广州花园酒店，是花好月圆的理想住所！酒店独具特色的花园环境让人仿佛置身于童话世界?。设施设备一流，床铺舒适如云??。此外，餐厅的美食更是令人垂涎三尺。期待再次光临这个让人心醉的花园天堂！??
5. ?? 广州花园酒店，真是一座难以忘怀的花海！入住期间，我仿佛成为了花园中的一朵鲜花??。每一次与员工们的交流都给予我温暖和安心感。酒店的设施也超乎想象，简直就是一座繁华之中的绿洲??。我已经迫不及待要再次回到这个温馨的花园！??
特别鸣谢Grollian前台接待，特别温馨特别有笑容??', '["https://dimg04.c-ctrip.com/images/0236z12000c2g32l324DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000c2g2je37F5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000c2g61xz75C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000c2fr7zy05A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000c2g3dyk99B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-04', '红棉双床套房', '套房', '家庭亲子', 568, 6.343880434126331, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '1. ?? 广州花园酒店，一处让人心生花开的住宿胜地！服务??????????，', '1. ?? 广州花园酒店，一处让人心生花开的住宿胜地！服务??????????，环境???令人陶醉，餐饮美味可口???。这里的员工热情周到，让你感受到家的温馨和舒适。强烈推荐给所有寻找完美住宿体验的朋友们！?
2. ?? 广州花园酒店，一场花样满满的入住之旅！从入门到退房，无一不体现着专业与贴心。房间整洁舒适，设施一应俱全??。而且酒店周边景点众多，交通便利??。在这里度过的时光成为了我美好回忆的一部分。??
3. ?? 广州花园酒店，绝对是一处花花世界！入住期间，每一个细节都散发着品质和温馨。从大堂到客房，无处不体现出酒店对细节的追求。而且服务人员态度友好，亲切有礼??。真心感谢酒店为我们提供了一段美好的旅行时光！??
4. ?? 广州花园酒店，是花好月圆的理想住所！酒店独具特色的花园环境让人仿佛置身于童话世界?。设施设备一流，床铺舒适如云??。此外，餐厅的美食更是令人垂涎三尺。期待再次光临这个让人心醉的花园天堂！??
5. ?? 广州花园酒店，真是一座难以忘怀的花海！入住期间，我仿佛成为了花园中的一朵鲜花??。每一次与员工们的交流都给予我温暖和安心感。酒店的设施也超乎想象，简直就是一座繁华之中的绿洲??。我已经迫不及待要再次回到这个温馨的花园！??
特别鸣谢Grollian前台接待，特别温馨特别有笑容??', '2023-09-04', 5, '整体满意度');
