INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c8a', '住花园酒店似乎成了每次到广州的习惯，但这次的住宿体验实在不能跟星级酒店对上号。第一次安排的房间厕所没有冲水，跟前台反映后换了另外一间。晚上洗脸，洗手盆水龙头一开水，水会往外弄到周围都湿，这个也很无语。本来这么小的房间就没地方放浴缸，但是硬把淋浴间弄成一个正方形浴缸，进去洗澡要跨过浴缸边，我164的身高跨过浴缸边都觉得危险，以后到广州应该不会住这里了。', '["https://dimg04.c-ctrip.com/images/0233e12000bv4xh6eAF86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000bv4utzk1710_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000bv55o1m7F41_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000bv4zise617B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000bv53n8u236C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-08-09', '花园大床房', '大床房', '家庭亲子', 176, 5.176149732573829, 1, 0.6931471805599453, 5, 1.791759469228055, 9, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '住花园酒店似乎成了每次到广州的习惯，但这次的住宿体验实在不能跟星级酒店对上号。第', '住花园酒店似乎成了每次到广州的习惯，但这次的住宿体验实在不能跟星级酒店对上号。第一次安排的房间厕所没有冲水，跟前台反映后换了另外一间。晚上洗脸，洗手盆水龙头一开水，水会往外弄到周围都湿，这个也很无语。本来这么小的房间就没地方放浴缸，但是硬把淋浴间弄成一个正方形浴缸，进去洗澡要跨过浴缸边，我164的身高跨过浴缸边都觉得危险，以后到广州应该不会住这里了。', '2023-08-09', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c8b', '老牌五星级酒店，够气派。', '["https://dimg04.c-ctrip.com/images/0231l12000cyoswznCE02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000cyot53p9592_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000cyot6qj29AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000cyoswzv561E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-17', '城央绿意双床房', '双床房', '情侣出游', 12, 2.5649493574615367, 0, 0.0, 37, 3.6375861597263857, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '老牌五星级酒店，够气派。', '老牌五星级酒店，够气派。', '2024-01-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c8c', '这是目前为止住到过的五星酒店落差最大的一次，相比较于大堂的富丽堂皇，酒店房间真的可以用陋室来形容，跟快捷酒店都没得比，工作人员服务很好，这个值得肯定，但是房间又小设备又差，房间没法开窗里面异味很大，闻着很不舒服；浴缸和房间隔断是通透且很mini一块，洗手间和淋浴房真的小的可怜，坐便我老公185身高坐下去膝盖直接顶住玻璃隔墙，根本没法坐；最震撼的是，房间里面的灯带居然都是随意挂下来的，有个床头柜下面的灯带都着地的，隔壁就是洗手台和浴缸，要是水满过来一点，难道不会触电吗？隔壁在修地铁，到晚上11点了还是咚咚咚跟地震一样吵。', '["https://dimg04.c-ctrip.com/images/0233p12000boc49t4C0CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000bocehsm2EAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000bocf0q0B0B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000boc9eiuEB84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000boc9tlrC6D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000bocbrdpD426_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-07-17', '花园大床房', '大床房', '家庭亲子', 262, 5.572154032177765, 5, 1.791759469228055, 15, 2.772588722239781, 9, '["房间设施", "安静程度", "卫生状况"]'::jsonb, '房间设施', '安静程度', '卫生状况', '未知酒店', '未知地点', '匿名', '这是目前为止住到过的五星酒店落差最大的一次，相比较于大堂的富丽堂皇，酒店房间真的', '这是目前为止住到过的五星酒店落差最大的一次，相比较于大堂的富丽堂皇，酒店房间真的可以用陋室来形容，跟快捷酒店都没得比，工作人员服务很好，这个值得肯定，但是房间又小设备又差，房间没法开窗里面异味很大，闻着很不舒服；浴缸和房间隔断是通透且很mini一块，洗手间和淋浴房真的小的可怜，坐便我老公185身高坐下去膝盖直接顶住玻璃隔墙，根本没法坐；最震撼的是，房间里面的灯带居然都是随意挂下来的，有个床头柜下面的灯带都着地的，隔壁就是洗手台和浴缸，要是水满过来一点，难道不会触电吗？隔壁在修地铁，到晚上11点了还是咚咚咚跟地震一样吵。', '2023-07-17', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c8d', '扂间干净卫生，装修布局舒服。环境优美，餐厅菜品丰富，味道不错。服务员热情大方，办理入住高效快捷。令人非常感觉舒服的酒店。下次还会入住。', '["https://dimg04.c-ctrip.com/images/0231312000c274uwhAC64_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000c273utk91AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000c26zbvp8B01_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-03', '花园双床房', '双床房', '家庭亲子', 67, 4.219507705176107, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "卫生状况", "退房/入住效率"]'::jsonb, '整体满意度', '卫生状况', '退房/入住效率', '未知酒店', '未知地点', '匿名', '扂间干净卫生，装修布局舒服。环境优美，餐厅菜品丰富，味道不错。服务员热情大方，办', '扂间干净卫生，装修布局舒服。环境优美，餐厅菜品丰富，味道不错。服务员热情大方，办理入住高效快捷。令人非常感觉舒服的酒店。下次还会入住。', '2023-09-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c8e', '房间很干净，工作人员服务态度很好很热情，特别是小华，很热心负责。春节期间酒店还有很多活动，舞狮很精彩。', '["https://dimg04.c-ctrip.com/images/0230g12000i6s5zwq27FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000i6sqhz5E457_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000i6t9sjmF753_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-31', '城央绿意双床房', '双床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 1, 0.6931471805599453, 7, '["卫生状况", "前台服务", "整体满意度"]'::jsonb, '卫生状况', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很干净，工作人员服务态度很好很热情，特别是小华，很热心负责。春节期间酒店还有', '房间很干净，工作人员服务态度很好很热情，特别是小华，很热心负责。春节期间酒店还有很多活动，舞狮很精彩。', '2025-01-31', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c8f', '超级不好的入住体验 1双床房的设计简直是反人类，淋浴区同浴缸合二为一，出入都需要跨过大概40公分高的浴缸边缘，如果有行动不便的或者小孩简直是硬伤，2卫生间，冲凉房与床之间没有遮挡，完全没有私隐可言3早上8点停水，事先没有通知，游泳后没有水冲凉，打电话问回复逐步恢复中（预计1小时后），可以提供瓶装水或者职员带去公寓楼冲凉4房间内电热水壶漏水，存在严重安全隐患，致电客房服务，回复送一个电热水壶过来，半小时都不见人影送过来5到一楼hsd咖啡阁，吃早餐，没有滑蛋配芦笋，改成煎蛋卷，需要退回10差价，当场问了服务员会有主管过来退单，然后重新收钱，我们至少坐了半小时，然后忘记了离开酒店也没有人主动联系我们，需要事后打电话再次询问才解决问题（不是多少钱的问题，是服务态度问题），这次真的住到一肚火，以后都不会再入住', '["https://dimg04.c-ctrip.com/images/0233s12000bmi6nr20F8E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000bmi3bz0810C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000bmi6csgE2CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-07-10', '花园双床房', '双床房', '家庭亲子', 354, 5.872117789475416, 1, 0.6931471805599453, 9, 2.302585092994046, 9, '["房间设施", "客房服务", "整体满意度"]'::jsonb, '房间设施', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '超级不好的入住体验 1双床房的设计简直是反人类，淋浴区同浴缸合二为一，出入都需要', '超级不好的入住体验 1双床房的设计简直是反人类，淋浴区同浴缸合二为一，出入都需要跨过大概40公分高的浴缸边缘，如果有行动不便的或者小孩简直是硬伤，2卫生间，冲凉房与床之间没有遮挡，完全没有私隐可言3早上8点停水，事先没有通知，游泳后没有水冲凉，打电话问回复逐步恢复中（预计1小时后），可以提供瓶装水或者职员带去公寓楼冲凉4房间内电热水壶漏水，存在严重安全隐患，致电客房服务，回复送一个电热水壶过来，半小时都不见人影送过来5到一楼hsd咖啡阁，吃早餐，没有滑蛋配芦笋，改成煎蛋卷，需要退回10差价，当场问了服务员会有主管过来退单，然后重新收钱，我们至少坐了半小时，然后忘记了离开酒店也没有人主动联系我们，需要事后打电话再次询问才解决问题（不是多少钱的问题，是服务态度问题），这次真的住到一肚火，以后都不会再入住', '2023-07-10', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c90', '花园酒店不愧是老牌五星，地理位置好，出门就是地铁站，服务周到，很多中东航空公司的乘务人员也下榻在这边，酒店内还有两家米其林餐厅，餐饮非常方便。城市酒店瀑布和博物馆非常惊喜！到的比较早，房间未打扫好，被升级了套房。值得一提的是，酒店茶包是TWG。下次来广州一定还会入住！', '["https://dimg04.c-ctrip.com/images/0234y12000bmsvh0eC961_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000bmt07mk17CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-11', '红棉双床套房', '套房', '家庭亲子', 134, 4.90527477843843, 1, 0.6931471805599453, 4, 1.6094379124341005, 9, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店不愧是老牌五星，地理位置好，出门就是地铁站，服务周到，很多中东航空公司的', '花园酒店不愧是老牌五星，地理位置好，出门就是地铁站，服务周到，很多中东航空公司的乘务人员也下榻在这边，酒店内还有两家米其林餐厅，餐饮非常方便。城市酒店瀑布和博物馆非常惊喜！到的比较早，房间未打扫好，被升级了套房。值得一提的是，酒店茶包是TWG。下次来广州一定还会入住！', '2023-07-11', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f09e3c98b0941765c91', '老牌的酒店，名头很大！前台入住登记排队至少要半个小时以上，整个大堂吵吵闹闹的，就像菜市场一样！早餐也要拿号排队，排了半个多小时，还排不到，只好放弃了！出去吃路边摊。估计再排下去就直接吃中午饭了。晕??晕??晕', '["https://dimg04.c-ctrip.com/images/0230l12000bm60urp5CB8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000bm5u84k9CF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000bm5u8o214AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000bm6058u8D42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000bm60c1c6D0D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-07-09', '花园大床房', '大床房', '情侣出游', 104, 4.653960350157523, 1, 0.6931471805599453, 48, 3.8918202981106265, 8, '["前台服务", "退房/入住效率", "安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度', '未知酒店', '未知地点', '匿名', '老牌的酒店，名头很大！前台入住登记排队至少要半个小时以上，整个大堂吵吵闹闹的，就', '老牌的酒店，名头很大！前台入住登记排队至少要半个小时以上，整个大堂吵吵闹闹的，就像菜市场一样！早餐也要拿号排队，排了半个多小时，还排不到，只好放弃了！出去吃路边摊。估计再排下去就直接吃中午饭了。晕??晕??晕', '2023-07-09', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f14e3c98b0941765c92', '这次入住体验很满意，酒店大堂很漂亮，?还有后花园跟博物馆，可以散散步，服务也很满意??，表扬kamille和maney 。', '["https://dimg04.c-ctrip.com/images/0233712000c4kcfadE143_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000c4ki054437D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000c4kfbxy6ACD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-13', '花园大床房', '大床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 1, 0.6931471805599453, 7, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '这次入住体验很满意，酒店大堂很漂亮，?还有后花园跟博物馆，可以散散步，服务也很满', '这次入住体验很满意，酒店大堂很漂亮，?还有后花园跟博物馆，可以散散步，服务也很满意??，表扬kamille和maney 。', '2023-09-13', 5, '整体满意度');
