INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f14e3c98b0941765c95', '客房服务非常好，早餐需要提高哦！', '["https://dimg04.c-ctrip.com/images/0237212000cnpdwyv0D67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000cnpea9j175D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000cnpglnu6C4F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-11-30', '花园双床房', '双床房', '独自旅行', 16, 2.833213344056216, 0, 0.0, 6, 1.9459101490553128, 4, '["客房服务", "餐饮设施"]'::jsonb, '客房服务', '餐饮设施', NULL, '未知酒店', '未知地点', '匿名', '客房服务非常好，早餐需要提高哦！', '客房服务非常好，早餐需要提高哦！', '2023-11-30', 4, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f14e3c98b0941765c96', '设施：一进门，整个震撼，不愧为全国仅有的三个铂金五星级酒店之一
卫生：一尘不染的状态
环境：典型的岭南建筑特色，办理前台是红楼梦壁画
服务：排队办入住，送了荔枝饮、每房送了花园酒店的主题公仔
早餐:太丰盛了，很用心的早餐种草了纯果汁，京东买了，10元一瓶，厉害了
双人自助晚餐-瀑布餐厅:太好吃了，芝士扇贝、海参、生蚝，太多好吃的', '["https://dimg04.c-ctrip.com/images/0230z12000c0x7x670018_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000c0xbhfkB5CE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000c0xcmqjCF32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-29', '花园双床房', '双床房', '家庭亲子', 165, 5.111987788356544, 0, 0.0, 5, 1.791759469228055, 9, '["整体满意度", "餐饮设施", "卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况', '未知酒店', '未知地点', '匿名', '设施：一进门，整个震撼，不愧为全国仅有的三个铂金五星级酒店之一', '设施：一进门，整个震撼，不愧为全国仅有的三个铂金五星级酒店之一
卫生：一尘不染的状态
环境：典型的岭南建筑特色，办理前台是红楼梦壁画
服务：排队办入住，送了荔枝饮、每房送了花园酒店的主题公仔
早餐:太丰盛了，很用心的早餐种草了纯果汁，京东买了，10元一瓶，厉害了
双人自助晚餐-瀑布餐厅:太好吃了，芝士扇贝、海参、生蚝，太多好吃的', '2023-08-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f14e3c98b0941765c97', '花园真的是宝藏酒店  瀑布餐厅的晚餐也很棒  服务很周到 地铁站出门就是  后面的街区也很好逛    非常满意', '["https://dimg04.c-ctrip.com/images/0233d12000c5z6pw862B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000c5z6o8wCDC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000c5zb22q2DFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000c5z9414B215_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000c5z5jjeB78D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-17', '花园大床房', '大床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 30, 3.4339872044851463, 7, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园真的是宝藏酒店  瀑布餐厅的晚餐也很棒  服务很周到 地铁站出门就是  后面', '花园真的是宝藏酒店  瀑布餐厅的晚餐也很棒  服务很周到 地铁站出门就是  后面的街区也很好逛    非常满意', '2023-09-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f14e3c98b0941765c98', '我真的一般不差评，因为红眼航班到酒店办理入住已经快凌晨一点半了，告诉我原本预定的房间没了，升级了传说中的“套房”（跟楼下提供的差评图片是一间），两点到房间水龙头就坏了，修到三点，没修好，孩子三点半才睡觉，早上九点被工地的声音吵醒。被子潮湿，睡的身上痒，淋浴间和马桶旧的程度无法想象，我们全家都没高兴洗澡。同行还有我的两位弟弟，二十几岁的高个男生一样r没双床房了让睡大床房，说免费加床，但据我弟弟反馈加床翻身就掉的那种。非常差的体验，好在携程积极解决，第二天第一时间给我换到了预定的房型。最后酒店给了一份欧舒丹的小样洗护套装表示道歉，感谢但心里面并不接受。本次广州行因为这酒店的第一晚一点体验感都没有。劝大家碰到相同情况一定要拒绝传说中的升级。', '["https://dimg04.c-ctrip.com/images/0230h12000bmj6uhz21DD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-07-11', '红棉双床套房', '套房', '家庭亲子', 321, 5.7745515455444085, 2, 1.0986122886681098, 13, 2.6390573296152584, 9, '["房间设施", "安静程度", "退房/入住效率"]'::jsonb, '房间设施', '安静程度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '我真的一般不差评，因为红眼航班到酒店办理入住已经快凌晨一点半了，告诉我原本预定的', '我真的一般不差评，因为红眼航班到酒店办理入住已经快凌晨一点半了，告诉我原本预定的房间没了，升级了传说中的“套房”（跟楼下提供的差评图片是一间），两点到房间水龙头就坏了，修到三点，没修好，孩子三点半才睡觉，早上九点被工地的声音吵醒。被子潮湿，睡的身上痒，淋浴间和马桶旧的程度无法想象，我们全家都没高兴洗澡。同行还有我的两位弟弟，二十几岁的高个男生一样r没双床房了让睡大床房，说免费加床，但据我弟弟反馈加床翻身就掉的那种。非常差的体验，好在携程积极解决，第二天第一时间给我换到了预定的房型。最后酒店给了一份欧舒丹的小样洗护套装表示道歉，感谢但心里面并不接受。本次广州行因为这酒店的第一晚一点体验感都没有。劝大家碰到相同情况一定要拒绝传说中的升级。', '2023-07-11', 2, '房间设施');
