INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f20e3c98b0941765c9e', '这次送孩子来中大上学，入住久闻大名的花园酒店，服务、餐饮、设施都很满意。唯一一点建议，就是房间的被子有点厚了，半夜热的出汗。', '["https://dimg04.c-ctrip.com/images/0232t12000c1j5jcf9801_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000c1j32buA5C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000c1j28ac963A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000c1ja42w3B78_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-31', '红棉双床套房', '套房', '家庭亲子', 62, 4.143134726391533, 0, 0.0, 2, 1.0986122886681098, 7, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '这次送孩子来中大上学，入住久闻大名的花园酒店，服务、餐饮、设施都很满意。唯一一点', '这次送孩子来中大上学，入住久闻大名的花园酒店，服务、餐饮、设施都很满意。唯一一点建议，就是房间的被子有点厚了，半夜热的出汗。', '2023-08-31', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f20e3c98b0941765c9f', '绝对超预期的感受。
首先一进门，就有白衣男生主动帮忙拿行李送至大堂。
接着粉衣女生开始为我们引导办理入住。
这次为我们办理入住的Tony很超级nice，因为有小朋友，帮我们其中一间大床房免费升级了套房。另外一件房也安排在了隔壁，最后也告知了酒店边上在修地铁，晚上睡觉会有噪音（啊，确实挺噪的?? 感觉是24小时在施工，就是中午和大半夜会消停点，如果是睡觉质量很浅的人要遭罪了）
酒店设施及清洁度都很高，唯一不足的是没有智能马桶（每天帮忙打扫的工作人员都超有礼貌，任何一位都会好好和我们打招呼，也会及时解决一些住宿问题）
4楼的露天泳池是最爱，那么热的天，非常适合带小朋友上午去释放能量（前台帮忙登记的眼镜男生也热心）
酒店的自助早餐相对其他而言，就很soso了，选择不多，纯属可以看看餐厅外的瀑布，不过室外花园真的很漂亮。
酒店位置出行地铁很方便，出门就是五号线淘金站，但是这个线路去一些景点无法直达，基本都是要换乘就是。
最后退宿的时候，大堂粉衣女生Rain做事也很效率，排队的人有些多，就主动一一询问需求及赠送了小礼品。
再次感谢酒店每位工作人员，此次入住体验超级棒，长辈小孩都很开心。', '["https://dimg04.c-ctrip.com/images/0232912000blkxvjpF9A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000blktsis57B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000blkykco8F7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-07', '花园大床房', '大床房', '家庭亲子', 503, 6.222576268071369, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "整体满意度", "安静程度"]'::jsonb, '前台服务', '整体满意度', '安静程度', '未知酒店', '未知地点', '匿名', '绝对超预期的感受。', '绝对超预期的感受。
