INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f20e3c98b0941765ca0', '本次带小孩入住，非常满意   整个酒店的环境  很惊艳，尤其是瀑布花园和餐厅，非常棒。', '["https://dimg04.c-ctrip.com/images/0235d12000cagxccb02D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000cah2my998A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000cah0rgkF29F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-30', '花园双床房', '双床房', '朋友出游', 43, 3.784189633918261, 0, 0.0, 35, 3.58351893845611, 6, '["整体满意度", "公共设施", "餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '本次带小孩入住，非常满意   整个酒店的环境  很惊艳，尤其是瀑布花园和餐厅，非', '本次带小孩入住，非常满意   整个酒店的环境  很惊艳，尤其是瀑布花园和餐厅，非常棒。', '2023-09-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f20e3c98b0941765ca1', '酒店位置非常好，就在淘金路地铁站上来转弯即可到达，我们从顺德乘地铁直接来到酒店，酒店大堂一片奢华的景象，非常豪华，前台办理入住很快，酒店也很贴心，提早开了空调，在炎热夏天进入房间就能感受舒适的环境；酒店有一个后花园可以散步，有瀑布和小桥流水还有各种花草，非常适合拍照留念，下次去广州还会选择入住，五星好评；', '["https://dimg04.c-ctrip.com/images/0233k12000bt6qwm7E02D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000bt6srf9EA95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000bt6x76h9E60_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000bt6wq3jB390_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000bt6tjko883B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000bt6l1plBC3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000bt6s0jm4ECB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000bt6w303F475_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000bt6qm0k4648_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-02', '花园大床房', '大床房', '家庭亲子', 153, 5.0369526024136295, 0, 0.0, 17, 2.8903717578961645, 9, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店位置非常好，就在淘金路地铁站上来转弯即可到达，我们从顺德乘地铁直接来到酒店，', '酒店位置非常好，就在淘金路地铁站上来转弯即可到达，我们从顺德乘地铁直接来到酒店，酒店大堂一片奢华的景象，非常豪华，前台办理入住很快，酒店也很贴心，提早开了空调，在炎热夏天进入房间就能感受舒适的环境；酒店有一个后花园可以散步，有瀑布和小桥流水还有各种花草，非常适合拍照留念，下次去广州还会选择入住，五星好评；', '2023-08-02', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f20e3c98b0941765ca2', '感谢前台Niki的热心安排免费升级房型，不愧是老牌的酒店，地理环境服务超棒，也感谢大堂的rain，考虑到我们是晚上18:00的回家航班，免费帮我们延到14:00后退房，让我们的整个广州旅途没有任何的疲劳感。', '["https://dimg04.c-ctrip.com/images/0231612000cbkcudc8477_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000cbkcz7u87B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000cbkcus5FDE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000cbkczz0959E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-03', '红棉双床套房', '套房', '家庭亲子', 103, 4.6443908991413725, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '感谢前台Niki的热心安排免费升级房型，不愧是老牌的酒店，地理环境服务超棒，也感', '感谢前台Niki的热心安排免费升级房型，不愧是老牌的酒店，地理环境服务超棒，也感谢大堂的rain，考虑到我们是晚上18:00的回家航班，免费帮我们延到14:00后退房，让我们的整个广州旅途没有任何的疲劳感。', '2023-10-03', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f20e3c98b0941765ca3', '酒店大堂很气派，地理位置很好，离各个景点都不远，门口就是淘金地铁站，打车也很方便，附近有广州酒家，点都德，陶陶居，酒店还有室外泳池，8个电梯，上下楼都不用等，花园很美，有瀑布，锦鲤看到人都会游过来，我们买了一点切片面包喂，孩子们玩得很开心', '["https://dimg04.c-ctrip.com/images/0231812000bmpq6jn6961_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000bmpx5qoE93C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000bmpsvn1811C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000bmpso66F7A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000bmq0bws8271_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000bmpujykAB05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000bmpuztt3048_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000bmpy1zz7C04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000bmpvkncD399_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-11', '花园大床房', '大床房', '家庭亲子', 119, 4.787491742782046, 1, 0.6931471805599453, 7, 2.079441541679836, 9, '["交通便利性", "周边配套", "公共设施"]'::jsonb, '交通便利性', '周边配套', '公共设施', '未知酒店', '未知地点', '匿名', '酒店大堂很气派，地理位置很好，离各个景点都不远，门口就是淘金地铁站，打车也很方便', '酒店大堂很气派，地理位置很好，离各个景点都不远，门口就是淘金地铁站，打车也很方便，附近有广州酒家，点都德，陶陶居，酒店还有室外泳池，8个电梯，上下楼都不用等，花园很美，有瀑布，锦鲤看到人都会游过来，我们买了一点切片面包喂，孩子们玩得很开心', '2023-07-11', 5, '交通便利性');
