INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f2be3c98b0941765ca6', '给领导定的房间，反馈还不错', '["https://dimg04.c-ctrip.com/images/0232712000cnotweiDBCB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000cnouo7z66B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-30', '花园大床房', '大床房', '商务出差', 13, 2.6390573296152584, 0, 0.0, 31, 3.4657359027997265, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '给领导定的房间，反馈还不错', '给领导定的房间，反馈还不错', '2023-11-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f2be3c98b0941765ca7', '环境优美 非常好??', '["https://dimg04.c-ctrip.com/images/0236u12000cp7vz01379D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000cp7wsvg8541_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000cp7wp3q440D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-08', '城央绿意大床房', '大床房', '商务出差', 10, 2.3978952727983707, 0, 0.0, 6, 1.9459101490553128, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '环境优美 非常好??', '环境优美 非常好??', '2023-12-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f2be3c98b0941765ca8', '这次在花园一共住了九晚，应该是可以评论一下了。酒店位置很好找，就在5号地铁出口大约二十米处，酒店地处老城中心，周边美食众多，何况酒店本身就包含了几个米其林餐厅，这几个餐厅环境和品质也是相当不错。作为白金五星酒店，酒店服务是非常好，只是酒店确实年代久，设施有些老旧，甚至房间如其他客人提到的有点味道。而且，靠马路这边晚上施工，确实影响休息。有点遗憾的是连住九天，酒店也没给升级房间。感谢退房时，前台Gillian给与的帮助，态度认真负责。
如果再来广州，考虑再次入住。', '["https://dimg04.c-ctrip.com/images/0235f12000cukbmz9FF3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000cuk8h2z7034_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000cukcli972F2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-02', '花园双床房', '双床房', '家庭亲子', 233, 5.455321115357702, 0, 0.0, 6, 1.9459101490553128, 9, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '这次在花园一共住了九晚，应该是可以评论一下了。酒店位置很好找，就在5号地铁出口大', '这次在花园一共住了九晚，应该是可以评论一下了。酒店位置很好找，就在5号地铁出口大约二十米处，酒店地处老城中心，周边美食众多，何况酒店本身就包含了几个米其林餐厅，这几个餐厅环境和品质也是相当不错。作为白金五星酒店，酒店服务是非常好，只是酒店确实年代久，设施有些老旧，甚至房间如其他客人提到的有点味道。而且，靠马路这边晚上施工，确实影响休息。有点遗憾的是连住九天，酒店也没给升级房间。感谢退房时，前台Gillian给与的帮助，态度认真负责。
如果再来广州，考虑再次入住。', '2024-01-02', 4, '交通便利性');
