希望花园酒店越来越好！', '2023-06-25', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f36e3c98b0941765cb3', '一年大概要来广州七八次，每次来广州必住花园酒店，酒店的服务环境我认为一直是最好的，尤其给Viria、kristy两位女士，大大的好评，服务非常的令人满意，亲切，更体现出来了包容城市-广州，万分推荐', '["https://dimg04.c-ctrip.com/images/0236a12000bi64ejuDAC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-26', '花园双床房', '双床房', '商务出差', 98, 4.59511985013459, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '一年大概要来广州七八次，每次来广州必住花园酒店，酒店的服务环境我认为一直是最好的', '一年大概要来广州七八次，每次来广州必住花园酒店，酒店的服务环境我认为一直是最好的，尤其给Viria、kristy两位女士，大大的好评，服务非常的令人满意，亲切，更体现出来了包容城市-广州，万分推荐', '2023-06-26', 5, '整体满意度');
