INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f36e3c98b0941765cb6', '卫生安静，大气经典。依然是处于第一梯队的酒店，服务一直是标杆，尤其谢谢房务阿姨，还有大堂的高挑姐姐，外籍工作人员，还有Whaley。贴心的现烤曲奇还有伴手礼，太棒啦', '["https://dimg04.c-ctrip.com/images/0236812000bq8rr9qFCCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000bq8ltkhC5D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000bq8l3gj0152_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-23', '花园大床房', '大床房', '情侣出游', 82, 4.418840607796598, 0, 0.0, 3, 1.3862943611198906, 8, '["整体满意度", "客房服务", "前台服务"]'::jsonb, '整体满意度', '客房服务', '前台服务', '未知酒店', '未知地点', '匿名', '卫生安静，大气经典。依然是处于第一梯队的酒店，服务一直是标杆，尤其谢谢房务阿姨，', '卫生安静，大气经典。依然是处于第一梯队的酒店，服务一直是标杆，尤其谢谢房务阿姨，还有大堂的高挑姐姐，外籍工作人员，还有Whaley。贴心的现烤曲奇还有伴手礼，太棒啦', '2023-07-23', 5, '整体满意度');
