INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f36e3c98b0941765cb8', '酒店自带一个很漂亮的大园林，房间干净，前台服务热情，下次还会再来。', '["https://dimg04.c-ctrip.com/images/0233a12000cggzks22CA5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000cggtji131A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000cggxh755F48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000cggz20pED06_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-26', '红棉双床套房', '套房', '朋友出游', 33, 3.5263605246161616, 0, 0.0, 3, 1.3862943611198906, 6, '["整体满意度", "卫生状况", "前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务', '未知酒店', '未知地点', '匿名', '酒店自带一个很漂亮的大园林，房间干净，前台服务热情，下次还会再来。', '酒店自带一个很漂亮的大园林，房间干净，前台服务热情，下次还会再来。', '2023-10-26', 5, '整体满意度');
