环境：超赞', '2023-08-03', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cbb', '来办签证材料缺失临时需要在广州过一夜什么东西都没有准备，仓促定了花园酒店。因为以前也住过本来没有什么期待，但是前台小姐姐Joyce非常体贴让疲惫的我心情好了很多??还给我们升级了房型，让我这一次的入住体验直接拉???！双人间床帘一拉互不打扰炒鸡喜欢！下次还会选择花园酒店！', '["https://dimg04.c-ctrip.com/images/0232i12000c1sbxm8996F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000c1sdg6dC8A0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000c1sf7t1C1FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000c1slh1s65D9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-01', '花园双床房', '双床房', '独自旅行', 136, 4.919980925828125, 0, 0.0, 4, 1.6094379124341005, 8, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '来办签证材料缺失临时需要在广州过一夜什么东西都没有准备，仓促定了花园酒店。因为以', '来办签证材料缺失临时需要在广州过一夜什么东西都没有准备，仓促定了花园酒店。因为以前也住过本来没有什么期待，但是前台小姐姐Joyce非常体贴让疲惫的我心情好了很多??还给我们升级了房型，让我这一次的入住体验直接拉???！双人间床帘一拉互不打扰炒鸡喜欢！下次还会选择花园酒店！', '2023-09-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cbc', '前台小姐姐态度很好，还送我了花花，和小点心。
但酒店有点老了，墙纸有些位置有脱落，一些死角灰层有点厚', '["https://dimg04.c-ctrip.com/images/0235v2215g8njewio4E2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t2234cfdvkmk06EE9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e2234cfdwchn48F00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-09-04', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 29, 3.4011973816621555, 7, '["前台服务", "卫生状况"]'::jsonb, '前台服务', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '前台小姐姐态度很好，还送我了花花，和小点心。', '前台小姐姐态度很好，还送我了花花，和小点心。
但酒店有点老了，墙纸有些位置有脱落，一些死角灰层有点厚', '2023-09-04', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cbd', '第一次入住，都给升级为套间，服务员们很热情，不错，住的舒服……路边在维修，房间有些吵，好在白天外出时间长，晚上短暂吵，还能接受的，下次还会选择', '["https://dimg04.c-ctrip.com/images/0237312000bswfqe0779A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000bsw3xd7DD6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000bswgz164B84_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-01', '花园大床房', '大床房', '家庭亲子', 71, 4.276666119016055, 0, 0.0, 7, 2.079441541679836, 6, '["整体满意度", "安静程度", "前台服务"]'::jsonb, '整体满意度', '安静程度', '前台服务', '未知酒店', '未知地点', '匿名', '第一次入住，都给升级为套间，服务员们很热情，不错，住的舒服……路边在维修，房间有', '第一次入住，都给升级为套间，服务员们很热情，不错，住的舒服……路边在维修，房间有些吵，好在白天外出时间长，晚上短暂吵，还能接受的，下次还会选择', '2023-08-01', 5, '整体满意度');
