INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cc0', '服务到位，清静卫生', '["https://dimg04.c-ctrip.com/images/0233h12000coy04svA6C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-12-07', '花园行政大床套房', '套房', '商务出差', 9, 2.302585092994046, 0, 0.0, 10, 2.3978952727983707, 4, '["客房服务", "卫生状况", "安静程度"]'::jsonb, '客房服务', '卫生状况', '安静程度', '未知酒店', '未知地点', '匿名', '服务到位，清静卫生', '服务到位，清静卫生', '2023-12-07', 4, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cc1', '昨天入住广州花园酒店，给我不一样的感受，接待我们的是Viria和Ariel两位美女，她们周到的介绍，细心的服务，让我们宾至如归，她们友好耐心的服务和美美的气质让我们感到花园的服务员是有良好素质和优质服意识的，从此可看到酒店的管理不错，再加上有历史的优美环境，干净整洁的房间，我们马上决定在这住9晚，续订了。很开心。', '["https://dimg04.c-ctrip.com/images/0234712000bxpc4b1230F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-17', '红棉双床套房', '套房', '家庭亲子', 157, 5.062595033026967, 0, 0.0, 16, 2.833213344056216, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '昨天入住广州花园酒店，给我不一样的感受，接待我们的是Viria和Ariel两位美', '昨天入住广州花园酒店，给我不一样的感受，接待我们的是Viria和Ariel两位美女，她们周到的介绍，细心的服务，让我们宾至如归，她们友好耐心的服务和美美的气质让我们感到花园的服务员是有良好素质和优质服意识的，从此可看到酒店的管理不错，再加上有历史的优美环境，干净整洁的房间，我们马上决定在这住9晚，续订了。很开心。', '2023-08-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cc2', '广州老字号酒店，地理位置非常好，地铁口出来100米，环境好，服务很好，前台办理员Niki很漂亮的小姐姐，给我们升级了一个套房，真的是太好了', '["https://dimg04.c-ctrip.com/images/0231612000dxxmlr7C596_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000dxxle7u17A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000dxxmq4v2B17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000dxxminiEFF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-10', '城央绿意大床房', '大床房', '家庭亲子', 69, 4.248495242049359, 0, 0.0, 32, 3.49650756146648, 7, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '广州老字号酒店，地理位置非常好，地铁口出来100米，环境好，服务很好，前台办理员', '广州老字号酒店，地理位置非常好，地铁口出来100米，环境好，服务很好，前台办理员Niki很漂亮的小姐姐，给我们升级了一个套房，真的是太好了', '2024-05-10', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f41e3c98b0941765cc3', '原来广州花园酒店也是出自顶尖的华裔建筑大师贝聿铭之手，感觉好几个中欧航空公司的空乘都是专门入住花园酒店的。
?环境亮点：地铁站上来即刻就到酒店 ～ 一进入酒店大厅，你就会为这里设计上深深蕴含的中国传统文化特色而震惊！大堂是大跨度无柱设计、富丽堂皇！正对着的是150平方米的红楼梦《大观园》金箔壁画～ 旁边就是18米双瀑布美景餐厅，在这里用早餐还是蛮心旷神怡的～ 
??房型服务：这次预定的是花园大床房，从房间内的落地玻璃窗就可直接眺望到瀑布，繁华的市区也能有一丝绿意盎然～ 室内的大浴缸令人眼前一亮。不过两天下来并没有专门去泡澡，因为酒店内的桑拿更是给力哦！
??设施齐全：个人原因总是喜欢体验各酒店的泳池和桑拿浴室，而广州也许因为国际客户特别多，因此连桑拿房都分了干湿蒸，也有冰凉的0度冰水给大家冷热交替！ 很多4星酒店这个部分都被搁置不被重视，但花园酒店令人惊喜！
??周边玩乐：酒店里现在有一个广州酒店博物馆～ 看了实在唏嘘。原来1996年，广州花园酒店给员工的服装费就有1600rmb，果然差距好大！花园酒店里还有好几家米其林星级餐厅！中餐、西餐各占2个席位！广州泰安门勇夺广州米其林二星！3楼桃园馆更是以地道粤菜蝉联米其林餐盘奖！可惜这次来没有机会了，下次必须泰安门走起！', '["https://dimg04.c-ctrip.com/images/0202e12000blp4n1l96C1_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233012000blohrj364AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000bloorduFFC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000blohdun531C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000blone3a08CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000blom68t8254_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000blook9fAFC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000bloipox7EA4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-08', '花园大床房', '大床房', '情侣出游', 545, 6.302618975744905, 1, 0.6931471805599453, 6, 1.9459101490553128, 9, '["公共设施", "交通便利性", "餐饮设施"]'::jsonb, '公共设施', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '原来广州花园酒店也是出自顶尖的华裔建筑大师贝聿铭之手，感觉好几个中欧航空公司的空', '原来广州花园酒店也是出自顶尖的华裔建筑大师贝聿铭之手，感觉好几个中欧航空公司的空乘都是专门入住花园酒店的。
