??设施齐全：个人原因总是喜欢体验各酒店的泳池和桑拿浴室，而广州也许因为国际客户特别多，因此连桑拿房都分了干湿蒸，也有冰凉的0度冰水给大家冷热交替！ 很多4星酒店这个部分都被搁置不被重视，但花园酒店令人惊喜！
??周边玩乐：酒店里现在有一个广州酒店博物馆～ 看了实在唏嘘。原来1996年，广州花园酒店给员工的服装费就有1600rmb，果然差距好大！花园酒店里还有好几家米其林星级餐厅！中餐、西餐各占2个席位！广州泰安门勇夺广州米其林二星！3楼桃园馆更是以地道粤菜蝉联米其林餐盘奖！可惜这次来没有机会了，下次必须泰安门走起！', '2023-07-08', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f4ce3c98b0941765cc4', '六一老婆生日，因为唔系假日，出唔捣外，所以就拣花园酒店住返晚，贪佢离公司同学校近，就脚。第二次入住喇，老婆对安排好满意。感谢大堂既靓女RAIN，送左份好靓既美颜用品手信，啱晒老婆用。不足：泳池D水有浊。', '["https://dimg04.c-ctrip.com/images/0232112000bcaotxyBE4C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000bcaktxt1DC5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000bcai2si9598_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000bcag9oyFE0C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000bcaiqyl3896_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000bcapltlE9B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000bcajt2u6545_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000bcakih53455_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000bcaky05087D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-02', '红棉双床套房', '套房', '家庭亲子', 101, 4.624972813284271, 0, 0.0, 54, 4.007333185232471, 7, '["周边配套", "前台服务", "公共设施"]'::jsonb, '周边配套', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '六一老婆生日，因为唔系假日，出唔捣外，所以就拣花园酒店住返晚，贪佢离公司同学校近', '六一老婆生日，因为唔系假日，出唔捣外，所以就拣花园酒店住返晚，贪佢离公司同学校近，就脚。第二次入住喇，老婆对安排好满意。感谢大堂既靓女RAIN，送左份好靓既美颜用品手信，啱晒老婆用。不足：泳池D水有浊。', '2023-06-02', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f4ce3c98b0941765cc5', '房间设施非常好??', '["https://dimg04.c-ctrip.com/images/0233v12000cmp9b2oB6F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-24', '红棉大床套房', '套房', '商务出差', 9, 2.302585092994046, 0, 0.0, 2, 1.0986122886681098, 3, '["房间设施"]'::jsonb, '房间设施', NULL, NULL, '未知酒店', '未知地点', '匿名', '房间设施非常好??', '房间设施非常好??', '2023-11-24', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f4ce3c98b0941765cc6', '入住花园酒店是个巧合，航司通知停飞改签至第二天，临时找的酒店。第一眼的印象非常好，大堂的布置是歌剧魅影，我们是看完歌剧后入住的，孩子看到后兴奋的不得了。前台Mancy给办的入住，给我们升级了套房，还送了我们欢迎花朵。服务周到细心，知道我们第一次入住给我们介绍了四楼的博物馆和油画展。办理手续非常顺利，动作娴熟，没有等待很久也是直接拿的房。广州玩了几天，下午下雨就直接去观展，还在酒店用了晚膳，体验感很不错，以后会是我再来广州首选的酒店。', '["https://dimg04.c-ctrip.com/images/0231h12000bt9ye2fE4F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000bt9yr154D91_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000bt9v1xuF640_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000bt9x4cj4555_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000bta2u71141B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000bt9tkq93891_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000bt9tkqb2175_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000bt9vkdr98EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000bta2uzpCEC9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-02', '花园双床房', '双床房', '家庭亲子', 218, 5.389071729816501, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "整体满意度", "退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '入住花园酒店是个巧合，航司通知停飞改签至第二天，临时找的酒店。第一眼的印象非常好', '入住花园酒店是个巧合，航司通知停飞改签至第二天，临时找的酒店。第一眼的印象非常好，大堂的布置是歌剧魅影，我们是看完歌剧后入住的，孩子看到后兴奋的不得了。前台Mancy给办的入住，给我们升级了套房，还送了我们欢迎花朵。服务周到细心，知道我们第一次入住给我们介绍了四楼的博物馆和油画展。办理手续非常顺利，动作娴熟，没有等待很久也是直接拿的房。广州玩了几天，下午下雨就直接去观展，还在酒店用了晚膳，体验感很不错，以后会是我再来广州首选的酒店。', '2023-08-02', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f4ce3c98b0941765cc7', '极具岭南特色的后花园景致和荔湾亭美食 值得再来 也是第一次游广州的最佳之选', '["https://dimg04.c-ctrip.com/images/0236f12000c26pct078A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000c26h7j76FBF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000c26ksx56983_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000c26lta729E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000c26pembC412_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000c26nkwo1F5B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000c26i9ilB6FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000c26o8w3377E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000c26fmud416E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-03', '花园大床房', '大床房', '情侣出游', 37, 3.6375861597263857, 0, 0.0, 13, 2.6390573296152584, 5, '["周边配套", "整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '极具岭南特色的后花园景致和荔湾亭美食 值得再来 也是第一次游广州的最佳之选', '极具岭南特色的后花园景致和荔湾亭美食 值得再来 也是第一次游广州的最佳之选', '2023-09-03', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f4ce3c98b0941765cc8', '办理入住时间比较长，排队地方设置不明显导致有人插队。早餐觉得不如其他五星，房间也的确有些年头。就住个情怀打个卡吧，五星好评。', '["https://dimg04.c-ctrip.com/images/0236u12000bufnot49F6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000bufqgpj71BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000bufpnma82CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000bufmxg6C764_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000bufj9td6255_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000bufnfsu46BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-06', '花园大床房', '大床房', '独自旅行', 62, 4.143134726391533, 0, 0.0, 10, 2.3978952727983707, 6, '["退房/入住效率", "餐饮设施", "房间设施"]'::jsonb, '退房/入住效率', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '办理入住时间比较长，排队地方设置不明显导致有人插队。早餐觉得不如其他五星，房间也', '办理入住时间比较长，排队地方设置不明显导致有人插队。早餐觉得不如其他五星，房间也的确有些年头。就住个情怀打个卡吧，五星好评。', '2023-08-06', 5, '退房/入住效率');
