INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f57e3c98b0941765cd0', '第一次来广州，在选入住酒店的时候对比了好多酒店选的花园酒店，酒店一级棒，大堂恢宏气派，酒店特别有自己的文化和特色，房间很漂亮整洁，服务人员特别热情周到，办理入住的小姐姐贴心的给我们送了鲜花，还推荐我们参观酒店的博物馆和后花园等网红打卡地，参观了一圈酒店晚上我们还在瀑布餐厅享受了一顿丰盛的自助餐，退房时候大堂的小美女帮我们办理了快速退房还送我们宝格丽的洗护套装，非常奈斯。下次来广州首选花园酒店', '["https://dimg04.c-ctrip.com/images/0202312000bmffi4m7D1D_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0230d12000bmf4zjj5A88_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000bmfdsm0B57B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000bmf5ktuB681_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-10', '花园双床房', '双床房', '家庭亲子', 197, 5.288267030694535, 0, 0.0, 3, 1.3862943611198906, 9, '["整体满意度", "前台服务", "退房/入住效率"]'::jsonb, '整体满意度', '前台服务', '退房/入住效率', '未知酒店', '未知地点', '匿名', '第一次来广州，在选入住酒店的时候对比了好多酒店选的花园酒店，酒店一级棒，大堂恢宏', '第一次来广州，在选入住酒店的时候对比了好多酒店选的花园酒店，酒店一级棒，大堂恢宏气派，酒店特别有自己的文化和特色，房间很漂亮整洁，服务人员特别热情周到，办理入住的小姐姐贴心的给我们送了鲜花，还推荐我们参观酒店的博物馆和后花园等网红打卡地，参观了一圈酒店晚上我们还在瀑布餐厅享受了一顿丰盛的自助餐，退房时候大堂的小美女帮我们办理了快速退房还送我们宝格丽的洗护套装，非常奈斯。下次来广州首选花园酒店', '2023-07-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f57e3c98b0941765cd1', '酒店环境十分好，后花园瀑布值得一逛。但房间设施有些老旧，玻璃窗全是灰，淋浴和厕所共用一扇移门，推拉不方便，很费劲。洗手池台面也不太干净。', '["https://dimg04.c-ctrip.com/images/0235v12000bqx26ct1D1E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000bqx52d099EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-07-25', '花园双床房', '双床房', '家庭亲子', 68, 4.23410650459726, 1, 0.6931471805599453, 15, 2.772588722239781, 8, '["房间设施", "卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '酒店环境十分好，后花园瀑布值得一逛。但房间设施有些老旧，玻璃窗全是灰，淋浴和厕所', '酒店环境十分好，后花园瀑布值得一逛。但房间设施有些老旧，玻璃窗全是灰，淋浴和厕所共用一扇移门，推拉不方便，很费劲。洗手池台面也不太干净。', '2023-07-25', 4, '房间设施');
