INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f69e3c98b0941765ce1', '酒店年久老旧，卫生间淋浴高仪水龙头水管滋水，马桶非电动圈。客房?香味难闻 由于客房数量众多，打扫慢。因位置入住率高。排队入住起码半小时以上。
还有个缺陷 是酒店附近再修地铁，（前台义正言辞说是政府工程）
客房非常受噪音的影响，建议携程预订时告知真实情况。
花园酒店对花园这边客房 要么不售卖 要么降价售卖 。而不是到酒店前台才告之 。广州酒店众多携程定1000+一晚上 因为噪音完全无法入睡。夜晚22:00见视频噪音
餐饮桃园馆 还不错。
昨日入住对面的友谊商店发生火灾，不宜停留。
